/* characters q05 (57 mục) — cân xếp hạng toàn cảnh Vương Lâm - gop trung 2026-06-24 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q05"]=window.__LIBQ["tien-nghich"]["q05"]||{};window.__LIBQ["tien-nghich"]["q05"]["characters"]={"updatedAt":"2026-06-24","count":55,"chars":[{"id":"chu-tuoc-tu","name":"Chu Tước Tử","cn":"朱雀子","aliases":["Một đời Chu Tước Tử","Ngũ tổ đại nhân","Ngũ tổ Tiên Di Tộc","Chu Tước Tử đời thứ mười bốn"],"gioiTinh":"nam","theLuc":[{"ten":"Chu Tước quốc","trangThai":"gan-bo"},{"ten":"Chu Tước Tinh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vấn Đỉnh Hậu Kỳ","trangThai":"song","blurb":"Người đứng đầu Chu Tước Tinh, đại thần thông Vấn Đỉnh Hậu Kỳ duy nhất hiện nay; Chu Tước Tử đời thứ mười bốn, mặc hồng bào thân ảnh như lửa.","vaiTro":"Cường giả đối thủ — đến Luyện Hồn Tông “mượn” Thập Ức Tôn Hồn Phiên, thực mục đích là thu phục đệ tứ hồn; bị Vương Lâm áp chế phải lui.","tinhCach":[{"text":"Cao ngạo, uy nghiêm; tự xưng “thông minh sao bằng đế vương”, giấu mưu kế thật sau lời nói.","chuong":"@c0395"},{"text":"Tính toán lợi hại kỹ lưỡng, sợ bị thương giảm thọ trước đại chiến Tiên Di Tộc.","chuong":"@c0394"},{"text":"Trước uy thế Vương Lâm thì khiếp sợ, lập tức cung kính gọi “lão tổ” và lui.","chuong":"@c0396"}],"tabs":{"diem":[{"text":"Đại thần thông Vấn Đỉnh Hậu Kỳ duy nhất hiện nay; người đứng đầu Chu Tước Tinh.","chuong":"@c0394"},{"text":"Chu Tước Tử đời thứ mười bốn, kế thừa Chu Tước huyền ấn cảm ngộ từ di vật đệ nhất Chu Tước Tử.","chuong":"@c0394"},{"text":"Đồng thời là Ngũ tổ Tiên Di Tộc — ấn ký lá cây tím trên má trái, chủ trì đại trận diệt Chu Tước quốc.","chuong":"@c0396"}],"kinhLich":[{"text":"Phá hộ sơn đại trận Luyện Hồn Tông, hiện thân Vấn Đỉnh Hậu Kỳ, đòi “mượn” Thập Ức Tôn Hồn Phiên vạn năm theo hứa hẹn cũ; Độn Thiên phủ nhận, hai bên khai chiến.","bridge":true,"khoang":"@c0394"},{"bridge":true,"khoang":"@c0394–@c0394","text":"Tung bàn tay lửa, dùng Chu Tước thánh hỏa, Chu Tước Kiếm và hồ lô đỏ; bị chín phi kiếm tiên lực của người mây Vấn Đỉnh vây."},{"chuong":"@c0394","importance":"normal","tieuDe":"Ép dùng Chu Tước huyền ấn (thủ)","text":"Bị chín phi kiếm dồn, buộc thi triển Chu Tước huyền ấn phòng thủ; không bị thương nhưng tái nhợt mất phiêu dật, lo giảm thọ trước đại chiến Tiên Di Tộc."},{"chuong":"@c0395","importance":"normal","tieuDe":"Thu phục Tam kim linh hồn","text":"Nhận ra đệ tứ hồn là “Tam kim linh hồn”, bày mưu luyện hóa cài máu; hiến chín phần mười tuổi thọ mở tu tinh chi tâm đoạt “đình chỉ ý cảnh”, chụp đệ tứ hồn vào tay."},{"chuong":"@c0395","importance":"major","tieuDe":"Bị Vương Lâm trọng thương nguyên thần","text":"Đúng lúc chụp giết Độn Thiên thì Vương Lâm từ bế quan xuất thủ, mắng một câu khiến nguyên thần Chu Tước Tử đau đớn, kinh hãi chưa từng có."},{"text":"Khí tức cuồng ngạo của Vương Lâm khiến Chu Tước Tử đời thứ mười bốn toát mồ hôi lạnh; nghe tên Diệp Vô Ưu thì run rẩy, cung kính gọi “lão tổ” và lui đi, để lại đệ tứ hồn cho Độn Thiên mượn ba năm.","bridge":true,"khoang":"@c0396"}],"tuViMoc":[{"chuong":"@c0394","canhGioi":"Vấn Đỉnh Hậu Kỳ","text":"Đại thần thông Vấn Đỉnh Hậu Kỳ duy nhất hiện nay; tu sĩ Vấn Đỉnh Sơ Kỳ phải bỏ chạy, Vấn Đỉnh Trung Kỳ cũng lui bước trước uy thế của hắn.","importance":"major"}],"nhanMach":[{"ten":"Độn Thiên","tag":"doi-thu","quanHe":"Đối thủ trong trận Luyện Hồn Tông; tranh đoạt Tôn Hồn Phiên và đệ tứ hồn.","ghiChu":"Khai chiến @c0394, bị Vương Lâm xen vào @c0395."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm xuất thủ trọng thương nguyên thần rồi áp chế, phải cung kính lui đi.","ghiChu":"@c0395-@c0396."},{"ten":"Diệp Vô Ưu","tag":"su-mon","quanHe":"Đệ nhất Chu Tước Tử — thủy tổ mà các đời Chu Tước Tử kế thừa; tên thật chỉ các đời Chu Tước Tử biết.","ghiChu":"@c0396."}],"tuiDo":{"phapBao":[{"ten":"Chu Tước Kiếm","loai":"tiên bảo","moTa":"Tiểu kiếm đỏ to bằng bàn tay, hút lửa mặt đất, phát tiên lực giống kiếm tiên nhân; do đệ nhất Chu Tước Tử đoạt được rồi ban tên. Bị tử kim châm đâm thủng một lỗ kim.","nguon":"@c0394"},{"ten":"Hồ lô đỏ","loai":"tiên bảo lửa","trangThai":"hong","moTa":"Hỏa hồ tiên bảo to bằng bàn tay; hô “Luyện!” phun lửa trắng tạo biển lửa trăm trượng nóng hơn lông Chu Tước, dùng luyện hóa đệ tứ hồn. Trước đó từng bị phi kiếm tiên lực phá vỡ.","nguon":"@c0394"},{"ten":"Lông chim đỏ","loai":"vật xúc tác","moTa":"Chất xúc tác Chu Tước thánh hỏa, đốt cháy rồi vỡ vụn phát lửa cuồng mãnh.","nguon":"@c0394"},{"ten":"Nắm bùn đen","loai":"vật khởi thuật","moTa":"Bùn đen to bằng bàn tay; phun máu lên bốc khói đen, vung tay tạo ký hiệu kỳ lạ để mở tu tinh chi tâm, đoạt đình chỉ ý cảnh.","nguon":"@c0395"}],"congPhap":[{"ten":"Chu Tước thánh hỏa","moTa":"Đốt một lông chim đỏ làm trung tâm, lửa cuồng mãnh phủ trăm dặm, vật dính lửa lập tức biến mất.","nguon":"@c0394"},{"ten":"Chu Tước huyền ấn","moTa":"Thần thông chỉ các đời Chu Tước Tử cảm ngộ từ di vật đệ nhất Chu Tước Tử; do tu chân liên minh ban khi thành tu chân quốc cấp sáu; có hai ấn công/thủ, công không gì không phá, thủ mạnh hơn Chu Tước kỳ trận; mỗi thế hệ chỉ một người nắm, dùng gây hao tổn.","nguon":"@c0394"},{"ten":"Tu tinh chi tâm","moTa":"Bí thuật mở bằng cách hiến tế tuổi thọ (Chu Tước Tử hiến chín phần mười), đoạt “đình chỉ ý cảnh” khiến mọi sinh linh trong trăm trượng ngừng bất động; mở tu tinh chi tâm cũng là lúc tuổi thọ kết thúc.","nguon":"@c0395"}],"khac":[{"ten":"Tam kim linh hồn (đệ tứ hồn)","loai":"hồn vật","trangThai":"dang-co","moTa":"Đệ tứ chủ hồn của Tôn Hồn Phiên, hình tử kim châm, vật cứng nhất thiên hạ; Chu Tước Tử chụp được rồi cho Độn Thiên mượn ba năm để đối phó Tiên Di Tộc.","nguon":"@c0395"}]},"nhanThu":[],"danDuoc":[],"linhThu":[],"nguyenLieu":[],"linhThao":[]},"uuTien":6,"nguon":["@c0394"]},{"id":"hong-diep-su-muoi-kien-phong","name":"Hồng Điệp","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Phe Chu Tước Tử","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không-rõ","trangThai":"song","blurb":"Sư muội của Kiền Phong, áo hồng xinh đẹp tuyệt trần nhưng hai mắt mờ mịt đờ đẫn như con rối không hồn; bị Kiền Phong khống chế và hút sinh mệnh lực để chữa thương.","vaiTro":"Nhân vật phụ — sư muội của Kiền Phong, được sư tôn phái đi thu thập đạo tâm Vương Lâm nhưng bị Kiền Phong khống chế.","tinhCach":[{"text":"Hai mắt mờ mịt đờ đẫn, vô hồn như con rối bị khống chế.","chuong":"@c0392"}],"tabs":{"diem":[{"text":"Dung mạo xinh đẹp tuyệt trần nhưng thần trí như con rối không hồn, bị sư huynh Kiền Phong khống chế.","chuong":"@c0392"},{"text":"Được sư tôn phái đi thu thập đạo tâm Vương Lâm.","chuong":"@c0392"}],"kinhLich":[{"text":"Kiền Phong gọi Hồng Điệp ra, điểm vào giữa lông mày nàng hút sinh mệnh lực để chữa lành thương thế trong nháy mắt, rồi đặt ngón tay bị thương vào miệng nàng cho liếm sạch máu. Nàng tỏ ra như con rối vô hồn, không phản kháng.","bridge":true,"khoang":"@c0392"}],"tuViMoc":[],"tuVi":"Chưa rõ cảnh giới cụ thể.","nhanMach":[{"ten":"Kiền Phong","tag":"su-mon","quanHe":"Sư huynh","ghiChu":"Kiền Phong khống chế nàng như con rối, hút sinh mệnh lực để tự chữa thương."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng thu thập đạo tâm","ghiChu":"Được sư tôn phái đi thu thập đạo tâm Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0392"]},{"id":"tu-ma-truong-lao-thi-am-tong","name":"Tư Mã trưởng lão","cn":"","aliases":["Tư Đồ Nam (tiêu đề chương)"],"gioiTinh":"nam","theLuc":[{"ten":"Thi Âm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến Sơ Kỳ","trangThai":"song","blurb":"Trưởng lão Thi Âm Tông trú tại Chu Tước Tinh, tu vi Anh Biến Sơ Kỳ; cưỡi quan tài đến đưa thi thể cho Tiên Di Tộc và báo tin Chu Tước Tử đại chiến Độn Thiên.","vaiTro":"Cầu nối thông tin giữa Thi Âm Tông và Tiên Di Tộc trong cuộc diệt Chu Tước quốc.","tinhCach":[{"text":"Thận trọng, biết lượng sức — cảnh báo Tiên Di Tộc rằng Chu Tước Tử không bao giờ ra tay khi chưa nắm tám phần thắng.","chuong":"@c0396"}],"tabs":{"diem":[{"text":"Trưởng lão Thi Âm Tông tại Chu Tước Tinh, tu vi Anh Biến Sơ Kỳ.","chuong":"@c0396"}],"kinhLich":[{"chuong":"@c0396","importance":"normal","tieuDe":"Đưa thi thể, báo tin cho Tiên Di Tộc","text":"Cùng hai phụ tá Hóa Thần Hậu Kỳ cưỡi cỗ quan tài lớn dài vài trượng đến chỗ Tiên Di Tộc, qua được lực cản phù văn nhờ Ngũ tổ mở thông đạo. Hắn giao thi thể và báo tin Chu Tước Tử đã tới Luyện Hồn Tông đại chiến Độn Thiên lão quỷ để tranh đoạt Thập Ức Tôn Hồn Phiên, đồng thời cảnh báo Tiên Di Tộc phải cẩn thận."}],"tuViMoc":[{"chuong":"@c0396","canhGioi":"Anh Biến Sơ Kỳ","text":"Xuất hiện với tu vi Anh Biến Sơ Kỳ, dẫn theo hai phụ tá Hóa Thần Hậu Kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Chu Tước Tử","tag":"dong-minh","quanHe":"Bẩm báo và phối hợp","ghiChu":"Gọi Ngũ tổ Tiên Di Tộc; đến báo tin và đưa thi thể."}],"tuiDo":{"phapBao":[{"ten":"Cỗ quan tài lớn","loai":"pháp bảo/phương tiện","trangThai":"dang-co","moTa":"Quan tài dài vài trượng dùng làm phương tiện bay của ba người Thi Âm Tông, chở thi thể đến cho Tiên Di Tộc.","nguon":"@c0396"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0396"]},{"id":"diep-vo-uu","name":"Diệp Vô Ưu","cn":"","aliases":["Đệ nhất Chu Tước Tử"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Chu Tước quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Tên thật của đệ nhất Chu Tước Tử, bí mật chỉ các đời Chu Tước Tử mới biết; từng có đại ân với Vương Lâm.","vaiTro":"Cội nguồn ân tình khiến Vương Lâm tha mạng Chu Tước Tử đời thứ mười bốn.","tinhCach":[],"tabs":{"diem":[{"text":"Tên thật của đệ nhất Chu Tước Tử — bí mật chỉ các đời Chu Tước Tử trong Chu Tước Tinh biết.","chuong":"@c0396"}],"kinhLich":[{"text":"Được Vương Lâm nhắc đến tại Luyện Hồn Tông: nể mặt Diệp Vô Ưu nên Vương Lâm tha mạng Chu Tước Tử đời thứ mười bốn. Khi nghe tên này, Chu Tước Tử run rẩy nhận ra lai lịch, cung kính gọi lão tổ rồi lui đi.","bridge":true,"khoang":"@c0396"}],"tuViMoc":[],"tuVi":"Chưa rõ tu vi; chỉ được nhắc tên trong chương 396.","nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Có đại ân năm xưa","ghiChu":"Vì ân tình của Diệp Vô Ưu, Vương Lâm tha mạng Chu Tước Tử."},{"ten":"Chu Tước Tử","tag":"ho-hang","quanHe":"Tổ tiên dòng Chu Tước Tử","ghiChu":"Là đệ nhất Chu Tước Tử; các đời sau mang đạo hiệu kế thừa."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0396"]},{"id":"ngu-to-tien-di-toc","name":"Ngũ tổ đại nhân (Tiên Di Tộc)","cn":"","aliases":["Ngũ tổ","Ngũ tổ đại nhân"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Tiên Di Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Trưởng lão Tiên Di Tộc chủ trì nghi thức hiến tế tổ linh phía đông Chu Tước đại lục, nhận thi thể Cự Ma Tộc do Thi Âm Tông dâng tới.","vaiTro":"Chủ trì hiến tế tổ linh của Tiên Di Tộc; bị Sở Vân Phi và lực lượng Thiên Ngọc Tông kéo tới khai chiến.","tinhCach":[{"text":"Trầm lặng, uy nghiêm; khi cảm thấy bất ổn thì sắc mặt âm trầm khó coi.","chuong":"@c0398"},{"text":"Quyết đoán trong giao tranh — lập tức quát ‘Giết’ phát động đại chiến khi bị tấn công.","chuong":"@c0398"}],"tabs":{"diem":[{"text":"Đứng đầu nghi thức hiến tế tổ linh trong màn sương đen phía đông Chu Tước đại lục.","chuong":"@c0398"},{"text":"Trung niên mặc áo xám như văn sĩ — Ngũ Tổ Tiên Di Tộc","chuong":"@c0413"}],"kinhLich":[{"text":"Tại màn sương đen phía đông Chu Tước đại lục, ngũ tổ thu hồi ánh mắt, ra lệnh bắt đầu nghi thức hiến tế tổ linh; nhận thi thể Cự Ma Tộc do Thi Âm Tông dâng tới cho cây thần.","bridge":true,"khoang":"@c0398"},{"text":"Khi Sở Vân Phi cùng lực lượng Thiên Ngọc Tông xé màn sương đen kéo tới quyết chiến, ngũ tổ vung tay quát ‘Giết’, dẫn người Tiên Di Tộc lao ra mở đại chiến.","bridge":true,"khoang":"@c0398"},{"text":"Xuất hiện ở phía đông Chu Tước Sơn, tham gia vây Chu Tước Tử cùng các Tổ Tiên Di Tộc khác.","bridge":true,"khoang":"@c0413"}],"tuViMoc":[],"tuVi":"Tu vi chưa được nêu rõ; là trưởng lão cấp cao của Tiên Di Tộc, đủ sức chủ trì nghi thức và đối đầu lão quái Vấn Đỉnh.","nhanMach":[{"ten":"Tư Mã trưởng lão","tag":"dong-minh","quanHe":"Trưởng lão Thi Âm Tông dâng thi thể Cự Ma Tộc cho nghi thức hiến tế của Tiên Di Tộc","ghiChu":"Tư Mã thấy sắc mặt ngũ tổ khó coi nên ngạc nhiên (@c0398)"},{"ten":"Sở Vân Phi","tag":"doi-thu","quanHe":"Lão quái Vấn Đỉnh Sơ Kỳ của Thiên Ngọc Tông tuyên chiến và tấn công nghi thức hiến tế","ghiChu":"@c0398"},{"ten":"Nhất Tổ Tiên Di Tộc","tag":"dong-minh","quanHe":"Đồng tộc","ghiChu":""},{"ten":"Chu Tước Tử","tag":"doi-thu","quanHe":"Đối thủ — vây công","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0413","@c0398"]},{"id":"tu-to-tien-di-toc","name":"Tứ tổ (Tiên Di Tộc)","cn":"","aliases":["Tứ tổ","Lão già đầu bạc Tiên Di Tộc"],"gioiTinh":"nam","theLuc":[{"ten":"Tiên Di Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thuật chú sư Tiên Di Tộc (lão tổ)","trangThai":"song","blurb":"Lão tổ đầu bạc của Tiên Di Tộc, chủ trì khởi động Luân Hồi thụ tổ linh phía bắc Chu Tước Tinh; bị Tư Đồ Nam nuốt mất tổ linh nên điên cuồng truy kích.","vaiTro":"Một trong các lão tổ Tiên Di Tộc trấn bốn hướng Chu Tước Tinh, phụ trách nuôi cấy tổ linh phía bắc; trở thành kẻ truy đuổi Tư Đồ Nam và Vương Lâm.","tinhCach":[{"text":"Nóng nảy, dễ mất kiểm soát: khi mất tổ linh thì hai mắt đỏ bừng, gào thét điên cuồng.","chuong":"@c0399"},{"text":"Quyết liệt báo thù: không tiếc hy sinh phù văn dùng bí thuật để truy lùng kẻ trộm.","chuong":"@c0399"}],"tabs":{"diem":[{"text":"Lão tổ Tiên Di Tộc chủ trì phía bắc, để mất nguyên một tổ linh — tổn thất cực lớn với cả tộc.","chuong":"@c0399"},{"text":"Hy sinh phù văn dùng bí thuật mới thấy được Tư Đồ Nam đang ẩn hình.","chuong":"@c0399"}],"kinhLich":[{"text":"Chủ trì nuôi cấy Luân Hồi thụ tổ linh ở phía bắc Chu Tước Tinh nhưng không hề hay biết Tư Đồ Nam đã lén vào màn sương đen ký sinh nuốt sạch dinh dưỡng, khiến tổ linh sụp đổ tiêu tan.","bridge":true,"khoang":"@c0399"},{"chuong":"@c0399","importance":"normal","tieuDe":"Điên cuồng truy kích","text":"Phẫn nộ tột độ, hy sinh phù văn dùng bí thuật để thấy được Tư Đồ Nam, hai mắt đỏ bừng gào thét đuổi theo tới tận Viêm Cực ở tiểu bắc, truy kích không dừng."}],"tuViMoc":[],"tuVi":"Lão tổ Tiên Di Tộc cấp cao, đủ năng lực chủ trì nuôi cấy tổ linh và truy kích cường giả; cấp độ diệp cụ thể chưa nêu rõ.","nhanMach":[{"ten":"Tư Đồ Nam","tag":"doi-thu","quanHe":"Kẻ thù","ghiChu":"Tư Đồ Nam lén nuốt sạch tổ linh phía bắc do tứ tổ chủ trì; tứ tổ điên cuồng truy kích.","gap":"@c0399"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu truy đuổi","ghiChu":"Truy kích Tư Đồ Nam khi hắn ôm Vương Lâm chạy về Viêm Cực.","gap":"@c0399"}],"tuiDo":{"phapBao":[{"ten":"Phù văn truy tung","loai":"phù bảo","trangThai":"da-dung","moTa":"Phù văn bị hy sinh để thi triển bí thuật, nhờ đó thấy được Tư Đồ Nam đang ẩn hình.","nguon":"@c0399"}],"danDuoc":[],"congPhap":[{"ten":"Bí thuật hy sinh phù văn truy tung","moTa":"Bí thuật của Tiên Di Tộc: không tiếc hy sinh phù văn để định vị, nhìn thấy kẻ địch đang ẩn hình.","nguon":"@c0399"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0399"]},{"id":"lao-gia-bat-diep-tien-di-toc","name":"Lão giả bát diệp (trưởng lão Tiên Di tộc)","cn":"","aliases":["Bát diệp Thuật Chú Sư bên ngũ tổ"],"gioiTinh":"nam","theLuc":[{"ten":"Tiên Di Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bát diệp Thuật Chú Sư","trangThai":"tu-vong","blurb":"Trưởng lão Tiên Di tộc, bát diệp Thuật Chú Sư bên cạnh ngũ tổ đại nhân; bị Vương Lâm phá Tổ phù rồi chém đầu trên tầng thứ tư.","vaiTro":"Phản diện nhỏ — trưởng lão Tiên Di tộc bị Vương Lâm tiêu diệt khi đang chữa thương ở Luân Hồi thụ.","tinhCach":[{"text":"Tàn nhẫn, từng giết vô số tu sĩ; khi nguy cấp lập tức triệu Tổ phù chống đỡ và tìm đường chạy cầu viện.","chuong":"@c0404"}],"tabs":{"diem":[{"text":"Bát diệp Thuật Chú Sư nắm quyền lớn trong Tiên Di tộc, hầu cận ngũ tổ đại nhân.","chuong":"@c0404"},{"text":"Đầu lâu sau khi chết không có hồn phách, trên đầu mang phù hào đen không trọn vẹn giống Tổ phù.","chuong":"@c0404"}],"kinhLich":[{"text":"Một tháng trước bị một tu sĩ Anh Biến hậu kỳ ở Chu Tước quốc đánh trọng thương; lão chạy về dùng quầng sáng Luân Hồi thụ ở tầng thứ tư để chữa thương, định lên tầng thứ mười một cầu cứu tam tổ đại nhân.","bridge":true,"khoang":"@c0404"},{"chuong":"@c0404","importance":"normal","tieuDe":"Bị Vương Lâm chém đầu","text":"Đang chữa thương thì bị Vương Lâm vỗ một chưởng tiên lực đánh trọng thương; lão triệu Tổ phù chống đỡ nhưng bị tiên kiếm phá vỡ, máu phun như suối, bị Vương Lâm đánh ấn ký rồi chém đầu. Hắn phát hiện đầu lâu không có hồn phách, mang phù hào tổ phù."}],"tuViMoc":[{"chuong":"@c0404","canhGioi":"Bát diệp Thuật Chú Sư","text":"Hệ Thuật Chú Sư của Tiên Di tộc, đạt cấp bát diệp — trưởng lão nắm quyền lớn bên cạnh ngũ tổ đại nhân.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết mình","ghiChu":"Bị Vương Lâm phá Tổ phù rồi chém đầu trên tầng thứ tư, đầu lâu bị thu vào túi trữ vật. @c0404"},{"ten":"Ngũ tổ đại nhân (Tiên Di Tộc)","tag":"cap-tren","quanHe":"Bề trên","ghiChu":"Là bát diệp Thuật Chú Sư hầu cận bên cạnh ngũ tổ đại nhân. @c0404"}],"tuiDo":{"phapBao":[{"ten":"Tổ phù","loai":"phù bảo","trangThai":"hong","moTa":"Phù văn cực kỳ phức tạp, tỏa khí tức tang thương; triệu hồi để chống đỡ tiên lực, từng chặn được một chưởng nhưng bị tiên kiếm Vương Lâm đánh vỡ vụn.","nguon":"@c0404"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0404"]},{"id":"nu-tu-cuu-diep-tam-to","name":"Nữ tử cửu diệp","cn":"","aliases":["Tiên tử tiểu muội muội","Tam Tổ"],"gioiTinh":"nu","theLuc":[{"ten":"Tiên Di tộc","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Không rõ (Thuật Chú Sư cửu diệp)","trangThai":"khong-ro","blurb":"Nữ tử xích lõa lơ lửng nơi tầng mười một sào huyệt Tiên Di tộc, trán lóe phù văn cửu diệp; Hứa Quốc Lập nhận ra là “Tiên tử tiểu muội muội”, gắn với bức tranh chín điểm sáng và tàn hồn ý cảnh năm xưa.","vaiTro":"Nhân vật bí ẩn quan trọng — được tiêu đề ám chỉ chính là Tam Tổ; liên hệ tới bức tranh không điều khiển được của Vương Lâm.","tinhCach":[{"text":"Bí ẩn, yêu dị; ánh mắt vừa mang tia sáng xanh động lòng người vừa mang tia sáng khiến người nhìn mê mẩn.","chuong":"@c0405"}],"tabs":{"diem":[{"text":"Toàn thân trắng nõn không có phù văn, chỉ trên trán lóe phù văn cửu diệp — bậc cao nhất trong hệ Thuật Chú Sư Tiên Di tộc.","chuong":"@c0405"},{"text":"Dung mạo cực mỹ lệ; cả đời Vương Lâm ngoài tiên thi chỉ Liễu Mi mới sánh được.","chuong":"@c0405"},{"text":"Lơ lửng tự chuyển động không gió giữa phù văn đỏ như máu, đầy yêu dị.","chuong":"@c0405"}],"kinhLich":[{"text":"Vương Lâm xuống tầng mười một sào huyệt Tiên Di tộc, thấy nàng xích lõa lơ lửng giữa phù văn đỏ như máu, trán lóe phù văn cửu diệp; phía trên là bức tranh chín điểm sáng vờn thành vòng tròn, hắc khí từ tranh chui vào mi tâm nàng.","bridge":true,"khoang":"@c0405"},{"text":"Phù văn đỏ bay lên, nàng mở mắt; kiếm hồn Hứa Quốc Lập biến ảo ra, lẩm bẩm “Tiên tử tiểu muội muội” và cảm tạ nàng đã mang về một tia ý cảnh mà tàn hồn năm xưa hắn bị mất khi hóa thành tu sĩ.","bridge":true,"khoang":"@c0405"}],"tuViMoc":[],"tuVi":"Chưa rõ cảnh giới cụ thể; thuộc hệ Thuật Chú Sư Tiên Di tộc bậc cửu diệp (cao nhất, vượt bát diệp tương đương Anh Biến kỳ).","nhanMach":[{"ten":"Hứa Quốc Lập","tag":"khac","quanHe":"Kiếm hồn trong tiên kiếm Vương Lâm","ghiChu":"Nhận ra nàng là “Tiên tử tiểu muội muội”, cảm tạ nàng mang về tia ý cảnh năm xưa."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người phát hiện nàng nơi tầng mười một","ghiChu":"Cảm thấy quen thuộc; bức tranh chín điểm sáng trên nàng giống y bức tranh không điều khiển được trong túi trữ vật của hắn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0405"]},{"id":"mi-co-tam-to","name":"Mị Cơ","cn":"媚姬","aliases":["Tam tổ Tiên Di Tộc","Tam tổ"],"gioiTinh":"nu","theLuc":[{"ten":"Tiên Di Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (trọng thương chưa lành)","trangThai":"song","blurb":"Tam tổ Tiên Di Tộc, nữ tử dâm tà trọng thương chưa lành, phong tỏa lối ra đòi gần gũi Vương Lâm rồi phái Phù Thú Đồ Phổ truy sát hắn.","vaiTro":"Cường địch nữ tử thần bí Vương Lâm chạm trán ở tầng mười một vùng đất Tiên Di; tam tổ Tiên Di Tộc, dâm tà, dùng phù thú truy sát nhưng bị Phù Thú Đồ Phổ của chính Vương Lâm khắc chế.","tinhCach":[{"text":"Dâm tà, đòi gần gũi Vương Lâm vì ngửi thấy “hương vị sạch sẽ” chưa tận nữ sắc của hắn.","chuong":"@c0406"},{"text":"Quỷ quyệt nhưng kiêu căng — vừa hứa mở lối vừa đòi giữ ý cảnh tàn hồn, quyết bắt sống hắn.","chuong":"@c0406"}],"tabs":{"diem":[{"text":"Tam tổ Tiên Di Tộc, năm xưa tu sĩ gọi nàng là Mị Cơ.","chuong":"@c0406"},{"text":"Trọng thương chưa lành, chỉ một hơi thổi tiêu tan hồn phách Hứa Lập Quốc.","chuong":"@c0406"},{"text":"Hiện gốc cây cửu diệp trên trán khi cưỡng thu phù thú, chịu phản phệ phun máu.","chuong":"@c0406"}],"kinhLich":[{"text":"Áp chế hồn phách Hứa Lập Quốc tách ra từ tiên kiếm, điểm vào lông mày rồi thổi một hơi làm tiêu tan kiếm quang đánh lén của hắn; tự xưng Mị Cơ, tam tổ Tiên Di Tộc.","bridge":true,"khoang":"@c0406"},{"text":"Phong tỏa cửa vào tầng thứ mười, nói ngửi thấy trên người Vương Lâm hương vị sạch sẽ, muốn cùng hắn gần gũi mới cho đi; bị Vương Lâm phán đoán đang trọng thương chưa lành.","bridge":true,"khoang":"@c0406"},{"text":"Tiết lộ vùng đất Tiên Di có mười chín tầng, dưới tầng tỷ tỷ còn sức mạnh huyền bí và tàn hồn đệ nhất tộc trưởng; gọi Vương Lâm bằng tên Anh Biến Kỳ, phái cuộn tranh phun giao long nghìn trượng và hắc hổ trăm trượng đuổi bắt.","bridge":true,"khoang":"@c0406"},{"chuong":"@c0406","importance":"normal","tieuDe":"Chịu phản phệ, Vương Lâm thoát","text":"Khi Vương Lâm mở Phù Thú Đồ Phổ của hắn, nữ tổ tiên tự phong ấn thu hai phù thú giao long mãnh hổ về; Mị Cơ kinh hãi hô “Thu” thất bại, phun máu vì phù thú bị gọi mất, hiện gốc cây cửu diệp trên trán cưỡng thu cuộn tranh nhưng không giữ được hắn."}],"tuViMoc":[],"tuVi":"Cảnh giới cụ thể chưa rõ; là tam tổ Tiên Di Tộc nhưng đang trọng thương chưa lành, sức chiến đấu suy giảm.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu Mị Cơ muốn bắt sống để hưởng thụ và phục hồi phù văn; bị hắn dùng Phù Thú Đồ Phổ khắc chế và thoát thân.","ghiChu":"Gọi Vương Lâm bằng tên Anh Biến Kỳ."},{"ten":"Hứa Lập Quốc","tag":"doi-thu","quanHe":"Hồn phách trong tiên kiếm tách ra định gần gũi nàng, bị nàng điểm mày và thổi tiêu tan, sợ chui lại vào kiếm.","ghiChu":""}],"tuiDo":{"phapBao":[{"ten":"Phù Thú Đồ Phổ","loai":"pháp bảo cuộn tranh","trangThai":"mat","moTa":"Bảo vật Tiên Di Tộc, cuộn tranh màn đen có mười tử quang điểm; phù văn rắn hổ hóa giao long nghìn trượng và hắc hổ trăm trượng truy sát Vương Lâm, nhưng bị Phù Thú Đồ Phổ của hắn thu mất hai phù thú.","nguon":"@c0406"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0406"]},{"id":"van-tuoc-tu","name":"Vân Tước Tử","cn":"云雀子","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Người được Kiền Bình Hải chỉ định làm Chu Tước Tử đời tiếp; đối thủ của Chu Tước Tử hiện tại, có liên hệ Tiên Di Tộc và cho hắn ba tháng cân nhắc số phận Tu Tinh Chi Tinh.","vaiTro":"Đối thủ then chốt của Chu Tước Tử (qua độc thoại): người Kiền Bình Hải khen ngợi và chọn kế vị Chu Tước Tử, có liên hệ với Tiên Di Tộc, ép Chu Tước Tử chọn cùng chết hay giao dịch tu chân liên minh quanh Tu Tinh Chi Tinh.","tinhCach":[{"text":"Mưu lược, đặt Chu Tước Tử vào thế cờ ba tháng cân nhắc cùng chết hay trao đổi.","chuong":"@c0406"}],"tabs":{"diem":[{"text":"Được Kiền Bình Hải khen ngợi và chỉ định làm Chu Tước Tử đời tiếp.","chuong":"@c0406"},{"text":"Có liên hệ với Tiên Di Tộc, muốn chiếm Chu Tước Tinh.","chuong":"@c0406"}],"kinhLich":[{"text":"Qua độc thoại Chu Tước Tử hé lộ: Vân Tước Tử cho hắn ba tháng cân nhắc cùng chết hay trao đổi với tu chân liên minh về Tu Tinh Chi Tinh; là người được Kiền Bình Hải khen ngợi mà luôn khiến Chu Tước Tử bị mắng chửi, sau được chỉ định kế vị.","bridge":true,"khoang":"@c0406"}],"tuViMoc":[],"tuVi":"Cảnh giới chưa rõ.","nhanMach":[{"ten":"Chu Tước Tử","tag":"doi-thu","quanHe":"Đối thủ — bị Chu Tước Tử hận vì được Kiền Bình Hải khen ngợi và chỉ định kế vị; ép Chu Tước Tử ba tháng cân nhắc số phận Tu Tinh Chi Tinh.","ghiChu":""},{"ten":"Kiền Bình Hải","tag":"an-nhan","quanHe":"Người khen ngợi và chỉ định Vân Tước Tử làm Chu Tước Tử đời tiếp.","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0406"]},{"id":"kien-binh-hai","name":"Kiền Bình Hải","cn":"乾平海","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Chu Tước Tử đời trước, người chỉ định Vân Tước Tử kế vị; bị Chu Tước Tử hiện tại hận, đoạt Tu Tinh Chi Tâm cướp ngôi và bán thi thể cho Thi Âm Tông.","vaiTro":"Chu Tước Tử đời trước (đã chết): khen ngợi Vân Tước Tử, chỉ định người này kế vị; bị Chu Tước Tử hiện tại căm hận, cướp ngôi và đoạt Tu Tinh Chi Tâm, thi thể bị bán cho Thi Âm Tông; là tổ tiên của Kiền Phong.","tinhCach":[{"text":"Trọng tài năng nhưng làm tổn thương lòng tự tôn Chu Tước Tử hiện tại bằng cách khen Vân Tước Tử mà mắng chửi hắn.","chuong":"@c0406"}],"tabs":{"diem":[{"text":"Chu Tước Tử đời trước, chỉ định Vân Tước Tử kế vị trước khi chết.","chuong":"@c0406"},{"text":"Thi thể bị Chu Tước Tử hiện tại bán cho Thi Âm Tông để hả hận.","chuong":"@c0406"}],"kinhLich":[{"chuong":"@c0406","importance":"normal","tieuDe":"Chỉ định kế vị và bị phản","text":"Qua độc thoại Chu Tước Tử hé lộ: Kiền Bình Hải luôn khen Vân Tước Tử mà mắng chửi Chu Tước Tử, trước khi chết chỉ định Vân Tước Tử kế vị; Chu Tước Tử âm thầm đoạt Tu Tinh Chi Tâm cướp ngôi, sau bán thi thể hắn cho Thi Âm Tông."}],"tuViMoc":[],"tuVi":"Cảnh giới chưa rõ; đã chết.","nhanMach":[{"ten":"Chu Tước Tử","tag":"doi-thu","quanHe":"Bị Chu Tước Tử hiện tại căm hận, cướp ngôi và đoạt Tu Tinh Chi Tâm; thi thể bị bán cho Thi Âm Tông.","ghiChu":""},{"ten":"Vân Tước Tử","tag":"khac","quanHe":"Người được Kiền Bình Hải khen ngợi và chỉ định làm Chu Tước Tử đời tiếp.","ghiChu":""},{"ten":"Kiền Phong","tag":"ho-hang","quanHe":"Hậu nhân Kiền Bình Hải, linh căn và dáng vẻ giống tổ.","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0406"]},{"id":"ly-thanh-binh","name":"Lý Thanh Bình","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thi Âm Tông (phân tông Triệu quốc)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh Hậu Kỳ","trangThai":"song","blurb":"Tông chủ phân tông Thi Âm Tông tại Triệu quốc, Nguyên Anh Hậu Kỳ, bế quan tu luyện chờ thây ma chiếm thân để lên Hóa Thần.","vaiTro":"Tông chủ phân tông Thi Âm Tông Triệu quốc; xuất hiện khi Vương Lâm đột nhập tông môn.","tinhCach":[{"text":"Cẩn trọng, thần bí.","chuong":"@c0407"}],"tabs":{"diem":[{"text":"Chấp chưởng phân tông Thi Âm Tông Triệu quốc hơn hai trăm năm.","chuong":"@c0407"},{"text":"Bế quan tu luyện nâng bản lãnh tới Hóa Thần trước khi thây ma chiếm thân, để được tổng bộ cấp thân thể tốt thành đệ tử nòng cốt.","chuong":"@c0407"}],"kinhLich":[{"text":"Hơn 40 tuổi, anh tuấn; ngồi giữa hang động lớn ở trung tâm Thi Âm Tông, phía sau là màn sương đen vươn vô số xúc tu. Không nhận biết thần thức Vương Lâm khi hắn đột nhập.","bridge":true,"khoang":"@c0407"}],"tuViMoc":[{"chuong":"@c0407","canhGioi":"Nguyên Anh Hậu Kỳ","text":"Nguyên Anh Hậu Kỳ, đang bế quan nhằm đột phá Hóa Thần.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Không nhận biết thần thức Vương Lâm khi hắn đột nhập tông môn.","ghiChu":"@c0407"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0407"]},{"id":"hu-anh-nguyen-than-di-lac-tong","name":"Hư ảnh nguyên thần (đệ tử Di Lặc Tông)","cn":"","aliases":["Đệ tử Di Lặc Tông"],"gioiTinh":"nam","theLuc":[{"ten":"Di Lặc Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Hóa Thần Trung Kỳ","trangThai":"song","blurb":"Nguyên thần Hóa Thần Trung Kỳ ẩn trong màn sương đen sau Lý Thanh Bình; đệ tử Di Lặc Tông Thiên Vận Tinh, thân thể bị phá nát nên mua thân từ Thi Âm Tông.","vaiTro":"Hư ảnh nguyên thần phát hiện và cầu xin Vương Lâm khi hắn đột nhập Thi Âm Tông.","tinhCach":[{"text":"Kinh hãi, biết khúm núm cầu xin trước cường giả.","chuong":"@c0407"}],"tabs":{"diem":[{"text":"Đệ tử Di Lặc Tông ở Thiên Vận Tinh; tu công pháp nhạy bén thần thức nên phát hiện được Vương Lâm.","chuong":"@c0407"},{"text":"Thân thể bị phá nát, phải trả giá lớn mua thân thể từ Thi Âm Tông.","chuong":"@c0407"}],"kinhLich":[{"text":"Hư ảnh màn sương đen sau Lý Thanh Bình run lên, hiện hai luồng u quang đầy kinh hãi và kêu Tiền bối. Khai là đệ tử Di Lặc Tông Thiên Vận Tinh, đoán Vương Lâm là Anh Biến lão quái; bị Vương Lâm lạnh lùng tra hỏi vì sao người Thiên Vận Tinh lại đến Chu Tước Tinh.","bridge":true,"khoang":"@c0407"}],"tuViMoc":[{"chuong":"@c0407","canhGioi":"Hóa Thần Trung Kỳ","text":"Nguyên thần đạt Hóa Thần Trung Kỳ; được Vương Lâm khen có thể nhận thấy hắn.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Phát hiện và khúm núm cầu xin Vương Lâm, bị tra hỏi.","ghiChu":"@c0407"},{"ten":"Lý Thanh Bình","tag":"khac","quanHe":"Ẩn trong màn sương đen phía sau Lý Thanh Bình tại trung tâm Thi Âm Tông.","ghiChu":"@c0407"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0407"]},{"id":"tao-nhat-dau","name":"Tào Nhất Đấu","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thi Âm Tông","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Hóa Thần Kỳ","trangThai":"song","blurb":"Hư ảnh nguyên thần Hóa Thần tu sĩ điều dưỡng trong thân Lý Thanh Bình, người Thiên Vận Tinh, bị Vương Lâm thu phục làm nô bộc trăm năm để dẫn đường.","vaiTro":"Nô bộc kiêm người dẫn đường cho Vương Lâm tới Thiên Vận Tinh, bị thu vào hồn phiên.","tinhCach":[{"text":"Dáng vẻ thành thực, khiến Vương Lâm nhớ tới Hứa Lập Quốc năm xưa.","chuong":"@c0408"},{"text":"Tinh ranh, biết tính toán: chọn nơi điều dưỡng rẻ hơn và đòi đảm bảo trăm năm không chết trước khi bái chủ.","chuong":"@c0408"}],"tabs":{"diem":[{"text":"Hư ảnh nguyên thần Hóa Thần tu sĩ, đoạt xá điều dưỡng trong thân Lý Thanh Bình ở Chu Tước Tinh vì rẻ hơn Thiên Vận Tinh.","chuong":"@c0408"},{"text":"Người Thiên Vận Tinh, tinh tường địa thế, được Vương Lâm chọn làm dẫn đường.","chuong":"@c0408"}],"kinhLich":[{"text":"Bị Vương Lâm tra hỏi lộ tên, cách không bắt lại nguyên thần. Sau khi đòi đảm bảo trăm năm không chết, hắn bái Vương Lâm làm chủ nhân, nhận giao ước làm nô bộc trăm năm đổi lấy một thân thể Anh Biến Kỳ.","bridge":true,"khoang":"@c0408"},{"chuong":"@c0408","importance":"normal","tieuDe":"Bị thu vào hồn phiên","text":"Khoe lớn lên ở Thiên Vận Tinh, nhận làm dẫn đường. Hoàn tất giao ước, hắn bị Vương Lâm dùng cây hồn phiên (vốn chế ra để thu Lý Nguyên Phong) thu vào bên trong."},{"text":"Được Vương Lâm phất hồn phiên thả nguyên thần ra, Tào Nhất Đấu nhận ra đây chính là Thiên Vận Tinh quê cũ, chỉ về hướng tây cách khoảng ba mươi vạn dặm là sơn môn Thiên Vận Tông; hắn tình nguyện dẫn đường vì được hứa cho một thân thể anh biến.","bridge":true,"khoang":"@c0461"},{"text":"Bị Vương Lâm rung hồn phiên triệu ra, hồn phách Tào Nhất Đấu biến sắc khi nghe tên Huyết Tổ và Huyết Hồn đan. Hắn xác nhận đèn đúng là Huyết Hồn đan với 3614 ký tự phù văn, nhỏ máu lóe sáng lam, là một trong ba bảo vật Thiên Vận tinh, đồng thời lộ vẻ thèm muốn; nhưng cũng phân tích đây là mưu k��� phế đan của Huyết Tổ vì phương pháp phân biệt quá phổ biến.","bridge":true,"khoang":"@c0519"}],"tuViMoc":[{"chuong":"@c0408","canhGioi":"Hóa Thần Kỳ","text":"Xuất hiện dưới dạng hư ảnh nguyên thần Hóa Thần tu sĩ, đang điều dưỡng/đoạt xá trong thân Lý Thanh Bình.","importance":"minor"}],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Chủ nhân","ghiChu":"Bị Vương Lâm thu phục làm nô bộc trăm năm, lập giao ước ràng buộc sinh tử “ta không chết thì ngươi cũng không chết”, rồi bị thu vào hồn phiên."},{"ten":"Lý Thanh Bình","tag":"khac","quanHe":"Thân thể ký chủ","ghiChu":"Mượn thân Lý Thanh Bình điều dưỡng/đoạt xá; có liên hệ kỳ lạ khiến Lý Thanh Bình tỉnh dậy khi hắn kinh hãi."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người thu nhận nguyên thần của hắn ở Thi Âm tông","ghiChu":"Làm người dẫn đường để đổi lấy lời hứa một thân thể anh biến."},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Chủ nhân khống chế hồn phách, sai giám định Huyết Hồn đan","ghiChu":"Từng dẫn đường cho Vương Lâm ở Chu Tước tinh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0408","@c0461","@c0519"]},{"id":"to-tien-cu-ma-toc","name":"Tổ tiên Cự Ma Tộc","cn":"","aliases":["Người khổng lồ da xanh"],"gioiTinh":"nam","theLuc":[{"ten":"Cự Ma Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ (thân thể cường hãn hơn ngũ lục tinh cổ thần)","trangThai":"khong-ro","blurb":"Thi thể khổng lồ da xanh bị cây xanh tím ký sinh và pháp thuật giam cầm, còn sống nhưng bất động, liên tục kêu cứu. Là tổ tiên mang Cự Ma Tộc từ tinh không vào Chu Tước Tinh.","vaiTro":"Tổ tiên Cự Ma Tộc, đối tượng Vương Lâm lấy máu tươi ở Chương 409.","tinhCach":[{"text":"Khẩn thiết cầu cứu, hứa cho trọng bảo để được giải thoát.","chuong":"@c0409"}],"tabs":{"diem":[{"text":"Thân thể cực kỳ cứng rắn — tiên kiếm đâm bị phản chấn đẩy lùi, cường hãn hơn ngũ lục tinh cổ thần không kém.","chuong":"@c0409"},{"text":"Dấu ấn mờ hình lưỡi búa giữa lông mày — dấu hiệu nhận ra thân phận tổ tiên Cự Ma Tộc.","chuong":"@c0409"},{"text":"Còn sức sống mạnh mẽ nhưng bị pháp thuật thần kỳ giam cầm nên bất động.","chuong":"@c0409"}],"kinhLich":[{"text":"Khi Vương Lâm dùng Phong động có tiên lực cuốn tan đám sương trắng âm hàn, lộ ra thi thể khổng lồ da xanh trần truồng bay giữa không trung, toàn thân bị cây xanh tím ký sinh hút sức sống chuyển thành khí âm hàn.","bridge":true,"khoang":"@c0409"},{"text":"Liên tục kêu cứu và hứa cho trọng bảo của Cự Ma Tộc, nhưng bị Vương Lâm ngoảnh mặt làm ngơ. Vương Lâm dùng cành cây ký sinh làm vũ khí lấy máu tươi từ thân thể cứng rắn của lão.","bridge":true,"khoang":"@c0409"}],"tuViMoc":[],"tuVi":"Thân thể cực kỳ cường hãn, vượt hơn ngũ lục tinh cổ thần; cảnh giới cụ thể chưa rõ trong nguyên tác.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm lấy máu tươi, cự tuyệt lời cầu cứu và lời hứa trọng bảo.","ghiChu":"Năm xưa Vương Lâm từng giết lão tổ và phong ấn Cự Ma Tộc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0409"]},{"id":"loi-cat","name":"Lôi Cát","cn":"","aliases":["Vạn Phu Hậu Cự Ma Tộc"],"gioiTinh":"nam","theLuc":[{"ten":"Cự Ma Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Vạn Phu Hậu của Cự Ma Tộc, một người khổng lồ bị Thi Âm Tông phong ấn trong hang động và bị Vương Lâm lấy máu nuôi dưỡng. Bề ngoài cầu cứu xin làm vật cưỡi, thực chất mưu kéo dài thời gian để thoát phong ấn.","vaiTro":"Người khổng lồ bị phong ấn làm nguồn máu cho Vương Lâm; phản diện tiềm ẩn với mưu đồ thoát thân.","tinhCach":[{"text":"Xảo trá, giỏi che giấu: ngoài mặt lo lắng cầu xin nhưng cố tỏ bình thường để kéo dài thời gian.","chuong":"@c0410"},{"text":"Tham vọng và nuôi hận, thề báo thù Thi Âm Tông nếu có ngày thoát ra.","chuong":"@c0410"}],"tabs":{"diem":[{"text":"Vạn Phu Hậu của Cự Ma Tộc, thân thể tựa Tinh La Bàn nhưng hùng mạnh hơn, có thể ngao du tinh không và làm vật cưỡi quý.","chuong":"@c0410"},{"text":"Dụ Vương Lâm cứu mình bằng cách hứa làm nô bộc tọa kỵ trọn đời, dâng trọng bảo Khai Thiên Chi Thiết và dịch thể cốt tủy.","chuong":"@c0410"},{"text":"Mưu thật là câu giờ để máu cạn dưới một phần ba, đẩy cái cây xanh tím ký sinh ra mà nguyên thần xuất khiếu thoát phong ấn.","chuong":"@c0410"}],"kinhLich":[{"text":"Bị Vương Lâm dùng cấm phiên phong ấn cái cây xanh tím trên ngực rồi điểm cổ tạo ấn chú lấy máu vào bình ngọc. Lôi Cát cầu cứu, xưng Vạn Phu Hậu Cự Ma Tộc, hứa làm vật cưỡi và dâng Khai Thiên Chi Thiết (99 miếng tạo cổ thần chiến giáp), kể bị Tiên Di Tộc trọng thương rồi bị Thi Âm Tông thừa cơ phong ấn.","bridge":true,"khoang":"@c0410"},{"chuong":"@c0410","importance":"normal","tieuDe":"Mưu kéo dài thời gian bại lộ","text":"Vương Lâm nhận ra Lôi Cát trả lời quá tỉ mỉ là cố câu giờ, bèn ép máu chảy nhanh hơn rồi gỡ phong ấn rời đi, từ chối cứu và định giữ làm nguồn máu lâu dài. Sau khi Vương Lâm đi, Lôi Cát tiếc nuối vì còn thiếu nửa nén hương; cái cây xanh tím đầy răng chui ra từ xương sống lan bọc toàn thân, hoa tím hấp thụ máu sinh trưởng. Hắn thề báo thù Thi Âm Tông."}],"tuViMoc":[],"tuVi":"Chưa rõ cảnh giới tu vi cụ thể; là người khổng lồ Cự Ma Tộc cấp Vạn Phu Hậu, thân thể hùng mạnh tựa Tinh La Bàn, hiện đang bị phong ấn và suy yếu vì bị rút máu.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người phong ấn cái cây ký sinh và lấy máu hắn nuôi dưỡng","ghiChu":"Lôi Cát cầu cứu, dụ làm vật cưỡi và dâng bảo vật nhưng bị Vương Lâm nhìn thấu mưu kéo dài thời gian rồi từ chối, định giữ làm nguồn máu lâu dài."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Cái cây màu xanh tím ký sinh","loai":"vật ký sinh","trangThai":"dang-co","moTa":"Cây đầy răng sắc nhọn, hoa tím nở rộ yêu dị ký sinh trong xương cổ/xương sống Lôi Cát, hấp thụ máu và sức sống để sinh trưởng; bị Vương Lâm phong ấn và cố bảo toàn nguyên vẹn.","nguon":"@c0410"}]}},"nguon":["@c0410"]},{"id":"nhat-to-tien-di-toc","name":"Nhất Tổ Tiên Di Tộc","cn":"","aliases":["Thập nhất diệp Thuật Chú Sư"],"gioiTinh":"nam","theLuc":[{"ten":"Tiên Di Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thập nhất diệp Thuật Chú Sư","trangThai":"song","blurb":"Tổ tiên cao nhất Tiên Di Tộc lộ diện ở Chu Tước Tinh, thập nhất diệp Thuật Chú Sư hiện thân bằng hư ảnh năm màu trong suốt.","vaiTro":"Tổ tiên đứng đầu Tiên Di Tộc đến vây Chu Tước Tử, định xuất thủ đoạt Tu Tinh Chi Tinh nhưng bị Vân Tước Tử cản.","tinhCach":[{"text":"Cao ngạo nhưng biết hối hận, tỉnh táo nhận ra Tiên Di Tộc xuất hiện sớm là sai lầm","chuong":"@c0413"}],"tabs":{"diem":[{"text":"Thập nhất diệp Thuật Chú Sư — cấp bậc cao nhất Tiên Di Tộc lộ diện","chuong":"@c0413"},{"text":"Hư ảnh năm màu trong suốt, khí thế áp chế cả Chu Tước Tinh","chuong":"@c0413"}],"kinhLich":[{"chuong":"@c0413","importance":"normal","tieuDe":"Vây Chu Tước Tử","text":"Hạ xuống từ trên trời ở Chu Tước Sơn, hiện thân hư ảnh năm màu trong suốt, hối hận vì Tiên Di Tộc xuất hiện sớm, đáng lý nghe theo Vân Tước Tử âm thầm khống chế. Định xuất thủ với Chu Tước Tử nhưng bị Vân Tước Tử cản vì Tu Tinh Chi Tinh đã dung hợp với Chu Tước Tử."}],"tuViMoc":[{"chuong":"@c0413","canhGioi":"Thập nhất diệp Thuật Chú Sư","text":"Hư ảnh năm màu trong suốt giáng xuống, áp chế toàn cảnh","importance":"major"}],"nhanMach":[{"ten":"Vân Tước Tử","tag":"dong-minh","quanHe":"Đồng tộc — Nhị Tổ Tiên Di Tộc, cản hành động của Nhất Tổ","ghiChu":"Vân Tước Tử cản không cho xuất thủ"},{"ten":"Chu Tước Tử","tag":"doi-thu","quanHe":"Đối thủ trục — mục tiêu cướp Tu Tinh Chi Tinh","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0413"]},{"id":"tam-to-tien-di-toc","name":"Tam Tổ Tiên Di Tộc","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Tiên Di Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Một trong năm Tổ Tiên Di Tộc lộ diện vây Chu Tước Tử, cô gái mắt quyến rũ tướng mạo xinh đẹp.","vaiTro":"Tổ Tiên Di Tộc phía nam, đi cùng hai linh hồn tổ tiên đời trước hư ảo.","tinhCach":[{"text":"Quyến rũ, lạnh lùng","chuong":"@c0413"}],"tabs":{"diem":[{"text":"Cô gái mắt quyến rũ, tướng mạo xinh đẹp — một trong Ngũ Tổ Tiên Di Tộc","chuong":"@c0413"},{"text":"Đi cùng hai linh hồn tổ tiên đời trước hư ảo","chuong":"@c0413"}],"kinhLich":[{"text":"Xuất hiện ở phía nam Chu Tước Sơn cùng hai linh hồn tổ tiên đời trước hư ảo, tham gia vây Chu Tước Tử.","bridge":true,"khoang":"@c0413"}],"tuViMoc":[],"nhanMach":[{"ten":"Nhất Tổ Tiên Di Tộc","tag":"dong-minh","quanHe":"Đồng tộc — cùng vây Chu Tước Tử","ghiChu":""},{"ten":"Chu Tước Tử","tag":"doi-thu","quanHe":"Đối thủ — vây công","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0413"]},{"id":"thieu-toc-truong-tien-di-toc","name":"Thiếu tộc trưởng Tiên Di Tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tiên Di Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Thiếu tộc trưởng Tiên Di Tộc trẻ tuổi, đầy ấn ký màu vàng khác thường — người Vương Lâm sẽ nhận ra.","vaiTro":"Đại diện thế hệ trẻ Tiên Di Tộc, theo các Tổ vây Chu Tước Tử rồi vào Chu Tước mộ.","tinhCach":[{"text":"Trẻ tuổi, mang khí chất khác biệt với tộc nhân thường (ấn ký vàng thay vì đen)","chuong":"@c0413"}],"tabs":{"diem":[{"text":"Trẻ tuổi, đầy ký hiệu/ấn ký màu vàng khác với màu đen thường của tộc nhân","chuong":"@c0413"},{"text":"Người Vương Lâm sẽ nhận ra — gợi danh tính liên quan tới Vương Lâm","chuong":"@c0413"}],"kinhLich":[{"text":"Xuất hiện ở phía tây Chu Tước Sơn cùng các Tổ Tiên Di Tộc, ấn ký màu vàng đầy người.","bridge":true,"khoang":"@c0413"},{"text":"Theo Kiền Phong và Liễu Mi nhảy vào Chu Tước mộ ngay sau khi Chu Tước Sơn nứt mở, cùng một số tộc nhân Tiên Di Tộc.","bridge":true,"khoang":"@c0413"}],"tuViMoc":[],"nhanMach":[{"ten":"Nhất Tổ Tiên Di Tộc","tag":"su-mon","quanHe":"Tổ tiên trong tộc","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người quen cũ — Vương Lâm sẽ nhận ra danh tính","ghiChu":"Foreshadowing — danh tính lộ về sau"},{"ten":"Chu Tước Tử","tag":"doi-thu","quanHe":"Đối thủ — vây công","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0413"]},{"id":"man-hoang-nam-minh","name":"Man Hoang Nam Minh","cn":"","aliases":["Tôn giả Man Hoang Nam Minh"],"gioiTinh":"nam","theLuc":[{"ten":"Tán tu","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Hóa Thần hậu kỳ đại viên mãn (đang tôi luyện đột phá Anh Biến)","trangThai":"song","blurb":"Tôn giả lão già áo bào đen gầy như bộ xương khô, mắt u quang; nhận ra thực lực Vương Lâm liền cung kính bái kiến tiền bối và nhường đường.","vaiTro":"Tu sĩ Hóa Thần hậu kỳ đại viên mãn đang chờ vào Chu Tước mộ, dẫn theo một đệ tử kiêu ngạo.","tinhCach":[{"text":"Nhãn lực sắc bén, biết tiến lui — vừa nhận ra Vương Lâm không thể trêu chọc liền lập tức cung kính, quát đệ tử câm miệng.","chuong":"@c0414"}],"tabs":{"diem":[{"text":"Lão già áo bào đen gầy như bộ xương khô, hai mắt u quang, thân thể đã uẩn hàm một tia tiên lực.","chuong":"@c0414"},{"text":"Vì thiếu tiên ngọc nên chỉ tôi luyện được một phần thân thể, chưa đột phá nổi Anh Biến.","chuong":"@c0414"}],"kinhLich":[{"text":"Ngồi khoanh chân cách Chu Tước Sơn trăm trượng trong nhóm năm tu sĩ Hóa Thần hậu kỳ đại viên mãn. Khi đệ tử quát chặn Vương Lâm, lão nhận ra thực lực hắn liền quát đệ tử câm miệng, đứng dậy ôm quyền tự xưng Man Hoang Nam Minh, bái kiến tiền bối và xin lỗi thay đệ tử rồi tránh đường. Sau đó giảng cho đệ tử rằng tu vi người này không chỉ Anh Biến và cảnh giới trên Anh Biến hậu kỳ là Vấn Đinh.","bridge":true,"khoang":"@c0414"}],"tuViMoc":[{"chuong":"@c0414","canhGioi":"Hóa Thần hậu kỳ đại viên mãn","text":"Tu sĩ Hóa Thần hậu kỳ đại viên mãn, thân thể đã uẩn hàm một tia tiên lực, đang tôi luyện thân thể để đột phá Anh Biến nhưng vì thiếu tiên ngọc nên chỉ tôi luyện được một phần.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người lão bái kiến làm tiền bối","ghiChu":"Nhận ra thực lực Vương Lâm, cung kính nhường đường tại Chu Tước Sơn (@c0414)."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0414"]},{"id":"mo-dung-van","name":"Mộ Dung Vân","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tán tu","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Hóa Thần trung kỳ","trangThai":"song","blurb":"Tu sĩ Hóa Thần trung kỳ thuộc nhóm đầu tiên vào Chu Tước mộ, đề nghị đồng hành cùng Vương Lâm và tiết lộ lối vào tế đàn của Kiền Phong.","vaiTro":"Nhân vật phụ — bạn đồng hành tạm thời của Vương Lâm trong Chu Tước mộ; mang nét khả nghi qua đồ án tông phái và vệt máu đen trên áo.","tinhCach":[{"text":"Niềm nở, chủ động bắt chuyện và mời đồng hành để tăng cơ hội thu mệnh hồn.","chuong":"@c0416"},{"text":"Lộ vẻ sợ hãi khi kể về tế đàn chết người.","chuong":"@c0416"}],"tabs":{"diem":[{"text":"Mặc áo xanh cũ nát có vệt máu đã đen, ống tay áo mang đồ án tiêu chí đệ tử tông phái.","chuong":"@c0416"},{"text":"Thuộc nhóm tu sĩ đầu tiên tiến vào Chu Tước mộ (đang ở Chu Tước Quốc khi mộ mở).","chuong":"@c0416"}],"kinhLich":[{"text":"Cùng một cô gái mặt rỗ áo trắng bay tới gặp Vương Lâm (đang giả Hóa Thần sơ kỳ, xưng Thanh Mộc); tự xưng Mộ Dung Vân và đề nghị đi cùng để tăng cơ hội thu mệnh hồn. Kể lại cảnh tận mắt thấy Kiền Phong cùng mấy vị bát diệp Thuật Chú Sư Tiên Di Tộc tiến vào bên trong Chu Tước mộ qua một tế đàn hẻo lánh; cũng kể hai bát diệp Thuật Chú Sư và hai Anh Biến lão quái bỏ mạng tại đó mà không thấy địch nhân.","bridge":true,"khoang":"@c0416"}],"tuViMoc":[{"chuong":"@c0416","canhGioi":"Hóa Thần trung kỳ","text":"Lần đầu xuất hiện đã ở Hóa Thần trung kỳ.","importance":"normal"}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-hanh","quanHe":"Bạn đồng hành tạm thời trong Chu Tước mộ","ghiChu":"Mời Vương Lâm (đang xưng Thanh Mộc) đi cùng; bị Vương Lâm cảnh giác và châm chọc."},{"ten":"Kiền Phong","tag":"khac","quanHe":"Người mà Mộ Dung Vân tận mắt thấy tiến vào tế đàn","ghiChu":"Kể lại cho Vương Lâm về lối vào của Kiền Phong."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0416"]},{"id":"mac-van-hai","name":"Mặc Vân Hải","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tán tu","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến sơ kỳ","trangThai":"song","blurb":"Lão già tóc hoa râm áo xám, tu sĩ Anh Biến sơ kỳ trong nhóm mười sáu người ngoài Chu Tước Sơn; ngộ nhận Vương Lâm là Tằng đạo hữu rồi liên thủ, dùng Sưu hồn thuật moi hồn giết Mộ Dung Vân để dò đường lên Tế Đàn.","vaiTro":"Kẻ đồng hành bất ngờ của Vương Lâm trên đường vào Tế Đàn, bản tính tàn nhẫn thủ đoạn.","tinhCach":[{"text":"Âm trầm, cảnh giác, tay trắng truy đuổi vẫn giữ bình tĩnh.","chuong":"@c0417"},{"text":"Tàn nhẫn thủ đoạn — lập tức giết Mộ Dung Vân ngay khi hết giá trị lợi dụng.","chuong":"@c0417"}],"tabs":{"diem":[{"text":"Bị một tia chớp giao long trắng quỷ dị truy đuổi không tha.","chuong":"@c0417"},{"text":"Ngộ nhận Vương Lâm là cố nhân Tằng đạo hữu (Tằng Ngưu).","chuong":"@c0417"},{"text":"Sử dụng Sưu hồn thuật moi hồn để khai thác ký ức nạn nhân.","chuong":"@c0417"}],"kinhLich":[{"text":"Lão già tóc hoa râm áo xám cưỡi phi kiếm trắng lao tới, kiếm mang kinh động bị khí lạnh bao quanh; phía sau bị một tia chớp hình giao long trắng có linh tính bám đuổi. Nhận ra Vương Lâm là tu sĩ Anh Biến trong nhóm mười sáu người ngoài Chu Tước Sơn.","bridge":true,"khoang":"@c0417"},{"chuong":"@c0417","importance":"normal","tieuDe":"Tự xưng Mặc Vân Hải, kết liên thủ","text":"Sau khi tia chớp rút lui, lão ôm quyền cảm tạ rồi tự xưng Mặc Vân Hải, hỏi manh mối tiến vào bên trong. Đồng ý liên thủ với Vương Lâm bảo mệnh Mộ Dung Vân để được dẫn đường tới Tế Đàn; mỗi người mang một người bay toàn lực ba ngày."},{"chuong":"@c0417","importance":"normal","tieuDe":"Sưu hồn giết Mộ Dung Vân","text":"Tới Tế Đàn, lão bất ngờ chụp Mộ Dung Vân, dùng Sưu hồn thuật lên đỉnh đầu để xác nhận lời hắn thật; Mộ Dung Vân run rẩy rồi ngã chết phát tử khí. Lão lao lên đỉnh Tế Đàn dò đường, nhờ Vương Lâm hộ pháp, sắc mặt cổ quái cúi nhìn chỗ lõm."}],"tuViMoc":[{"chuong":"@c0417","canhGioi":"Anh Biến sơ kỳ","text":"Tu sĩ Anh Biến sơ kỳ, một trong nhóm mười sáu người tiến vào ngoài Chu Tước Sơn.","importance":"minor"}],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đồng minh tạm thời","ghiChu":"Ngộ nhận Vương Lâm là Tằng đạo hữu; liên thủ vào Tế Đàn rồi nhờ hộ pháp."},{"ten":"Mộ Dung Vân","tag":"doi-thu","quanHe":"Kẻ bị hắn giết","ghiChu":"Hứa bảo mệnh nhưng dùng Sưu hồn thuật moi hồn giết chết khi hết giá trị."}],"tuiDo":{"phapBao":[{"ten":"Phi kiếm trắng","loai":"phap-bao","moTa":"Phi kiếm màu trắng gào thét bay tới, bao quanh bởi khí lạnh, mang kiếm mang kinh động trời đất.","nguon":"@c0417"}],"danDuoc":[],"congPhap":[{"ten":"Sưu hồn thuật","loai":"cong-phap","moTa":"Thuật moi hồn: đặt tay lên đỉnh đầu nạn nhân, hai mắt phát quang yêu dị lục soát ký ức/linh hồn, khiến nạn nhân run rẩy rồi ngã chết phát tử khí.","nguon":"@c0417"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0417"]},{"id":"nu-tu-tuong-mao-kho-coi","name":"Nữ tử tướng mạo khó coi","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Tán tu","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (tu vi thấp)","trangThai":"song","blurb":"Nữ tử tướng mạo khó coi dẫn đầu phi hành, tu vi thấp, đồng hành cùng Vương Lâm; được hắn dùng lực kỳ dị bao bọc mang theo, từng hỏi Vương Lâm có phải Tằng Ngưu.","vaiTro":"Người đồng hành tu vi thấp của Vương Lâm trên đường tới Tế Đàn.","tinhCach":[{"text":"Cẩn trọng, biết cảnh báo nguy hiểm phía trước.","chuong":"@c0417"}],"tabs":{"diem":[{"text":"Tu vi thấp, không phát hiện Vương Lâm âm thầm thả pháp bảo trong sương đen.","chuong":"@c0417"},{"text":"Đứng cạnh Mộ Dung Vân lúc Vương Lâm cách không đánh linh quyết vạch trần bản chất.","chuong":"@c0418"}],"kinhLich":[{"text":"Dẫn đầu phi hành cùng Vương Lâm và Mộ Dung Vân, cảnh báo có người phía trước. Vì tu vi thấp, được Vương Lâm dùng lực kỳ dị bao bọc mang theo bay toàn lực; từng hỏi Tiền bối có phải Tằng Ngưu.","bridge":true,"khoang":"@c0417"},{"text":"Đứng bên Mộ Dung Vân, do dự nhìn từ Mộ Dung Vân sang Vương Lâm khi Vương Lâm xuất thủ lộ bản chất hắc khí của Mộ Dung Vân; Vương Lâm không để ý đến nàng.","bridge":true,"khoang":"@c0418"}],"tuViMoc":[],"tuVi":"Tu vi thấp, không rõ cảnh giới cụ thể.","nhanMach":[{"ten":"Vương Lâm","tag":"dong-hanh","quanHe":"Người đồng hành","ghiChu":"Được Vương Lâm bao bọc mang theo; hỏi hắn có phải Tằng Ngưu."},{"ten":"Mộ Dung Vân","tag":"dong-hanh","quanHe":"Đứng cùng phía trong Chu Tước Mộ","ghiChu":"Do dự quan sát khi Mộ Dung Vân bị Vương Lâm vạch mặt."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0418","@c0417"]},{"id":"nguoi-tu-khi-rung-xuong","name":"Người tử khí (nhân vật rừng xương)","cn":"","aliases":["Kẻ rừng xương","Người tử khí"],"gioiTinh":"nam","theLuc":[{"ten":"Tán tu","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Kẻ bí ẩn toàn thân bao trùm tử khí xuất hiện bên ngoài Toái Tinh Loạn ở Tu Ma Hải, quanh người là hư ảnh rừng xương khô, dường như săn lùng và ăn thượng cổ tu sĩ.","vaiTro":"Nhân vật bí ẩn hé lộ cuối chương, đặt nền cho biến cố quanh Toái Tinh Loạn.","tinhCach":[{"text":"Thận trọng, do dự trước nơi quá nguy hiểm dù bị thôi thúc bởi cơn đói.","chuong":"@c0423"}],"tabs":{"diem":[{"text":"Toàn thân bị tử khí bao trùm không rõ diện mạo, quanh người loé hư ảnh đám xương khô như cánh rừng xương.","chuong":"@c0423"},{"text":"Cảm nhận được hương vị thượng cổ tu sĩ, dường như săn lùng và ăn thượng cổ tu sĩ.","chuong":"@c0423"}],"kinhLich":[{"text":"Bên ngoài Toái Tinh Loạn ở Tu Ma Hải, hắn cảm nhận tia thiên kiếp chỉ do một tiểu bối tế luyện thượng cổ pháp bảo; đi khắp Chu Tước Tinh không thấy thượng cổ tu sĩ nào nên đói bụng. Duy nơi này ngửi thấy hương vị thượng cổ tu sĩ, song hắn do dự có nên vào vì quá nguy hiểm.","bridge":true,"khoang":"@c0423"}],"tuViMoc":[],"tuVi":"Cảnh giới chưa rõ, song khí thế cường đại đủ để săn lùng thượng cổ tu sĩ.","nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0423"]},{"id":"mac-luc-hai","name":"Mạc Lực Hải","cn":"","aliases":["Mạc Lệ Hải"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Lão già đoạt xá khoanh chân ngồi trên đỉnh Linh Sơn cùng một con khỉ nhỏ là khôi lỗi, ánh mắt bắn ra hung mang.","vaiTro":"Kẻ đoạt xá mới lộ diện trên Linh Sơn, đối mặt Vân Tước Tử.","tinhCach":[{"text":"Trầm tĩnh ngạo nghễ, sau khi bị truy hỏi vẫn ung dung xưng danh rồi nhắm mắt ngồi lại.","chuong":"@c0428"},{"text":"Ẩn chứa sát khí — mắt bắn ra hung mang khi bị động chạm.","chuong":"@c0428"}],"tabs":{"diem":[{"text":"Là kẻ đoạt xá, mượn thân lão già và dùng con khỉ nhỏ làm khôi lỗi che mắt.","chuong":"@c0428"},{"text":"Bị Vân Tước Tử nhận ra thân phận đoạt xá ngay khi giáp mặt.","chuong":"@c0428"}],"kinhLich":[{"chuong":"@c0428","importance":"normal","tieuDe":"Lộ diện kẻ đoạt xá trên Linh Sơn","text":"Khi Vân Tước Tử hạ xuống đỉnh Linh Sơn, hắn hiện ra là lão già khoanh chân ngồi với con khỉ nhỏ trên vai. Bị Vân Tước Tử nhận ra là kẻ đoạt xá và truy hỏi, con khỉ (vốn là rối) phát tiếng chi chi; lão xưng tên Mạc Lực Hải rồi nhắm mắt ngồi lại, mắt bắn ra hung mang."},{"chuong":"@c0531","importance":"normal","tieuDe":"Rời Cổ Yêu thành tới kinh đô","text":"Đứng trên tường thành cửa đông Cổ Yêu thành tiếc nuối vì Thập Tam — bộ thứ mười tám hắn cần để hoàn tất Thập Bát Yêu Ma Thân — bị Vương Lâm mang đi; cùng Vương Lâm qua ba truyền tống trận hướng kinh thành Thiên Yêu quận, mưu cầu vào vòng ba cuộc chiến Yêu tướng để giành tư cách vào Cổ Yêu điện và chức phó soái."},{"text":"Yêu tướng trấn thủ Cổ Yêu thành, tu vi đứng đầu trong số Yêu tướng, sau ba mươi năm mới trở về Đế Đô qua truyền tống trận thứ mười bốn, dẫn theo Vương Lâm. Được Yêu binh cung nghênh là “Mạc Yêu tướng”, mời Vương Lâm về phủ ở Hồng thành vì kinh thành đang hỗn tạp thế lực.","bridge":true,"khoang":"@c0532"},{"chuong":"@c0532","importance":"minor","text":"Mười chín kỵ binh giáp đen Hóa Thần dưới trướng quỳ tham kiến Chủ tướng; ông giới thiệu Vương Lâm là “Vương tướng” bạn tốt rồi cùng phóng ngựa về phủ, đoạn trầm sắc tăng tốc khi nghe tiếng vó ngựa lạ phía trước."},{"text":"Hai đoàn người lao thẳng vào nhau; Mạc Lệ Hải tung Thập Băng Quyền Ý đối Lục Chỉ Kiếm Quyết của Thạch Tiễn, cả hai nén lực ở mức thấp nhất. Nhờ Vương Lâm trợ một điểm, chiến mã Mạc Lệ Hải không tổn hại trong khi mã Thạch Tiễn nứt bốn chân — cao thấp đã rõ.","bridge":true,"khoang":"@c0533"},{"bridge":true,"khoang":"@c0533","text":"Vào Đế Đô bái kiến Yêu Đế báo cáo công tác, rồi mấy ngày đi sớm về muộn thăm hỏi các Yêu soái, Phó soái, Yêu tướng thân thiết, cảm nhận Thiên Yêu thành phong vân tụ hội trước cuộc chiến Yêu tướng."},{"chuong":"@c0535","importance":"normal","tieuDe":"Sắp xếp đưa Vương Lâm vào Hồng lao","text":"Yêu tu chủ Mạc phủ; chứng kiến năm đạo sát lục khí của Vương Lâm dung hợp len qua quyền phong chấn động yêu giáp, hắn kinh ngạc nhận ra thứ khí xám sắc bén như yêu kiếm lại có biến hóa khó giải dẫn động sinh cơ trong cơ thể, nếu hình thành tới mấy ngàn đạo thì cực kỳ đáng sợ. Hắn từ chối một tháng nhưng chấp nhận bảy ngày, hẹn ba ngày sau trả lời, và quyết giữ quan hệ tốt không để Vương Lâm thành kẻ địch."}],"tuViMoc":[],"tuVi":"Cảnh giới chưa rõ; là một kẻ đoạt xá ẩn mình trên Linh Sơn.","nhanMach":[{"ten":"Vân Tước Tử","tag":"doi-thu","quanHe":"Bị Vân Tước Tử truy hỏi và nhận ra thân phận đoạt xá khi giáp mặt trên Linh Sơn.","ghiChu":"@c0428"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đồng hành tới kinh đô, kỳ vọng được trợ giúp hoàn tất Thập Bát Yêu Ma Thân","ghiChu":""},{"ten":"Thập Tam","tag":"khac","quanHe":"Là bộ thứ mười tám còn thiếu của Thập Bát Yêu Ma Thân, bị Vương Lâm mang đi","ghiChu":""},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Mời làm trợ thủ cuộc chiến Yêu tướng, bảo chứng thân phận “Vương tướng”","ghiChu":""},{"ten":"Thạch Tiễn","tag":"doi-thu","quanHe":"Kình địch trong cuộc chiến Yêu tướng","ghiChu":"Đấu một chiêu ngang ngửa trên quân đạo."},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Quân sư phe Thạch Tiễn","ghiChu":"Đang trọng thương; nếu khỏe có thể giết được Mạc Lệ Hải theo lời Trần Đào."},{"ten":"Yêu Đế","tag":"cap-tren","quanHe":"Quân chủ Thiên Yêu quận","ghiChu":"Thân truyền thức thứ ba trong Thần Thông Tam Thức cho Mạc Lệ Hải."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đối tác giao dịch — đổi sự giúp đỡ lấy việc sắp xếp Vương Lâm vào Hồng lao tu luyện","ghiChu":"@c0535"},{"ten":"Thập Tam","tag":"khac","quanHe":"Từng lấy mạng Thập Tam để đổi lấy sự giúp đỡ của Vương Lâm","ghiChu":"@c0535"}],"tuiDo":{"phapBao":[{"ten":"Con khỉ nhỏ (khôi lỗi)","loai":"khôi lỗi","trangThai":"dang-co","moTa":"Con khỉ nhỏ mắt hồng quang đậu trên vai, thực chất là một con rối; phát tiếng chi chi khiến lão dừng động thủ.","nguon":"@c0428"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0428","@c0531","@c0532","@c0533","@c0535"]},{"id":"thac-lam","name":"Thác Lâm","cn":"","aliases":["Lão già (lối vào Chu Tước Sơn)"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Bát tinh Cổ Thần (lực lượng truyền thừa, chỉ phát huy được tới năm tinh)","trangThai":"song","blurb":"Ma niệm sinh từ Cổ Thần Đồ Ti, mang nụ cười quỷ dị; nắm lực lượng truyền thừa bát tinh nhưng chỉ phát huy được tới năm tinh, khao khát đoạt ký ức truyền thừa từ Vương Lâm.","vaiTro":"Lão già âm trầm lưu nụ cười quỷ dị đứng nơi lối vào Chu Tước Sơn, tạo cảm giác uy hiếp đáng sợ hơn Vân Tước Tử mấy lần. Là ma niệm sinh từ Cổ Thần Đồ Ti — kẻ thù cũ mà Vương Lâm từng trêu chọc khi mới Kết Đan tiến vào Cổ Thần chi địa.","tinhCach":[{"text":"Âm trầm, quỷ dị; nụ cười khiến đối phương kinh tâm dù chưa từng giao đấu.","chuong":"@c0430"},{"text":"Khao khát mãnh liệt việc đoạt ký ức truyền thừa Đồ Ti để chân chính thành bát tinh Cổ Thần.","chuong":"@c0430"}],"tabs":{"diem":[{"text":"Ma niệm sinh từ Cổ Thần Đồ Ti, cùng nguồn truyền thừa với Vương Lâm.","chuong":"@c0430"},{"text":"Nắm lực lượng truyền thừa bát tinh nhưng không thi triển được, chỉ phát huy bản mạng thuật cấp thấp tương đương năm tinh — vẫn siêu việt Vấn Đỉnh kỳ.","chuong":"@c0430"}],"kinhLich":[{"text":"Đứng nơi lối vào Chu Tước Sơn với nụ cười quỷ dị, tạo cảm giác uy hiếp khiến Vương Lâm kinh tâm. Nhờ cảm ứng huyền diệu của Anh Biến tu sĩ, Vương Lâm nhận ra lão chính là ma niệm Thác Lâm sinh từ Cổ Thần Đồ Ti — kẻ hắn từng trêu chọc thuở mới Kết Đan.","bridge":true,"khoang":"@c0430"}],"tuViMoc":[{"chuong":"@c0430","canhGioi":"Bát tinh Cổ Thần (lực lượng)","text":"Thừa kế lực lượng truyền thừa bát tinh của Cổ Thần Đồ Ti, nhưng không thi triển được; chỉ phát huy được bản mạng thuật cấp thấp nhất tương đương năm tinh Cổ Thần — vẫn siêu việt Vấn Đỉnh kỳ. Thuộc hệ Cổ Thần, không phải tu vi tu chân thông thường.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ truyền thừa","ghiChu":"Vương Lâm từng trêu chọc Thác Lâm khi mới Kết Đan tiến vào Cổ Thần chi địa; nay cả hai cùng tranh truyền thừa Đồ Ti — Thác Lâm muốn đoạt ký ức truyền thừa mà Vương Lâm đang giữ."},{"ten":"Cổ thần Đồ Ti","tag":"khac","quanHe":"Bản nguyên sinh ra","ghiChu":"Thác Lâm là ma niệm sinh từ Cổ Thần Đồ Ti, nắm phần lực lượng truyền thừa."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Bản mạng thuật","loai":"thần thông bẩm sinh","moTa":"Các bản mạng thuật Thác Lâm tự nhiên nắm giữ khi sinh ra từ ma niệm Đồ Ti, qua đó vận dụng được chút lực lượng truyền thừa nhưng chỉ ở cấp thấp nhất.","nguon":"@c0430"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0430"]},{"id":"kim-giap-dai-han","name":"Kim Giáp Đại Hán","cn":"","aliases":["Đại hán giáp vàng"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Thủ hộ uy nghiêm trong kim sắc thế giới sau cánh cửa Linh Sơn, cầm kim sắc cự kiếm trấn giữ cung điện giữa không trung.","vaiTro":"Thủ hộ kim sắc thế giới — trấn giữ cung điện trên đảo nhỏ, đánh lui kẻ xâm nhập.","tinhCach":[{"text":"Uy nghiêm, mắt như điện, ra tay quyết liệt với kẻ đột nhập.","chuong":"@c0431"}],"tabs":{"diem":[{"text":"Tướng mạo uy nghiêm, mắt như điện, tóc đen phiêu tán, cầm kim sắc cự kiếm.","chuong":"@c0431"},{"text":"Vung kiếm dâng cả biển vàng thành sóng lớn nuốt chửng đảo nhỏ, chém ra hơn trăm đạo kiếm khí.","chuong":"@c0431"}],"kinhLich":[{"text":"Từ hào quang vạn trượng trong cung điện kim sắc thế giới bước ra, vung cự kiếm dâng biển vàng nuốt đảo, chém hơn trăm đạo kiếm khí đẩy lùi Vân Tước Tử khiến hắn hoá lưu tinh trốn xuống đáy biển.","bridge":true,"khoang":"@c0431"},{"text":"Định huy kiếm chém con khỉ nhỏ thì bị hồng quang khí thế độc ác của nó (tràn hơn ba thước) làm thân chấn động, kiếm quang chậm lại; con khỉ nhếch miệng cười lùi về theo lão già âm trầm.","bridge":true,"khoang":"@c0431"}],"tuViMoc":[],"tuVi":"Tu vi chưa rõ; sức chiến đấu cực mạnh, dâng được cả biển vàng và áp chế Vân Tước Tử.","nhanMach":[{"ten":"Chu Tước Tử","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Đánh lui Vân Tước Tử (Chu Tước Tử) khi hắn lao vào cung điện."},{"ten":"Con khỉ nhỏ","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Bị con khỉ nhỏ nhiễm máu biển máu áp chế bằng hồng quang."},{"ten":"Lão già âm trầm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Con khỉ trên vai lão già âm trầm áp chế hắn rồi lùi về theo lão."}],"tuiDo":{"phapBao":[{"ten":"Kim sắc cự kiếm","loai":"pháp bảo","trangThai":"dang-co","moTa":"Cự kiếm sắc vàng tản kim mang, dâng được biển vàng thành sóng lớn nuốt đảo và phóng ra hơn trăm đạo kiếm khí nhiều hình dạng.","nguon":"@c0431"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0431"]},{"id":"ly-dan-nam","name":"Lý Đan Nam","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Nguyên Anh hậu kỳ","trangThai":"song","blurb":"Thanh niên nhỏ con sống ở Minh Hồng thành, làm người chỉ đường kiêm môi giới, dẫn Vương Lâm vào phường thị tự do tìm mua Khôn Mộc Thạch.","vaiTro":"Người dẫn đường tại Minh Hồng thành trên Giao Dịch Tinh.","tinhCach":[{"text":"Nhanh nhẹn, rành rẽ thị trường, biết nhìn người để chào mời dịch vụ","chuong":"@c0445"},{"text":"Thẳng thắn khuyên khách cân nhắc khi món hàng đắt mà ít công dụng","chuong":"@c0445"}],"tabs":{"diem":[{"text":"Từ nhỏ sống ở Minh Hồng thành, thông thạo các gian hàng và phường thị tự do","chuong":"@c0445"},{"text":"Nhận ra ngay Khôn Mộc Thạch là vật thuộc tính mộc sống trên nham thạch, mười năm mọc một tấc","chuong":"@c0445"},{"text":"Sinh ra và lớn lên ở Minh Hồng thành, thông thạo đường đi nước bước và các gian hàng.","chuong":"@c0445"}],"kinhLich":[{"text":"Âm thầm đi theo Vương Lâm từ khi hắn vào Minh Hồng thành, đến gian hàng thứ bảy thì lộ diện, mời chỉ dẫn với giá mười khối thượng phẩm linh thạch. Khi nghe hỏi mua Khôn Mộc Thạch, hắn khuyên đừng mua vì giá cao mà chỉ tăng tốc độ phi kiếm, rồi dẫn Vương Lâm vào phường thị tự do phía tây thành.","bridge":true,"khoang":"@c0445"},{"text":"Âm thầm đi theo Vương Lâm từ khi vào thành, đến gian hàng thứ bảy thì lộ diện mời chỉ dẫn với giá mười khối thượng phẩm linh thạch. Khi nghe Vương Lâm hỏi mua Khôn Mộc Thạch, hắn khuyên đừng mua vì giá cao mà chỉ tăng tốc độ phi kiếm, rồi dẫn Vương Lâm vào phường thị tự do phía tây.","bridge":true,"khoang":"@c0445"}],"tuViMoc":[{"chuong":"@c0445","canhGioi":"Nguyên Anh hậu kỳ","text":"Tu vi Nguyên Anh hậu kỳ, chưa Hóa Thần.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Khách thuê chỉ đường","ghiChu":"Dẫn Vương Lâm tìm mua Khôn Mộc Thạch với phí mười khối thượng phẩm linh thạch"}],"tuiDo":{}},"nguon":["@c0445"]},{"id":"bach-vi","name":"Bạch Vi","cn":"","aliases":["Công tử áo bào tím"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến trung kỳ đỉnh phong","trangThai":"song","blurb":"Công tử áo bào tím đến từ Thiên Vận Tinh, sư môn Thiên Vận Tông, dùng quạt lông trắng, khí chất phong nhã nhưng ngạo nghễ; ném chén trà cứu người hầu nhưng bị Vương Lâm hóa giải.","vaiTro":"Công tử Thiên Vận Tông gặp Vương Lâm tại cửa hàng Thương Thị ở thành bắc Minh Tư thành.","tinhCach":[{"text":"Khí chất công tử, ngang ngược nhưng nhã nhặn với người ngang hàng","chuong":"@c0446"},{"text":"Tỏ thái độ kỳ dị, thâm thúy với Vương Lâm, ngâm thơ ‘tâm duyệt quân hề quân bất tri’","chuong":"@c0446"}],"tabs":{"diem":[{"text":"Mày kiếm mắt sáng, ánh mắt thâm thúy, cầm quạt lông trắng toát khí chất công tử","chuong":"@c0446"},{"text":"Tu vi Anh Biến trung kỳ đỉnh phong, phóng tiên lực làm dao động không gian","chuong":"@c0446"},{"text":"Anh Biến trung kỳ đỉnh phong, tiên lực phóng ra làm dao động không gian","chuong":"@c0446"},{"text":"Đến từ Thiên Vận Tinh, sư môn Thiên Vận Tông; mua vật mừng thọ một vạn năm của sư tôn","chuong":"@c0446"},{"text":"Ánh mắt kỳ dị, ngâm thơ tỏ tình ý lạ với Vương Lâm","chuong":"@c0446"}],"kinhLich":[{"text":"Khi người hầu áo lam của Bạch Vi ngăn cản Vương Lâm và bị một quyền phế tiên cơ, Bạch Vi từ gian hàng thứ ba ném một chén trà chứa tiên lực khổng lồ để cản, nhưng bị Vương Lâm hóa giải bằng pháp thuật Tinh Chuyển. Bạch Vi hiện thân, gạt lời xin giết Vương Lâm của người hầu, tự giới thiệu đến từ Thiên Vận Tinh sư môn Thiên Vận Tông và mời Vương Lâm có dịp ghé thăm.","bridge":true,"khoang":"@c0446"},{"text":"Bạch Vi nhìn theo Vương Lâm vào cửa hàng với ánh mắt kỳ dị, đập quạt ngâm thơ, hứa sẽ cấp lại tiên cơ cho người hầu khi về Thiên Vận Tinh, rồi vào cửa hàng thứ ba để mua vật tinh xảo cho ngày mừng thọ một vạn năm của sư tôn.","bridge":true,"khoang":"@c0446"},{"text":"Khi người hầu áo lam bị Vương Lâm đánh phế tiên cơ, Bạch Vi ném chén trà chứa tiên lực khổng lồ ngăn cản nhưng bị Vương Lâm hóa giải bằng Tinh Chuyển; sau đó nhã nhặn tự giới thiệu và mời Vương Lâm ghé Thiên Vận Tinh.","bridge":true,"khoang":"@c0446"},{"text":"Đập quạt ngâm \"Sơn hữu mộc hề mộc hữu chi, tâm duyệt quân hề quân bất tri…\", ánh mắt kỳ dị nhìn Vương Lâm; nói sẽ ban tiên cơ mới cho người hầu khi về Thiên Vận Tinh rồi vào cửa hàng thứ ba mua vật mừng thọ sư tôn.","bridge":true,"khoang":"@c0446"}],"tuViMoc":[{"chuong":"@c0446","canhGioi":"Anh Biến trung kỳ đỉnh phong","text":"Tu vi Anh Biến trung kỳ đỉnh phong, phóng tiên lực ra ngoài làm dao động không gian.","importance":"minor"},{"chuong":"@c0446","canhGioi":"Anh Biến trung kỳ đỉnh phong","text":"Lần đầu xuất hiện, tu vi Anh Biến trung kỳ đỉnh phong, phóng ra tiên lực làm dao động không gian.","importance":"major"}],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người vừa gặp tại cửa hàng Thương Thị; Bạch Vi tỏ thái độ kỳ dị, mời ghé Thiên Vận Tinh","ghiChu":"@c0446"},{"ten":"Người hầu áo lam (của Bạch Vi)","tag":"khac","quanHe":"Người hầu đi theo Bạch Vi, bị Vương Lâm phế tiên cơ","ghiChu":"@c0446"},{"ten":"Người thanh niên áo lam (người hầu của Bạch Vi)","tag":"cap-tren","quanHe":"Chủ nhân","ghiChu":"Người hầu bị Vương Lâm phế tiên cơ; Bạch Vi gạt ý xin giết Vương Lâm, hứa ban tiên cơ mới."}],"tuiDo":{"phapBao":[{"ten":"Quạt lông trắng","moTa":"Cây quạt lông trắng tăng khí chất công tử","nguon":"@c0446"},{"ten":"Chén trà","loai":"pháp bảo công kích","moTa":"Chén trà ẩn chứa tiên lực khổng lồ, ném tốc độ cực nhanh","nguon":"@c0446"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0446"]},{"id":"truong-hoa-lam","name":"Trương Hóa Lâm","cn":"","aliases":["Lão già mặt đỏ (phường thị tự do)","Lão già mặt đỏ"],"gioiTinh":"nam","theLuc":[{"ten":"Phường thị tự do Minh Hồng thành","trangThai":"danh-nghia"},{"ten":"Phường thị tự do (Minh Hồng thành)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Lão già mặt đỏ buôn bán trong phường thị tự do Minh Hồng thành, bán Khôn Mộc Thạch giúp bạn bè rồi vội rời thành sau khi nhận năm cực phẩm linh thạch.","vaiTro":"Người bán Khôn Mộc Thạch cho Vương Lâm tại phường thị tự do.","tinhCach":[{"text":"Cẩn trọng, sợ mang vạ vì giữ nhiều cực phẩm linh thạch","chuong":"@c0446"}],"tabs":{"diem":[{"text":"Kinh hãi khi thấy Vương Lâm phá vỡ Khốn Phong Chú trong nháy mắt, đoán tu vi ít nhất Anh Biến kỳ","chuong":"@c0446"},{"text":"Chủ cửa hàng bán Khôn Mộc Thạch giúp bạn bè, chào giá cố định năm cực phẩm linh thạch không trả giá","chuong":"@c0446"},{"text":"Kinh hãi khi Vương Lâm phá Khốn Phong Chú dễ dàng, đoán hắn ít nhất Anh Biến kỳ","chuong":"@c0446"}],"kinhLich":[{"text":"Trương Hóa Lâm lấy Khôn Mộc Thạch ra với Khốn Phong Chú phủ ngoài, chào giá cố định năm khối cực phẩm linh thạch. Vương Lâm vung tay phá vỡ Khốn Phong Chú dễ dàng khiến lão kinh hãi. Sau khi nhận đủ năm khối cực phẩm linh thạch, lão sợ ‘mang ngọc mắc tội’ bị tu sĩ Hóa Thần truy sát nên vội thu quầy rời Minh Hồng thành.","bridge":true,"khoang":"@c0446"},{"text":"Bán Khôn Mộc Thạch cho Vương Lâm, chứng kiến hắn phá vỡ Khốn Phong Chú trong nháy mắt; sợ năm cực phẩm linh thạch khiến tu sĩ Hóa Thần truy sát nên vội thu quầy rời Minh Hồng thành.","bridge":true,"khoang":"@c0446"}],"tuViMoc":[],"tuVi":"Chưa rõ tu vi cụ thể.","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Khách mua Khôn Mộc Thạch, trả năm khối cực phẩm linh thạch","ghiChu":"@c0446"},{"ten":"Lý Đan Nam","tag":"khac","quanHe":"Người dẫn khách tới","ghiChu":"Lý Đan Nam dẫn Vương Lâm đến cửa hàng của lão."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Khốn Phong Chú","moTa":"Pháp thuật phòng vệ buôn bán phủ lên Khôn Mộc Thạch, bị Vương Lâm phá vỡ.","nguon":"@c0446"}],"linhThu":[],"nguyenLieu":[{"ten":"Khôn Mộc Thạch","trangThai":"mat","moTa":"Tảng đá xanh hiếm bán dùm bạn bè, đã bán cho Vương Lâm","nguon":"@c0446"}],"linhThao":[],"khac":[]}},"nguon":["@c0446"]},{"id":"nguoi-hau-ao-lam-bach-vi","name":"Người hầu áo lam (của Bạch Vi)","cn":"","aliases":["Thanh niên áo lam","Người hầu áo lam"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Rìa Anh Biến (đang hấp thụ tiên ngọc)","trangThai":"song","blurb":"Người hầu áo lam của Bạch Vi, tu vi gần Anh Biến do hấp thụ tiên ngọc; ngạo nghễ ngăn Vương Lâm vào cửa hàng nên bị một quyền phế tiên cơ, tụt về Hóa Thần kỳ.","vaiTro":"Người hầu của Bạch Vi gây sự với Vương Lâm tại cửa hàng Thương Thị.","tinhCach":[{"text":"Ngạo nghễ, hống hách theo tác phong của chủ nhân Bạch Vi","chuong":"@c0446"}],"tabs":{"diem":[{"text":"Đang dùng phương pháp thứ hai hấp thụ tiên ngọc để tiến lên Anh Biến, tu vi chỉ còn nửa bước vào Anh Biến","chuong":"@c0446"},{"text":"Tu vi nửa bước vào Anh Biến nhờ hấp thụ tiên ngọc theo phương pháp thứ hai","chuong":"@c0446"},{"text":"Bị Vương Lâm một quyền phế tiên cơ, tụt về Hóa Thần kỳ","chuong":"@c0446"}],"kinhLich":[{"text":"Người hầu phóng sóng xanh ngăn cản Vương Lâm vào cửa hàng và quát ‘Cút’. Vương Lâm tiến một bước, một quyền uy lực làm nứt không gian; tuy quyền rơi vào hư không do bị chén trà Bạch Vi cản, người hầu vẫn bị phế tiên cơ, phun máu nâu, tiên khí bạch sắc bay ra thất khiếu, tu vi tụt từ rìa Anh Biến về Hóa Thần kỳ. Hắn xin Bạch Vi giết Vương Lâm nhưng bị gạt.","bridge":true,"khoang":"@c0446"},{"text":"Ngạo nghễ phóng sóng xanh quát Vương Lâm cút khỏi cửa hàng; bị Vương Lâm dùng tốc độ cực nhanh tiến tới một quyền uy lực, tuy quyền rơi vào hư không nhưng tiên cơ bị phế, phun máu nâu, tiên khí bạch sắc bay ra thất khiếu, tu vi tụt từ rìa Anh Biến về Hóa Thần kỳ; xin Bạch Vi giết Vương Lâm nhưng bị gạt.","bridge":true,"khoang":"@c0446"}],"tuViMoc":[{"chuong":"@c0446","canhGioi":"Hóa Thần kỳ","text":"Bị Vương Lâm phế tiên cơ, tu vi tụt từ rìa Anh Biến về Hóa Thần kỳ.","importance":"minor"}],"tuVi":"","nhanMach":[{"ten":"Bạch Vi","tag":"cap-tren","quanHe":"Chủ nhân, hứa cấp lại tiên cơ khi về Thiên Vận Tinh","ghiChu":"@c0446"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người phế tiên cơ của hắn","ghiChu":"@c0446"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Tiên ngọc","moTa":"Dùng hấp thụ theo phương pháp thứ hai để tiến lên Anh Biến.","nguon":"@c0446"}],"linhThao":[],"khac":[]}},"nguon":["@c0446"]},{"id":"nu-tu-ao-trang-thuong-thi","name":"Nữ tử áo trắng (cửa hàng Thương Thị)","cn":"","aliases":["Nữ chủ Thương Thị"],"gioiTinh":"nu","theLuc":[{"ten":"Thương Thị","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Nữ tử xinh đẹp tiếp đãi/chủ cửa hàng Thương Thị, mặc đồ trắng thêu hoa cà độc dược, cài trâm thủy tinh, dưới mắt trái có ba miếng dán tím — đều là pháp bảo hiếm.","vaiTro":"Người tiếp đãi/nữ chủ cửa hàng Thương Thị ở thành bắc Minh Tư thành.","tinhCach":[{"text":"Niềm nở, mời chào khách hàng","chuong":"@c0446"}],"tabs":{"diem":[{"text":"Mặc đồ trắng thêu chín đóa hoa cà độc dược, cài ba trâm thủy tinh tím-trắng, dưới mắt trái dán ba miếng tím mỏng như cánh ve — tất cả đều là pháp bảo hiếm","chuong":"@c0446"}],"kinhLich":[{"text":"Trong cung điện xa hoa của cửa hàng Thương Thị với chín mươi chín bức tượng nữ tử điêu khắc từ linh thạch, nữ tử áo trắng đứng ra hoan nghênh Vương Lâm. Vương Lâm nhận ra các pháp bảo nàng đeo và hỏi thẳng nơi đây có Mặc Tuyết Dịch không.","bridge":true,"khoang":"@c0446"},{"text":"Trong cung điện linh khí nồng đậm với chín mươi chín tượng nữ tử bằng linh thạch, nàng hoan nghênh Vương Lâm vào cửa hàng; Vương Lâm hỏi thẳng có Mặc Tuyết Dịch không.","bridge":true,"khoang":"@c0446"}],"tuViMoc":[],"tuVi":"Chưa rõ tu vi cụ thể.","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Khách hỏi mua Mặc Tuyết Dịch tại cửa hàng Thương Thị","ghiChu":"@c0446"}],"tuiDo":{"phapBao":[{"ten":"Trâm thủy tinh tím-trắng","moTa":"Ba cái trâm cài tóc, là pháp bảo","nguon":"@c0446"},{"ten":"Hoa cà độc dược (thêu váy)","moTa":"Chín đóa hoa cà độc dược thêu trên y phục, là pháp bảo hiếm","nguon":"@c0446"},{"ten":"Miếng dán tím dưới mắt","moTa":"Ba miếng tím mỏng như cánh ve dưới mắt trái, là pháp bảo","nguon":"@c0446"},{"ten":"Hoa cà độc dược (thêu trên váy)","moTa":"Chín đóa hoa cà độc dược trên y phục là pháp bảo hiếm.","nguon":"@c0446"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0446"]},{"id":"bien-duyen-tu-si-dui-mu","name":"Biên duyên tu sĩ đui mù","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Biên duyên tu sĩ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến Sơ Kỳ","trangThai":"song","blurb":"Một biên duyên tu sĩ vô danh hai mắt đui mù cảnh Anh Biến Sơ Kỳ, gặp và giao đấu với Vương Lâm trong tinh không rồi trọng thương bỏ chạy.","vaiTro":"Nhân vật phụ thoáng qua, đại diện cho lớp biên duyên tu sĩ chuyên cướp đoạt rải khắp tinh không.","tinhCach":[{"text":"Hung hãn, liều lĩnh cướp đoạt người gặp phải nhưng biết lượng sức bỏ chạy khi gặp đối thủ mạnh.","chuong":"@c0448"}],"tabs":{"diem":[{"text":"Biên duyên tu sĩ đui mù, dám động thủ với Vương Lâm rồi nhận trọng thương phải bỏ chạy.","chuong":"@c0448"},{"text":"Đui mù nhưng vẫn là biên duyên tu sĩ cảnh Anh Biến Sơ Kỳ, dám gây sự với Vương Lâm.","chuong":"@c0448"}],"kinhLich":[{"text":"Trên đường Vương Lâm tới Thiên Vận Tinh, gã biên duyên tu sĩ đui mù cảnh Anh Biến Sơ Kỳ động thủ với hắn, nhanh chóng bị đánh trọng thương và phải bỏ chạy.","bridge":true,"khoang":"@c0448"},{"text":"Trong hành trình tinh không, biên duyên tu sĩ đui mù này đánh nhau với Vương Lâm rồi bị trọng thương, phải bỏ chạy. Sau đó Vương Lâm phát sát khí bổn tôn khiến các biên duyên tu sĩ khác đều tránh.","bridge":true,"khoang":"@c0448"}],"tuViMoc":[{"chuong":"@c0448","canhGioi":"Anh Biến Sơ Kỳ","text":"Xuất hiện ở cảnh giới Anh Biến Sơ Kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ thoáng qua","ghiChu":"Động thủ với Vương Lâm rồi bị trọng thương bỏ chạy."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0448"]},{"id":"dai-su-huynh-thien-van-tong","name":"Đại sư huynh (Thiên Vận Tông)","cn":"","aliases":["Đại sư huynh"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đệ tử lớn của Thiên Vận Tử, ở Tử Thiên Các; bề ngoài hiền lành tươi cười nhưng ngầm nổi sát ý với Vương Lâm.","vaiTro":"Đại đệ tử của Thiên Vận Tử, ngụ tại Tử Thiên Các; bên ngoài thuận hòa khâm phục nhưng âm thầm can thiệp Tam Quan để hại Vương Lâm.","tinhCach":[{"text":"Vẻ mặt tư��i cười hiền lành, lễ độ bề ngoài","chuong":"@c0449"},{"text":"Thâm hiểm, giấu sát ý dưới lời lẽ thân thiện","chuong":"@c0449"}],"tabs":{"diem":[{"text":"Khâm phục bản lãnh vấn đạo của Vương Lâm nhưng lập tức quyết không cho hắn lưu lại","chuong":"@c0449"},{"text":"Bấm quyết hai tay phóng luồng ánh sáng bảy màu can thiệp cửa khảo nghiệm","chuong":"@c0449"}],"kinhLich":[{"text":"Khi Vương Lâm vấn đạo trụ tám mươi ba ngày trong Nhân Chi Quan, đại sư huynh nhận định người này không thể lưu lại, bèn phóng luồng ánh sáng bảy màu bá đạo can thiệp cửa ải, khiến sơn thôn ảo cảnh tan rã.","bridge":true,"khoang":"@c0449"},{"text":"Đại sư huynh là người bố trí trận pháp tại thạch lâm khốn địa để vây Vương Lâm — màn sáng bạc bao phủ mười dặm, triệt tiêu mọi kiếm quang pháp bảo phóng ra. Bị tứ sư tỷ tuyên bố cắt đứt nhân tình năm xưa khi nàng đưa Vương Lâm tới đây.","bridge":true,"khoang":"@c0459"}],"tuViMoc":[],"tuVi":"Cảnh giới chưa nêu rõ; là đại đệ tử của Thiên Vận Tử.","nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Đứng đầu Thiên Vận Tông"},{"ten":"Chu sư đệ","tag":"su-mon","quanHe":"Sư đệ đồng môn","ghiChu":""},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Ngầm muốn hại","ghiChu":"Can thiệp cửa ải nhập môn của Vương Lâm"},{"ten":"Tôn Vân","tag":"su-mon","quanHe":"Nhắc tới như sư đệ cũ","ghiChu":""},{"ten":"Tứ sư tỷ (Tử hệ)","tag":"doi-thu","quanHe":"Sư muội đồng môn, từng có nhân tình","ghiChu":"Bị tứ sư tỷ tuyên bố nhân tình đã hồi báo, từ nay không còn liên quan."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư đệ đồng môn","ghiChu":"Bố trí trận pháp vây khốn Vương Lâm tại thạch lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0449","@c0459"]},{"id":"chu-su-de-thien-van-tong","name":"Chu sư đệ (Thiên Vận Tông)","cn":"","aliases":["Chu sư đệ"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đệ tử của Thiên Vận Tử, vẻ mặt nghiêm nghị lạnh lùng, ở Tử Mộng Các; chế giễu việc Vương Lâm được sắp xếp vào Tử Vân Các.","vaiTro":"Đệ tử Thiên Vận Tử ngụ tại Tử Mộng Các, bất mãn với việc một ký danh đệ tử tầm thường như Vương Lâm được vào Tử Vân Các.","tinhCach":[{"text":"Lạnh lùng, nghiêm nghị, hay cười lạnh","chuong":"@c0449"},{"text":"Cao ngạo, coi thường ký danh đệ tử","chuong":"@c0449"}],"tabs":{"diem":[{"text":"Cười lạnh chế giễu rằng Tử Vân Các sẽ sớm đổi tên thành Tử Lâm Các","chuong":"@c0449"}],"kinhLich":[{"text":"Khi Thiên Vận Tử dặn dẫn Vương Lâm tới Tử Vân Các, Chu sư đệ cười lạnh cho rằng nơi đó đâu phải chốn ký danh đệ tử tầm thường được ở, rồi hừ một tiếng bỏ đi.","bridge":true,"khoang":"@c0449"}],"tuViMoc":[],"tuVi":"Cảnh giới chưa nêu rõ; là đệ tử chân chính của Thiên Vận Tử.","nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư tôn","ghiChu":""},{"ten":"Đại sư huynh (Thiên Vận Tông)","tag":"su-mon","quanHe":"Sư huynh đồng môn","ghiChu":""},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Coi thường, chế giễu","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0449"]},{"id":"nguoi-gac-cong-thien-van-tinh","name":"Người gác cổng (Thiên Vận Tinh)","cn":"","aliases":["Thanh niên áo choàng lụa đen"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thanh niên áo choàng lụa đen tướng mạo tầm thường nhưng khí tức cuồng ngạo, canh giữ màn sương lối vào Thiên Vận Tinh.","vaiTro":"Người canh cửa nơi màn sương dẫn vào Thiên Vận Tinh; thử thách Vương Lâm rồi mở thông đạo cho qua.","tinhCach":[{"text":"Cuồng ngạo, khí tức ăn sâu vào xương tủy","chuong":"@c0449"}],"tabs":{"diem":[{"text":"Vung tay tạo xúc tu giao long bằng sương thử Vương Lâm rồi ôm quyền cho qua","chuong":"@c0449"}],"kinhLich":[{"text":"Chặn Vương Lâm trước màn sương, hỏi có thông điệp hay lời mời không; nghe nhắc tên Thiên Vận Tử và nguồn Chu Tước Tinh liền thử bằng xúc tu giao long sương. Khi Vương Lâm hóa giải thành trường kiếm xanh bước qua, hắn ôm quyền cho qua và mở thông đạo sương dẫn vào Thiên Vận Tinh.","bridge":true,"khoang":"@c0449"}],"tuViMoc":[],"tuVi":"Cảnh giới chưa rõ, đủ sức tạo xúc tu giao long bằng sương.","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người thử thách rồi cho qua cửa","ghiChu":""},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Người mà hắn canh cổng","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0449"]},{"id":"ton-van-su-de","name":"Tôn Vân","cn":"","aliases":["Tôn Vân sư đệ"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Đệ tử cũ của Thiên Vận Tử từng ở Tử Vân Các; năm xưa cũng chọn vấn đạo và kiên trì sáu mươi bảy ngày.","vaiTro":"Người tiền nhiệm chỗ Tử Vân Các mà Vương Lâm sắp thay thế; nay lòng sư tôn với hắn được nói là không còn chút nào.","tinhCach":[{"text":"Có đại trí tuệ, từng vấn đạo thay vì né tránh","chuong":"@c0449"}],"tabs":{"diem":[{"text":"Năm xưa cũng vấn đạo trong cửa khảo đạo tâm, kiên trì sáu mươi bảy ngày","chuong":"@c0449"}],"kinhLich":[{"text":"Đại sư huynh nhắc rằng cách vấn đạo của Vương Lâm giống hệt Tôn Vân năm đó; lòng sư tôn với Tôn Vân nay không còn chút nào, gợi một biến cố chưa rõ.","bridge":true,"khoang":"@c0449"}],"tuViMoc":[],"tuVi":"Cảnh giới chưa nêu rõ.","nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư tôn cũ","ghiChu":"Lòng sư tôn nay không còn"},{"ten":"Đại sư huynh (Thiên Vận Tông)","tag":"su-mon","quanHe":"Sư huynh đồng môn","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0449"]},{"id":"lao-gia-nhan-chi-quan","name":"Lão già Nhân Chi Quan","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Hộ quan hoặc hóa thân trong Nhân Chi Quan của Thiên Vận Tông, người dẫn dắt khảo nghiệm vấn đạo.","vaiTro":"Hộ quan ải vấn đạo","tinhCach":[{"text":"Điềm đạm, dò xét tâm đạo người nhập quan","chuong":"@c0450"}],"tabs":{"diem":[{"text":"Đứng ra hỏi Vương Lâm có muốn tiếp tục lần thử thứ tám mươi bốn không, biểu trưng cho cốt lõi vấn đạo của Nhân Chi Quan","chuong":"@c0450"}],"kinhLich":[{"text":"Trong Nhân Chi Quan, lão hỏi đồng tử Vương Lâm có tiếp tục lần thử thứ tám mươi bốn không; được đáp đó chính là vấn đạo, ý nghĩa thật sự của ải.","bridge":true,"khoang":"@c0450"}],"tuViMoc":[],"tuVi":"Chưa rõ tu vi; là sinh linh/hóa thân gắn với cơ chế khảo nghiệm Nhân Chi Quan.","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người nhập quan vấn đạo","ghiChu":"Khảo vấn đạo Vương Lâm trong Nhân Chi Quan"}],"tuiDo":{}},"nguon":["@c0450"]},{"id":"de-thap-ho-tien-dia-chi-quan","name":"Đệ thập hộ tiên (Địa Chi Quan)","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Sinh linh hóa từ lửa đỏ trong Địa Chi Quan, khảo nghiệm tu vi của người nhập quan.","vaiTro":"Hộ tiên khảo nghiệm tu vi","tinhCach":[{"text":"Tự tin thách đấu nhưng biết tiến thoái, bại thì lễ độ rút lui","chuong":"@c0450"}],"tabs":{"diem":[{"text":"Hóa từ một ngọn lửa thành thân ảnh đỏ, tự xưng đệ thập hộ tiên, đòi đánh bại mới cho qua ải","chuong":"@c0450"}],"kinhLich":[{"text":"Thách đấu Vương Lâm trong Địa Chi Quan, bị một chiêu Thái Cực quy nguyên đánh lui hơn mười trượng, hai tay rỉ máu, rồi khom người chào và hóa khói lửa chui vào khe nứt.","bridge":true,"khoang":"@c0450"}],"tuViMoc":[],"tuVi":"Tu vi đủ để làm hộ tiên khảo nghiệm, song bị Vương Lâm chế áp một chiêu.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người vượt ải","ghiChu":"Bị Vương Lâm đánh bại trong Địa Chi Quan"}],"tuiDo":{}},"nguon":["@c0450"]},{"id":"trieu-tinh-sat","name":"Triệu Tinh Sát","cn":"","aliases":["Triệu Sát Tinh","Đại sư huynh Tử hệ"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"},{"ten":"Tử Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Đại sư huynh hàng chữ Tử của Thiên Vận Tông, vẻ mặt hiền lành nhưng ẩn giấu tâm cơ; chính là kẻ phát luồng sáng bảy màu Vương Lâm gặp ở Nhân Chi Quan.","vaiTro":"Đại sư huynh Tử hệ đón Vương Lâm nhập môn, dẫn đường giới thiệu Thiên Vận Tông nhưng ẩn giấu sát ý.","tinhCach":[{"text":"Bề ngoài hiền lành ôn hòa nhưng nội tâm thâm trầm, ánh mắt thỉnh thoảng lóe tia kỳ dị","chuong":"@c0451"}],"tabs":{"diem":[{"text":"Đại sư huynh hàng chữ Tử, nhập môn sớm nhất trong hệ của sư tôn","chuong":"@c0451"},{"text":"Là người phát luồng sáng bảy màu mà Vương Lâm gặp tại Nhân Chi Quan","chuong":"@c0451"},{"text":"Tự xưng đại sư huynh, đệ tử nhập môn sớm nhất hàng chữ Tử của sư tôn.","chuong":"@c0451"},{"text":"Là người phát ra luồng sáng bảy màu Vương Lâm gặp ở Nhân Chi Quan.","chuong":"@c0451"}],"kinhLich":[{"text":"Mặc áo tím, vẻ mặt hiền lành, tự xưng đại sư huynh Tử hệ, dẫn Vương Lâm vào sâu Thập Vạn Đại Sơn và giới thiệu tỉ mỉ về Thiên Vận Tông cùng bảy hệ đệ tử. Chỉ đường tới Tử Vân Các rồi viện cớ rời đi, mắt lóe tia kỳ dị, lộ tâm cơ ẩn giấu.","bridge":true,"khoang":"@c0451"},{"text":"Tự xưng Triệu Tinh Sát, đại sư huynh hàng chữ Tử, đón Vương Lâm ở Thập Vạn Đại Sơn, dẫn đường vào sâu giới thiệu tỉ mỉ Thiên Vận Tông cùng bảy hệ đệ tử. Sau đó viện cớ có chuyện quan trọng rời đi, vẻ mặt hiền lành nhưng mắt lóe tia kỳ dị.","bridge":true,"khoang":"@c0451"}],"tuViMoc":[],"tuVi":"Tu vi chưa nêu rõ; là đệ tử trọng yếu hàng chữ Tử của Thiên Vận Tông.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư đệ trên danh nghĩa","ghiChu":"Đón nhập tông nhưng ẩn giấu sát ý; Vương Lâm đã nhận ra hắn là kẻ ở Nhân Chi Quan."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Đệ tử nhập môn sớm nhất hàng chữ Tử."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0451"]},{"id":"nu-tu-ao-tim-tu-van-cac","name":"Nữ tử áo tím canh Tử Vân Các","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Tử Tông","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến Sơ Kỳ","trangThai":"song","blurb":"Đệ tử Tử Tông tu vi Anh Biến Sơ Kỳ, mặc đồ tím điểm hoa vàng, khuôn mặt xinh đẹp đầy sát khí, kiên quyết canh giữ Tử Vân Các cho Tôn Vân sư huynh.","vaiTro":"Người canh gác cấm tiếp cận Tử Vân Các khi Vương Lâm vừa nhập tông.","tinhCach":[{"text":"Cứng cỏi, trung thành tới mức cố chấp với Tôn Vân sư huynh","chuong":"@c0451"}],"tabs":{"diem":[{"text":"Trung thành tuyệt đối với Tôn Vân, thề không cho ai thay thế vị trí của hắn ở Tử Vân Các","chuong":"@c0451"}],"kinhLich":[{"text":"Đối đầu sát khí với Vương Lâm, cấm hắn ở lại và cấm vào trong vòng trăm dặm quanh Tử Vân Các. Sau khi Vương Lâm rời đi mới phát hiện lưng đã ướt mồ hôi vì sợ hãi, độc thoại thề giữ vị trí cho Tôn Vân sư huynh.","bridge":true,"khoang":"@c0451"}],"tuViMoc":[{"chuong":"@c0451","canhGioi":"Anh Biến Sơ Kỳ","text":"Tu vi Anh Biến Sơ Kỳ, không đủ để Vương Lâm để mắt.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người bị nàng ngăn cấm tiếp cận Tử Vân Các","ghiChu":""},{"ten":"Tôn Vân","tag":"dong-minh","quanHe":"Sư huynh nàng trung thành giữ vị trí","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0451"]},{"id":"hai-chap-phap-truong-lao-tu-tong","name":"Hai chấp pháp trưởng lão Tử Tông","cn":"","aliases":["Chấp pháp trưởng lão Tử Tông","Lão béo và lão gầy"],"gioiTinh":"nam","theLuc":[{"ten":"Tử Tông","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Anh Biến Sơ Kỳ","trangThai":"khong-ro","blurb":"Hai lão già áo bào tím nhạt (một béo một gầy), chấp pháp trưởng lão Tử Tông, tới ép Vương Lâm phá động phủ và định tội; một bị diệt nguyên thần đem luyện, một bị khống chế.","vaiTro":"Phản diện thoáng qua — đại diện chấp pháp Tử Tông tới gây sự với Vương Lâm theo lời xúi của Triệu Tinh Sát.","tinhCach":[{"text":"Hống hách, cậy thế môn quy ép người.","chuong":"@c0452"},{"text":"Khi gặp đối thủ mạnh thì kinh hãi, run sợ bỏ chạy.","chuong":"@c0452"}],"tabs":{"diem":[{"text":"Bản lãnh Anh Biến Sơ Kỳ, mặc áo bào tím nhạt, một béo một gầy.","chuong":"@c0452"},{"text":"Tự xưng chấp pháp trưởng lão Tử Tông, viện môn quy ép Vương Lâm.","chuong":"@c0452"}],"kinhLich":[{"text":"Ngày thứ mười bảy, hai lão tới quát Vương Lâm vì tự ý mở động phủ chưa được phép, hạn một nén nhang phá động phủ rồi ép theo về đại điện định tội.","bridge":true,"khoang":"@c0452"},{"text":"Lão thứ nhất bị Côn Cực Tiên đánh bật nguyên thần, bị Vương Lâm ném vào chuông luyện hóa; lão còn lại dùng chiêu Thất Tinh Toái nhưng bị tiên kiếm và loan đao đánh tan, kinh hãi bỏ chạy rồi bị khống chế cách mười trượng và tra hỏi.","bridge":true,"khoang":"@c0452"}],"tuViMoc":[{"chuong":"@c0452","canhGioi":"Anh Biến Sơ Kỳ","text":"Cả hai lão đều ở cảnh giới Anh Biến Sơ Kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Tới ép Vương Lâm rồi bị hắn diệt nguyên thần và khống chế."},{"ten":"Triệu Tinh Sát","tag":"dong-minh","quanHe":"Kẻ xúi giục","ghiChu":"Nghe lời Triệu Tinh Sát tới gây sự, sau hối hận."}],"tuiDo":{"phapBao":[{"ten":"Trường kiếm màu tím","loai":"phi-kiem","moTa":"Vũ khí của lão gầy, dùng cho chiêu Thất Tinh Toái, vỡ thành bảy mảnh rồi bị loan đao đánh tan.","nguon":"@c0452"}],"congPhap":[{"ten":"Thất Tinh Toái","moTa":"Chiêu kiếm khiến trường kiếm vỡ thành bảy mảnh lao về phía địch.","nguon":"@c0452"}]}},"nguon":["@c0452"]},{"id":"nu-tu-bi-an-tu-van-cac","name":"Nữ tử bí ẩn (Tử Vân Các)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Tử Tông","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Nữ tử mỗi sáng đến ngơ ngác nhìn Tử Vân Các suốt nửa tháng không gián đoạn, gắn với bí ẩn của tòa lầu và chủ cũ.","vaiTro":"Nhân vật bí ẩn gắn với bí mật trung tâm của Tử Vân Các.","tinhCach":[{"text":"Lặng lẽ, đều đặn, dường như mang nỗi niềm với chủ cũ Tử Vân Các.","chuong":"@c0452"}],"tabs":{"diem":[{"text":"Mỗi sáng đến ngơ ngác nhìn Tử Vân Các, ngày nào cũng vậy suốt nửa tháng.","chuong":"@c0452"},{"text":"Mỗi sáng đều đến nhìn Tử Vân Các, đều đặn không gián đoạn suốt nửa tháng.","chuong":"@c0452"}],"kinhLich":[{"text":"Trong nửa tháng Vương Lâm bị cô lập, chỉ có nữ tử này mỗi sáng đến nhìn Tử Vân Các không gián đoạn, gợi mối liên hệ tình cảm/quá khứ với chủ cũ của tòa lầu.","bridge":true,"khoang":"@c0452"},{"text":"Trong nửa tháng Vương Lâm bị cô lập ở Tử Tông, mỗi sáng nữ tử đều đến đứng ngơ ngác nhìn về phía Tử Vân Các rồi rời đi, lặp lại không đổi, gợi mối liên hệ tình cảm hoặc quá khứ với chủ cũ tòa lầu.","bridge":true,"khoang":"@c0452"}],"tuViMoc":[],"tuVi":"Chưa rõ tu vi.","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Cùng khu Tử Tông trong thời gian Vương Lâm bị cô lập","ghiChu":"Vương Lâm để ý thấy nữ tử mỗi sáng đến nhìn Tử Vân Các."}],"tuiDo":{}},"nguon":["@c0452"]},{"id":"nhi-su-huynh-tu-tong","name":"Nhị sư huynh (Tử tông)","cn":"","aliases":["Nam tử trung niên (Tử tông)","Nhị sư huynh","Nam tử trung niên"],"gioiTinh":"nam","theLuc":[{"ten":"Tử Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến trung kỳ","trangThai":"tu-vong","blurb":"Nhị sư huynh Tử tông, tướng mạo bình thường nhưng lửa giận ngập trời, tự nhận thay sư tôn thanh lý môn hộ; bị Vương Lâm phá hết cấm thuật rồi đánh nguyên thần bay ra.","vaiTro":"Đối thủ một trận của Vương Lâm tại Tử Lâm Các, đại diện phe phản đối Vương Lâm trong nội bộ Tử tông.","tinhCach":[{"text":"Nóng nảy, đầy thù hận, tự cho mình chính nghĩa khi đòi thanh lý môn hộ.","chuong":"@c0454"},{"text":"Tự phụ về thực lực, cho đối thủ ra ba pháp thuật trước nhưng vẫn bại.","chuong":"@c0454"}],"tabs":{"diem":[{"text":"Gọi Vương Lâm là dân bản xứ một tinh cầu, khinh thường nhưng bị nghiền nát.","chuong":"@c0454"},{"text":"Thành thạo cấm thuật Quy khư, Tiên Ma thể và Thập phương bát la trận.","chuong":"@c0454"},{"text":"Tự nhận thay sư tôn thanh lý môn hộ, quyết giết Vương Lâm trả thù cho ngũ sư muội.","chuong":"@c0454"},{"text":"Thi triển liên tiếp cấm thuật Quy khư, Thập phương bát la trận và Tiên Ma thể nhưng đều bị phá.","chuong":"@c0454"}],"kinhLich":[{"text":"Xuất hiện cùng ba người Tử tông, đòi thay sư tôn thanh lý môn hộ vì Vương Lâm giết ngũ sư muội. Hắn cho Vương Lâm ra trước ba pháp thuật, lần lượt thi triển cấm thuật Quy khư, Thập phương bát la trận và Tiên Ma thể nhưng đều bị Côn Cực Tiên, tiên kiếm, loan đao và Hóa Ma chỉ phá tan; cuối cùng bị quất một roi vào ngực, nguyên thần bay ra ngoài rồi bị Tôn Hồn Phiên truy sát.","bridge":true,"khoang":"@c0454"},{"text":"Sau khi Triệu Tinh Sát buông tay, nam tử trung niên đến cách mười trượng cho Vương Lâm ra ba pháp thuật trước, tố hắn giết ngũ sư muội.","bridge":true,"khoang":"@c0454"},{"text":"Lần lượt thi cấm thuật Quy khư, Thập phương bát la trận, Tiên Ma thể đều bị Vương Lâm phá; cuối cùng bị quất roi đánh nguyên thần bay ra, bị Tôn Hồn Phiên xua chủ hồn đuổi theo.","bridge":true,"khoang":"@c0454"}],"tuViMoc":[{"chuong":"@c0454","canhGioi":"Anh Biến trung kỳ","text":"Tu vi Anh Biến trung kỳ, ngang Triệu Tinh Sát và Bạch Vi nhưng kém Vương Lâm về thủ đoạn.","importance":"normal"},{"chuong":"@c0454","canhGioi":"Anh Biến trung kỳ","text":"Tu vi Anh Biến trung kỳ, bị Vương Lâm (Anh Biến sơ kỳ) áp chế và giết chết.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đồng môn Tử tông trở thành tử địch","ghiChu":"Khiêu chiến Vương Lâm để báo thù cho ngũ sư muội, bị đánh bại và truy sát nguyên thần."},{"ten":"Triệu Tinh Sát","tag":"su-mon","quanHe":"Đại sư huynh đồng môn","ghiChu":"Bị Triệu Tinh Sát ngăn lại lúc đầu, sau được buông tay cho khiêu chiến."},{"ten":"Bạch Vi","tag":"su-mon","quanHe":"Đồng môn Tử tông","ghiChu":"Bị Bạch Vi cảnh báo về môn quy cấm dùng cấm thuật; ghi hận vì bị động húy kị."},{"ten":"Nữ tử áo lụa trắng (Tử Tâm)","tag":"su-mon","quanHe":"Ngũ sư muội bị tử y nữ tử thay; hắn tố Vương Lâm giết ngũ sư muội.","ghiChu":"(tự sinh — R4 rà)"}],"tuiDo":{"phapBao":[{"ten":"Trường kiếm lớn","loai":"kiem","moTa":"Trường kiếm dùng thi triển Thập phương bát la trận, một hóa hai, hai hóa bốn trút xuống vô số kiếm.","nguon":"@c0454"}],"danDuoc":[],"congPhap":[{"ten":"Quy khư","moTa":"Cấm thuật thần thông, kim quang vàng từ mi tâm bao phủ toàn thân hóa thành ngón tay vàng phản kích.","nguon":"@c0454"},{"ten":"Tiên Ma thể","moTa":"Cấm thuật khiến hắc vụ chui vào thất khiếu, thân thể bất hoại, hóa thành hắc vụ di chuyển.","nguon":"@c0454"},{"ten":"Thập phương bát la trận","moTa":"Trận kiếm thuật, ném trường kiếm lên một hóa hai hóa bốn, vô số kiếm trút xuống.","nguon":"@c0454"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0454"]},{"id":"nu-tu-anh-bien-hau-ky-tu-tong","name":"Nữ tử xinh đẹp (Tử tông)","cn":"","aliases":["Nữ tử xinh đẹp Tử tông"],"gioiTinh":"nu","theLuc":[{"ten":"Tử Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến hậu kỳ","trangThai":"song","blurb":"Nữ tử xinh đẹp Tử tông, đứng đâu hương thơm tràn đó, tu vi Anh Biến hậu kỳ mạnh nhất trong bốn người, sắc mặt cổ quái như muốn xem trò vui.","vaiTro":"Một trong bốn người Tử tông xuất hiện đối mặt Vương Lâm, tu vi mạnh nhất nhóm nhưng chưa ra tay.","tinhCach":[{"text":"Lạnh lùng quan sát, thái độ như muốn xem trò vui hơn là can thiệp.","chuong":"@c0454"}],"tabs":{"diem":[{"text":"Tu vi Anh Biến hậu kỳ, mạnh nhất trong bốn người Tử tông khiến Vương Lâm để ý.","chuong":"@c0454"},{"text":"Đi đến đâu hương thơm tràn ra đến đó.","chuong":"@c0454"},{"text":"Tu vi Anh Biến hậu kỳ — mạnh nhất trong bốn người Tử tông, khiến Vương Lâm để ý.","chuong":"@c0454"},{"text":"E ngại thú hồn nên lui hơn trăm trượng khi Vương Lâm giải phong Xạ Thần Xa.","chuong":"@c0454"}],"kinhLich":[{"text":"Hiện thân cùng Triệu Tinh Sát, Bạch Vi và nhị sư huynh, đứng quan sát Vương Lâm với sắc mặt cổ quái muốn xem trò vui. Khi thú hồn của Xạ Thần Xa giải phong gầm thét, nàng biến sắc lui xa hơn trăm trượng nhưng vẫn chưa ra tay.","bridge":true,"khoang":"@c0454"},{"text":"Hiện ra cùng Triệu Tinh Sát, Bạch Vi, nam tử trung niên; đứng đâu hương thơm tràn đó, sắc mặt cổ quái muốn xem trò vui; lui xa khi thú hồn xuất hiện.","bridge":true,"khoang":"@c0454"}],"tuViMoc":[{"chuong":"@c0454","canhGioi":"Anh Biến hậu kỳ","text":"Tu vi Anh Biến hậu kỳ, mạnh nhất trong bốn người Tử tông, khiến Vương Lâm phải để tâm.","importance":"normal"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đồng môn Tử tông đối mặt","ghiChu":"Quan sát Vương Lâm với thái độ xem trò vui, lui xa khi thú hồn xuất hiện."},{"ten":"Triệu Tinh Sát","tag":"su-mon","quanHe":"Đồng môn Tử tông","ghiChu":"Cùng nhóm bốn người Tử tông xuất hiện."},{"ten":"Bạch Vi","tag":"su-mon","quanHe":"Đồng môn Tử tông, cùng nhóm bốn người.","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0454"]},{"id":"ngu-su-muoi-tu-y-nu-tu","name":"Ngũ sư muội (Tử y nữ tử)","cn":"","aliases":["Tử y nữ tử"],"gioiTinh":"nu","theLuc":[{"ten":"Tử Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến","trangThai":"tu-vong","blurb":"Ngũ sư muội Tử tông, nữ tử mặc tử y mắt đỏ sát khí; bị Vương Lâm dùng Tịch Diệt Chỉ giam nguyên thần vào Tôn Hồn Phiên.","vaiTro":"Đối thủ Anh Biến bị Vương Lâm dứt điểm mở màn xung đột với Tử tông.","tinhCach":[{"text":"Hung hãn, mắt đỏ đầy sát khí khi giao chiến.","chuong":"@c0454"}],"tabs":{"diem":[{"text":"Thả hỏa phượng từ túi trữ vật và dùng hai phân thân để chống Tịch Diệt Chỉ.","chuong":"@c0454"}],"kinhLich":[{"text":"Tấn công Vương Lâm bằng hỏa phượng đổ lửa như dung nham, nhưng bị tiên kiếm chém tan. Khi Vương Lâm thi Tịch Diệt Chỉ khóa không gian, nàng thoát hai phân thân để cản — một bị hấp thu làm tăng uy lực ngón chỉ, một tự bạo nới lỏng không gian — nhưng cuối cùng vẫn bị điểm mi tâm, nguyên thần bị giam vào Tôn Hồn Phiên. Được nhị sư huynh gọi là ngũ sư muội.","bridge":true,"khoang":"@c0454"}],"tuViMoc":[{"chuong":"@c0454","canhGioi":"Anh Biến","text":"Tu vi Anh Biến, biết phân thân và tự bạo phân thân.","importance":"normal"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đồng môn Tử tông bị giết","ghiChu":"Bị Vương Lâm dùng Tịch Diệt Chỉ giam nguyên thần."},{"ten":"Nhị sư huynh (Tử tông)","tag":"su-mon","quanHe":"Sư huynh đồng môn","ghiChu":"Được nhị sư huynh gọi là ngũ sư muội; cái chết của nàng là cớ để nhị sư huynh khiêu chiến."}],"tuiDo":{"phapBao":[{"ten":"Hỏa phượng","loai":"phap-bao","moTa":"Hồng quang từ túi trữ vật hóa thành hỏa phượng, đổ lửa đỏ như dung nham.","nguon":"@c0454"}],"danDuoc":[],"congPhap":[{"ten":"Phân thân tự bạo","moTa":"Thoát phân thân chống Tịch Diệt Chỉ, một bị hấp thu một tự bạo nới lỏng không gian.","nguon":"@c0454"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0454"]},{"id":"truong-huong-pham","name":"Trương Hướng Phàm","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Hóa Thần đại viên mãn","trangThai":"song","blurb":"Đệ tử trông coi Phẩm Linh Các của Tử Tông, tu vi Hóa Thần đại viên mãn ẩn giấu, sở hữu phi kiếm xanh biếc mang một tia kiếm ý của Chu Dật.","vaiTro":"Đệ tử Thiên Vận Tông phụ trách Phẩm Linh Các, nơi cấp phát đan dược, linh thạch và tiên ngọc cho đệ tử.","tinhCach":[{"text":"Tiên phong đạo cốt, điềm tĩnh, ẩn giấu tu vi sâu kín","chuong":"@c0457"},{"text":"Trọng kiếm đạo, khao khát công pháp công kích mạnh để bước lên Hóa Thần hậu kỳ","chuong":"@c0457"}],"tabs":{"diem":[{"text":"Tu vi Hóa Thần đại viên mãn nhưng giấu kín, chỉ người cao hơn mới nhận ra","chuong":"@c0457"},{"text":"Trên thân ẩn một luồng kiếm ý sâu, thực ra phát ra từ chính phi kiếm của hắn","chuong":"@c0457"}],"kinhLich":[{"chuong":"@c0457","importance":"normal","tieuDe":"Ra mắt thất sư tổ Vương Lâm","text":"Đang ngồi khoanh chân ngoài Phẩm Linh Các, Trương Hướng Phàm thấy Vương Lâm liền đứng dậy ôm quyền xưng đệ tử ra mắt thất tổ sư, thu phi kiếm xanh hóa lục quang nhập thân. Hắn cho Vương Lâm mượn phi kiếm, được Vương Lâm lấy đi một tia kiếm ý cố nhân nhưng đền bù ngọc giản mười tám cấm chế công kích chồng tầng — vật cực hiếm khiến hắn chấn động, hận không thể bế quan khắc lên kiếm ngay. Sau đó hắn chuẩn bị mở truyền tống trận để giao tiên ngọc cho Vương Lâm."},{"text":"Trương Hướng Phàm ấn lệnh bài vào chỗ ba đạo bạch ngân giao nhau, kích hoạt trận pháp tạo cánh cửa truyền tống tại tầng thứ bảy Phẩm Linh Các, rồi cung kính mời Thất sư tổ Vương Lâm cầm lệnh bài tiến vào.","bridge":true,"khoang":"@c0458"}],"tuViMoc":[{"chuong":"@c0457","canhGioi":"Hóa Thần đại viên mãn","text":"Tu vi Hóa Thần đại viên mãn được ẩn giấu hoàn toàn; trên thân mang kiếm ý ẩn sâu.","importance":"major"}],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Thất sư tổ (thất tử của Thiên Vận Tông)","ghiChu":"Ra mắt và cho Vương Lâm mượn phi kiếm, được tặng ngọc giản mười tám cấm chế."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Cung kính dẫn Thất sư tổ Vương Lâm vào Phẩm Linh Các lấy tiên ngọc","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[{"ten":"Phi kiếm xanh biếc","loai":"phi kiếm","trangThai":"dang-co","moTa":"Trường kiếm bảy thước thân xanh biếc tỏa u quang, bị nói là vật tầm thường nhưng ẩn một tia kiếm ý của Chu Dật.","nguon":"@c0457"},{"ten":"Ngọc giản mười tám cấm chế","loai":"ngọc giản","trangThai":"dang-co","moTa":"Vật Vương Lâm tặng để đền tia kiếm ý, khắc mười tám cấm chế công kích chồng tầng lên thượng phẩm phi kiếm sẽ tăng uy lực gấp mấy lần.","nguon":"@c0457"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0457","@c0458"]},{"id":"phu-than-chu-nhu","name":"Phụ thân Chu Như","cn":"","aliases":["Lão nhân bệnh liệt giường"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Cha ruột Chu Như, phàm nhân nơi ngôi làng ngoài Phượng Hoàng thành; bệnh liệt giường vì nhớ con, được Vương Lâm chữa lành rồi đoàn tụ con gái.","vaiTro":"Cha ruột của Chu Như, sống đời phàm nhân trong làng.","tinhCach":[{"text":"Nặng tình thương con, canh cánh nhớ con gái tới mức sinh bệnh liệt giường.","chuong":"@c0441"}],"tabs":{"diem":[{"text":"Hai mươi năm canh cánh chuyện để đạo nhân dẫn con gái đi, vì nhớ con mà bệnh liệt giường.","chuong":"@c0441"}],"kinhLich":[{"chuong":"@c0441","importance":"normal","tieuDe":"Đoàn tụ con gái sau hai mươi năm","text":"Sau hai mươi năm xa cách, mơ thấy con gái trở về rồi quả thật Chu Như về thăm; vợ chồng vỡ òa nhận con. Vương Lâm âm thầm phóng linh lực chữa lành bệnh tật, phục hồi sức sống cho ông."}],"tuViMoc":[{"chuong":"@c0441","canhGioi":"Phàm nhân","text":"Là người phàm sống đời thường trong làng, không tu hành.","importance":"minor"}],"tuVi":"","nhanMach":[{"ten":"Chu Như","tag":"cha-me","quanHe":"Con gái ruột","ghiChu":"Bị đạo nhân dẫn đi từ nhỏ, hai mươi năm sau mới đoàn tụ."},{"ten":"Mẫu thân Chu Như","tag":"the-thiep","quanHe":"Vợ","ghiChu":"Cùng nhau gánh vác gia đình suốt nhiều năm."},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân chữa lành","ghiChu":"Người nuôi dưỡng con gái mình, âm thầm phóng linh lực chữa khỏi bệnh."}],"tuiDo":{}},"nguon":["@c0441"]},{"id":"mau-than-chu-nhu","name":"Mẫu thân Chu Như","cn":"","aliases":["Bà lão"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Mẹ ruột Chu Như, phàm nhân gánh vác cả gia đình nhiều năm; đêm khóc gọi nhũ danh con, đoàn tụ con gái và được chữa lành.","vaiTro":"Mẹ ruột Chu Như, trụ cột gia đình khi chồng bệnh.","tinhCach":[{"text":"Tảo tần gánh vác cả nhà, đêm đêm thầm khóc nhớ con gái.","chuong":"@c0441"}],"tabs":{"diem":[{"text":"Một mình gánh vác gia đình khi chồng liệt giường, đêm khóc gọi nhũ danh con.","chuong":"@c0441"}],"kinhLich":[{"chuong":"@c0441","importance":"normal","tieuDe":"Đoàn tụ con gái sau hai mươi năm","text":"Buổi bình minh mùa xuân đang thổi lửa nấu cơm thì con gái Chu Như trở về quỳ khóc gọi mẫu thân; bà vỡ òa nhận con, sau được Vương Lâm âm thầm phục hồi sức sống."}],"tuViMoc":[{"chuong":"@c0441","canhGioi":"Phàm nhân","text":"Là người phàm sống đời thường trong làng, không tu hành.","importance":"minor"}],"tuVi":"","nhanMach":[{"ten":"Chu Như","tag":"cha-me","quanHe":"Con gái ruột","ghiChu":"Đêm đêm khóc gọi nhũ danh con suốt nhiều năm."},{"ten":"Phụ thân Chu Như","tag":"the-thiep","quanHe":"Chồng","ghiChu":"Cùng nhau gánh vác gia đình suốt nhiều năm."},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân chữa lành","ghiChu":"Âm thầm phóng linh lực chữa khỏi bệnh, phục hồi sức sống."}],"tuiDo":{}},"nguon":["@c0441"]},{"id":"dai-su-huynh-thien-van-tu","name":"Đại sư huynh (Thiên Vận Tử)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Đệ tử lớn nhất của Thiên Vận Tử, ở Tử Thiên Các; bề ngoài hiền lành tươi cười nhưng giấu sát ý, ngầm phá ải hại Vương Lâm ngay từ khi nhập môn.","vaiTro":"Đại đệ tử của Thiên Vận Tử tại Thiên Vận Tông, ở Tử Thiên Các — nơi chỉ đệ tử chân chính được ở.","tinhCach":[{"text":"Bề ngoài hiền lành tươi cười, lễ độ với sư đệ.","chuong":"@c0449"},{"text":"Giấu sát ý sâu, ra tay ngầm hại người mới để bảo vệ vị thế.","chuong":"@c0449"}],"tabs":{"diem":[{"text":"Khâm phục trí tuệ của Vương Lâm khi hắn chọn vấn đạo, nhưng lập tức quyết không để hắn lưu lại.","chuong":"@c0449"},{"text":"Dùng luồng ánh sáng bảy màu can thiệp Nhân Chi Quan để phá ải hại Vương Lâm.","chuong":"@c0449"}],"kinhLich":[{"chuong":"@c0449","importance":"normal","tieuDe":"Phá ải hại Vương Lâm","text":"Khi Vương Lâm vấn đạo cửa thứ nhất và trụ tám mươi ba ngày vượt kỷ lục của Tôn Vân, đại sư huynh nhận định người này không thể lưu lại, bèn bấm quyết hai tay phóng ra luồng ánh sáng bảy màu can thiệp Nhân Chi Quan, khiến sơn thôn ảo cảnh tan rã."}],"tuViMoc":[],"tuVi":"Cảnh giới chưa rõ; là đại đệ tử của Thiên Vận Tử.","nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Là đại đệ tử của Thiên Vận Tử."},{"ten":"Chu sư đệ (Thiên Vận Tông)","tag":"su-mon","quanHe":"Sư đệ","ghiChu":"Cùng môn, khuyên Chu sư đệ đừng nghĩ một đằng nói một nẻo."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tiểu sư đệ tương lai bị hắn ngầm hại","ghiChu":"Phóng ánh sáng bảy màu phá ải hại Vương Lâm."},{"ten":"Tôn Vân","tag":"su-mon","quanHe":"Sư đệ cũ","ghiChu":"Nhắc tới Tôn Vân từng vấn đạo kiên trì 67 ngày."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Ánh sáng bảy màu","moTa":"Bấm quyết hai tay phóng ra luồng sáng bảy màu bá đạo, can thiệp phá hủy cửa ải.","nguon":"@c0449"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0449"]},{"id":"chu-su-de-thien-van-tu","name":"Chu sư đệ (Thiên Vận Tử)","cn":"","aliases":["Chu sư đệ (Thiên Vận Tông)"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Đệ tử của Thiên Vận Tử, vẻ mặt nghiêm nghị lạnh lùng, ở Tử Mộng Các; cười lạnh chế giễu việc Vương Lâm được vào Tử Vân Các.","vaiTro":"Đệ tử của Thiên Vận Tử tại Thiên Vận Tông, ở Tử Mộng Các.","tinhCach":[{"text":"Lạnh lùng, nghiêm nghị, hay cười lạnh.","chuong":"@c0449"},{"text":"Khinh thường người mới, chế giễu chua cay.","chuong":"@c0449"}],"tabs":{"diem":[{"text":"Cho rằng Tử Vân Các không phải nơi ký danh đệ tử tầm thường được ở, chế giễu sẽ đổi tên thành Tử Lâm Các.","chuong":"@c0449"}],"kinhLich":[{"text":"Khi Thiên Vận Tử dặn dẫn Vương Lâm tới Tử Vân Các, Chu sư đệ cười lạnh phản đối, cho rằng Tử Hệ Các đâu phải nơi ký danh đệ tử tầm thường được ở, rồi hừ lạnh bỏ đi.","bridge":true,"khoang":"@c0449"}],"tuViMoc":[],"tuVi":"Cảnh giới chưa rõ; là đệ tử của Thiên Vận Tử.","nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Là đệ tử của Thiên Vận Tử."},{"ten":"Đại sư huynh (Thiên Vận Tử)","tag":"su-mon","quanHe":"Sư huynh","ghiChu":"Bị đại sư huynh khuyên đừng nghĩ một đằng nói một nẻo."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Khinh thường người mới","ghiChu":"Chế giễu việc Vương Lâm được vào Tử Vân Các."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0449"]},{"id":"nu-tu-ao-tim-canh-tu-van-cac-q05","name":"Nữ tử áo tím canh Tử Vân Các","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Tử Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến Sơ Kỳ","trangThai":"song","blurb":"Đệ tử Tử Tông tu vi Anh Biến Sơ Kỳ, mặc đồ tím điểm hoa vàng, khuôn mặt xinh đẹp đầy sát khí. Trung thành với Tôn Vân, quyết cấm Vương Lâm tiếp cận Tử Vân Các.","vaiTro":"Người canh giữ Tử Vân Các, cấm Vương Lâm tới gần.","tinhCach":[{"text":"Quyết liệt, đầy sát khí nhưng thực ra sợ hãi khi đối mặt cao thủ; trung thành tuyệt đối với Tôn Vân.","chuong":"@c0451"}],"tabs":{"diem":[{"text":"Trung thành với Tôn Vân sư huynh, thề không cho ai thay th�� vị trí của hắn ở Tử Vân Các.","chuong":"@c0451"}],"kinhLich":[{"text":"Ngăn Vương Lâm không cho ở Tử Vân Các, còn cấm vào trong vòng trăm dặm. Bị Vương Lâm hiện sát khí nhìn chằm chằm, sau khi hắn rời mới phát hiện lưng đã ướt mồ hôi vì sợ hãi; độc thoại thề giữ vị trí cho Tôn Vân.","bridge":true,"khoang":"@c0451"}],"tuViMoc":[{"chuong":"@c0451","canhGioi":"Anh Biến Sơ Kỳ","text":"Tu vi Anh Biến Sơ Kỳ, Vương Lâm không để mắt tới.","importance":"minor"}],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người bị nàng cấm tiếp cận Tử Vân Các","ghiChu":"Đối đầu sát khí, nàng sợ tới ướt mồ hôi."},{"ten":"Tôn Vân","tag":"su-mon","quanHe":"Sư huynh nàng trung thành","ghiChu":"Thề giữ vị trí cho hắn ở Tử Vân Các."}],"tuiDo":{}},"nguon":["@c0451"]},{"id":"ton-van-tu-van-cac-q05","name":"Tôn Vân","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tử Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Sư huynh hàng chữ Tử mà nữ tử canh Tử Vân Các một lòng trung thành; gắn với bí ẩn về Tử Vân Các.","vaiTro":"Nhân vật được nhắc tên, liên quan tới bí ẩn Tử Vân Các.","tinhCach":[],"tabs":{"diem":[{"text":"Được nữ tử canh Tử Vân Các thề giữ vị trí, không cho ai thay thế.","chuong":"@c0451"}],"kinhLich":[{"text":"Nữ tử áo tím canh Tử Vân Các độc thoại với Tôn Vân sư huynh, thề chỉ cần nàng còn ở đây sẽ không cho ai thay thế vị trí của hắn, gợi mối quan hệ và biến cố cũ chưa rõ.","bridge":true,"khoang":"@c0451"}],"tuViMoc":[],"tuVi":"Chưa rõ tu vi.","nhanMach":[{"ten":"Nữ tử áo tím canh Tử Vân Các","tag":"su-mon","quanHe":"Sư muội trung thành","ghiChu":"Thề giữ vị trí Tử Vân Các cho hắn."}],"tuiDo":{}},"nguon":["@c0451"]},{"id":"ton-van-thien-van-that-tu","name":"Tôn Vân","cn":"","aliases":["Lão lục Tử hệ"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"da-roi"},{"ten":"Tử hệ","trangThai":"da-roi"}],"canhGioiCaoNhat":"không-ro","trangThai":"mat-tich","blurb":"Kỳ tài Tử hệ ngàn năm trước, vươn lên thay lão lục trở thành một trong Thiên Vận Thất tử, ở tại Tử Vân Các; trăm năm trước bỗng trốn khỏi sư môn.","vaiTro":"Nhân vật được nhắc qua lời kể, gắn liền bí mật Tử Vân Các và lời sấm về người kế nhiệm.","tinhCach":[{"text":"Tư chất kiệt xuất, dám rời bỏ sư môn theo lựa chọn riêng.","chuong":"@c0453"}],"tabs":{"diem":[{"text":"Kỳ tài hiếm có của Tử hệ, vươn lên thay lão lục thành Thiên Vận Thất tử.","chuong":"@c0453"},{"text":"Trăm năm trước đột nhiên trốn khỏi sư môn, lý do chưa rõ.","chuong":"@c0453"}],"kinhLich":[{"chuong":"@c0453","importance":"normal","tieuDe":"Trở thành Thiên Vận Thất tử","text":"Ngàn năm trước, Tôn Vân là kỳ tài Tử hệ, vươn lên thay thế lão lục để trở thành một trong Thiên Vận Thất tử, được ban cho ở tại Tử Vân Các."},{"chuong":"@c0453","importance":"normal","tieuDe":"Trốn khỏi sư môn","text":"Trăm năm trước Tôn Vân bỗng nhiên trốn khỏi sư môn; thủy tổ không phái người đuổi giết mà tự đi tìm một lần, sau một tháng trở về hạ lệnh phong ấn Tử Vân Các."}],"tuViMoc":[],"tuVi":"Chưa rõ cảnh giới cụ thể; là đệ tử chân chính đứng đầu Tử hệ.","nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ (thủy tổ tôn giả), tự đi tìm khi Tôn Vân bỏ trốn","ghiChu":"Để lại lời sấm về người kế nhiệm Tử Vân Các"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0453"]},{"id":"vuong-lam","name":"Vuong Lam","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c0391","tieuDe":"Tin tức Nạp Đa","text":"Trên hành trình chu du Chu Tước Tinh cùng Độn Thiên, Vương Lâm nghe nhắc tới Nạp Đa - một trong bốn người ngoại lai năm xưa, liền chấn động vì từng gặp và kể lại các chuyện liên quan.","importance":"normal","nguon":["@c0391"]},{"chuong":"@c0391","tieuDe":"Chu Tước kỳ trận chặn đường","text":"Bay vào biên giới phía bắc Chu Tước đại lục, Vương Lâm phát hiện nguy hiểm vội lùi lại khi Chu Tước kỳ trận trỗi dậy bao phủ toàn đại lục.","importance":"normal","nguon":["@c0391"]},{"chuong":"@c0391","tieuDe":"Bị Kiền Phong nhốt ngoài trận","text":"Khi Độn Thiên ép trận nhãn mở lỗ hổng tiến vào, Vương Lâm theo sau thì bị Kiền Phong vỗ hư không khép quầng sáng, ngăn lại bên ngoài để khiêu chiến.","importance":"bridge","nguon":["@c0391"]},{"chuong":"@c0391","tieuDe":"Khai chiến, ép lui Kiền Phong","text":"Vương Lâm nhận lời đấu, rút tiên kiếm dung nhập tiên lực chém một nhát cắt lời Kiền Phong; tiếng nổ lớn ép Kiền Phong lui trăm trượng, khiến hắn kinh hãi nhận ra tiên bảo và ngón tay rỉ máu.","importance":"bridge","nguon":["@c0391"]},{"text":"Vương Lâm ra tay trước toàn lực, phun khí đen rồi triệu Thập Ức Tôn Hồn Phiên thả hàng triệu hồn phách cùng mười hai chủ hồn lao về Kiền Phong, khiến đối thủ Anh Biến Trung Kỳ không kịp trở tay.","nguon":["@c0392"],"bridge":true,"khoang":"@c0392","importance":"normal"},{"chuong":"@c0392","tieuDe":"Ép hồn phách tự nổ","text":"Vương Lâm quyết đoán hô Nổ, hàng triệu hồn phách tự nổ sinh uy lực hùng mạnh, ép Kiền Phong phải thu dùi chuyển Chu Tước trận hộ thân và phun máu; hắn thu hồi mười hai chủ hồn, thong dong vào Chu Tước đại lục bên Độn Thiên.","importance":"bridge","nguon":["@c0392"]},{"chuong":"@c0392","tieuDe":"Rút lui, không giết được Kiền Phong","text":"Hai phân phiên hư ảo dùng hết, khí đen từ nguyên thần Vương Lâm bay về dung nhập thân Độn Thiên hợp với Tôn Hồn Phiên thật; không giết nổi Kiền Phong vì có Chu Tước trận, Vương Lâm bình thản rời đi về Luyện Hồn Tông.","importance":"normal","nguon":["@c0392"]},{"chuong":"@c0392","tieuDe":"Vào cấm địa bế quan chờ Anh Biến","text":"Về Luyện Hồn Tông, Vương Lâm được Độn Thiên dẫn vào cấm địa sau núi, nhận túi trữ vật và lời hứa hộ pháp; hắn cảm ơn, hứa nhớ kỹ chuyện đã đáp ứng rồi bắt đầu bế quan gắng tới ngày Anh Biến.","importance":"normal","nguon":["@c0392"]},{"text":"Vương Lâm ngồi trong động phủ cấm địa, dùng túi trữ vật tiên ngọc khổng lồ Độn Thiên để lại, đổ tiên ngọc ra bốn phía rồi thổ nạp hấp thụ tiên lực, ngưng linh cầu tại đan điền để khởi động Anh Biến.","nguon":["@c0393"],"bridge":true,"khoang":"@c0393","importance":"normal"},{"chuong":"@c0393","tieuDe":"Hoàn thành bước một - thân thể ngưng hóa thành tiên thể","text":"Tiên lực dập nát kinh mạch, thân thể Vương Lâm thành thùng rỗng rồi tái tạo bằng tiên lực, trở nên trong suốt như thủy tinh, quần áo hòa tan, xóa sạch phàm căn, cả người như tiên nhân — hoàn thành bước một của Anh Biến.","importance":"normal","nguon":["@c0393"]},{"chuong":"@c0393","tieuDe":"Nguyên thần bị đánh văng","text":"Linh cầu hóa kim cầu rồi nổ tung, tiên lực đánh nguyên thần Vương Lâm văng ra ngoài ba thước; một lực đạo ngăn nguyên thần trở vào thân, khiến nó lơ lửng quan sát thân thể được cải tạo như nhìn người khác.","importance":"normal","nguon":["@c0393"]},{"chuong":"@c0393","tieuDe":"Bắt đầu bước hai - nguyên thần cô đọng","text":"Được Độn Thiên bố trí lồng khí đen hộ pháp ngăn hương khí dẫn dụ, nguyên thần Vương Lâm mở túi trữ vật đổ tiên ngọc; lần này tiên lực không bị thân thể hút mà ngưng kết bên cạnh, thấm vào nguyên thần, khởi động bước hai cô đọng nguyên thần.","importance":"normal","nguon":["@c0393"]},{"chuong":"@c0394","tieuDe":"Tiến gần Anh Biến","text":"Vương Lâm cảm nhận linh lực dung nhập, nguyên thần dần ngưng thật, ngày càng lớn và thật hơn; sau khi ngưng thật hoàn toàn sẽ nhập làm một với thân thể, Anh Biến thành công. Quá trình ngưng thật còn lâu dài.","importance":"major","nguon":["@c0394"]},{"chuong":"@c0394","tieuDe":"Bị Chu Tước thánh hỏa phủ trăm dặm, biến mất","text":"Khi Chu Tước Tử thi triển Chu Tước thánh hỏa cuồng mãnh bao phủ trăm dặm quanh Luyện Hồn Tông, Vương Lâm đang giữa quá trình Anh Biến cũng bị lửa bao trùm và biến mất, sống chết chưa rõ.","importance":"normal","nguon":["@c0394"]},{"chuong":"@c0395","tieuDe":"Xuất thủ từ bế quan cứu Độn Thiên","text":"Đúng lúc Chu Tước Tử chụp giết Độn Thiên, Vương Lâm từ nơi bế quan vọng ra tiếng cười âm trầm, mắng Cút con bà ngươi đi rồi xuất thủ, khiến Chu Tước Tử nguyên thần đau đớn, kinh hãi chưa từng có.","importance":"normal","nguon":["@c0395"]},{"chuong":"@c0397","tieuDe":"Để Tư Đồ Nam mượn thân đuổi Chu Tước Tử","text":"Nguyên thần Vương Lâm đã về thân, Anh Biến đại thành nhưng kiệt sức không thể tham chiến; hắn để Tư Đồ Nam nhập thân hư trương thanh thế, ép đệ tam Chu Tước Tử cắt ba ngón tay rồi đuổi đi.","importance":"major","nguon":["@c0397"]},{"chuong":"@c0397","tieuDe":"Nhận Tôn Hồn Phiên, quỳ tiễn Độn Thiên","text":"Sau khi Tư Đồ Nam lộ diện và hứa khôi phục Luyện Hồn Tông, Vương Lâm chứng kiến Độn Thiên hủy thần trí qua đời; hắn cầm lấy Thập Ức Tôn Hồn Phiên bay về tay mình, quỳ dập đầu lạy ba cái.","importance":"bridge","nguon":["@c0397"]},{"chuong":"@c0397","tieuDe":"Thề báo thù Chu Tước Tử","text":"Vương Lâm thề sẽ trở về tìm Chu Tước Tử báo thù việc tiêu diệt Luyện Hồn Tông.","importance":"bridge","nguon":["@c0397"]},{"chuong":"@c0397","tieuDe":"Đồng ý đưa Tư Đồ Nam tìm thân đồng tử, cho mượn Văn Thú","text":"Vương Lâm gọi Văn Thú cưỡi đi về Viêm Cực cực bắc nơi có thân thể đồng tử Tư Đồ Nam muốn đoạt xá; ban đầu từ chối nhưng vì Tư Đồ Nam kể công ơn cũ nên động lòng đồng ý cho mượn Văn Thú nghiên cứu một ngày.","importance":"normal","nguon":["@c0397"]},{"chuong":"@c0397","tieuDe":"Hỏi Cực Cảnh, đưa xem sợi trắng áp lực Thiên Kiếp","text":"Vương Lâm hỏi Tư Đồ Nam về Cực Cảnh trong cực đạo thủy tam cảnh và lấy ra một sợi màu trắng tỏa áp lực như Thiên Kiếp, khiến Tư Đồ Nam biến sắc rồi vội cất lại vào túi trữ vật của hắn.","importance":"bridge","nguon":["@c0397"]},{"chuong":"@c0399","tieuDe":"Rời Chu Tước theo Tư Đồ Nam","text":"Vương Lâm nghe tiếng gào từ xa, thu hồi Văn Thú rồi tự bay đi không chờ; bị Tư Đồ Nam tìm ra, chê chậm và ôm mang đi khỏi Chu Tước đại lục, bay thẳng tới Viêm Cực ở tiểu bắc. Hắn không hay Tư Đồ Nam đang mưu tính sau khi kết hợp thân thể sẽ quay lại nuốt luôn cả mình.","importance":"bridge","nguon":["@c0399"]},{"chuong":"@c0400","tieuDe":"Theo Tư Đồ Nam vào Tiểu Bắc Viêm Cực","text":"Vương Lâm cùng Tư Đồ Nam phá không tới Tiểu Bắc Viêm Cực phía bắc Chu Tước Tinh, bị tứ tổ Tiên Di Tộc đuổi theo; vào tới nơi hắn liếc thấy ma đồng bị viêm băng đỏ vây khốn.","importance":"bridge","nguon":["@c0400"]},{"chuong":"@c0400","tieuDe":"Bị Tư Đồ Nam kéo tránh cấm chế","text":"Khi Tư Đồ Nam bấm quyết niệm chú kích hoạt cấm chế khiến băng toàn vùng phóng tinh quang, Vương Lâm bị hắn túm kéo lui ra xa trăm trượng, đứng ngoài cuộc giao đấu giữa Tư Đồ Nam và tứ tổ.","importance":"bridge","nguon":["@c0400"]},{"chuong":"@c0401","tieuDe":"Nghe bí mật Tu Tinh Chi Tinh","text":"Vương Lâm nghe Tư Đồ Nam (đang đoạt xá đồng tử) tiết lộ bí mật Tu Tinh Chi Tinh: vật khống chế tối thượng do tu chân liên minh tạo, hấp thụ mệnh hồn mọi sinh mệnh trên tinh cầu, từng bị Tư Đồ Nam phong ấn khi còn là Chu Tước Tử.","importance":"normal","nguon":["@c0401"]},{"chuong":"@c0401","tieuDe":"Chấn động vì mệnh hồn còn bị giữ","text":"Vương Lâm kinh chấn khi biết một tia mệnh hồn của mình còn nằm trong Tu Tinh Chi Tinh, sinh tử nằm trong tay Chu Tước Tử; trong mắt lóe hàn quang, thầm quyết không để sinh mệnh mình bị người khác nắm.","importance":"bridge","nguon":["@c0401"]},{"chuong":"@c0401","tieuDe":"Vỡ lẽ cục diện đại loạn","text":"Vương Lâm hiểu ra vì sao các tu chân quốc làm phản, vì sao Chu Tước Tử trừ khử tu chân quốc cấp năm và vì sao Tiên Di Tộc chưa bị tiêu diệt; nhớ lại giọng điệu phỏng đoán của Nạp Đa năm xưa.","importance":"bridge","nguon":["@c0401"]},{"chuong":"@c0401","tieuDe":"Lập kế hoạch rời Chu Tước Tinh","text":"Vương Lâm rời Tiểu Bắc Viêm Cực, định rút mệnh hồn ra, thu du hồn khôi phục Thập Ức Tôn Hồn Phiên, tìm huyết dịch Cự Ma Tộc ở Thi Âm Tông (Triệu quốc) rồi đi tìm Thiên Vận Tử; lo ngại mối đe dọa Thác Sâm (thừa hưởng sức mạnh bát tinh của Đồ Ti).","importance":"bridge","nguon":["@c0401"]},{"chuong":"@c0401","tieuDe":"Bay về Sở quốc giữa đại chiến","text":"Vương Lâm đổi hướng về Sở quốc thăm nhà, dọc đường chém giết vô số tộc nhân Tiên Di Tộc nhưng chúng quá đông nên phải ẩn tàng thân hình cấp tốc bay đi giữa đại chiến lần hai trên Chu Tước đại lục.","importance":"bridge","nguon":["@c0401"]},{"chuong":"@c0402","tieuDe":"Nghe tin Vân Tước Tử lộ thân phận","text":"Trên đường về Sở quốc, Vương Lâm nghe tin Vân Tước Tử thực ra là nhị tổ Tiên Di Tộc đã đánh lén trọng thương Chu Tước Tử, kinh hãi và dự cảm Vân Tước Tử nhất định sẽ tìm đến mình.","importance":"bridge","nguon":["@c0402"]},{"chuong":"@c0402","tieuDe":"Gặp lại Chu Võ Thái bên truyền tống trận","text":"Tại cổ truyền tống trận cuối cùng của Sở quốc, Vương Lâm gặp lại Chu Võ Thái (đội Vân Tước mão), cùng uống thứ rượu cũ gợi nhớ Đại Ngưu; Chu Võ Thái kính ba chén tạ ơn, cảnh báo cả bốn người đều là quân cờ của Vân Tước Tử và để lại nửa bình rượu.","importance":"normal","nguon":["@c0402"]},{"chuong":"@c0402","tieuDe":"Nhận và phá ngọc giản ý cảnh Liễu Mi","text":"Vương Lâm xem ngọc giản Chu Võ Thái để lại, hiểu ý cảnh Liễu Mi là Thiên Huyễn vô tình đạo, tự tin có thể phá vỡ nếu bị Liễu Mi chọc vào, rồi miết vỡ ngọc giản.","importance":"bridge","nguon":["@c0402"]},{"chuong":"@c0402","tieuDe":"Trở về Sở quốc tan hoang, đổi quyết định","text":"Vương Lâm truyền tống về Sở quốc tan hoang bị Tiên Di Tộc khống chế, về thôn cũ không một bóng người; hắn không thèm nhìn đám Thuật Chú Sư lao tới, không cứu Vân Thiên Tông, và cuối cùng nội tâm thay đổi quyết định thay vì đi thu du hồn ngoại vực.","importance":"normal","nguon":["@c0402"]},{"chuong":"@c0403","tieuDe":"Quyết đột nhập hố sâu Tiên Di tộc","text":"Trước khi rời Chu Tước tinh, Vương Lâm nhắm vào kho dự trữ vạn năm của Tiên Di tộc, bay tới hố sâu nhưng bị cái cây khổng lồ chọc trời phòng vệ chặn không thể vào.","importance":"bridge","nguon":["@c0403"]},{"chuong":"@c0403","tieuDe":"Phá giải cơ chế cái cây phòng vệ","text":"Hắn thử bắn linh quang (tan biến) và dùng thần thông Anh Biến kỳ lấy vật hóa thân tạo phân thân tượng gỗ (bị phù hào phá), rồi thả hồn phách Kết Đan kỳ và phát hiện cây chỉ ngăn linh lực cùng tượng gỗ, không ngăn hồn phách.","importance":"major","nguon":["@c0403"]},{"chuong":"@c0403","tieuDe":"Dùng khải giáp hồn phách xuyên qua cây","text":"Vương Lâm phất Thiên Hồn Phiên, điều hơn hai ngàn hồn phách (gồm tàn hồn Kỳ Lân thú) tụ thành khải giáp bao quanh nhục thân, chịu khí lạnh như băng xuyên vào bên trong thân cây.","importance":"bridge","nguon":["@c0403"]},{"chuong":"@c0403","tieuDe":"Thuấn di qua bốn tầng hố sâu","text":"Tu vi gần đạt Anh Biến sơ kỳ giúp hắn nhanh chóng thuấn di qua tầng một, hai, ba (vắng lặng) tới cửa tầng bốn rồi ẩn thân.","importance":"normal","nguon":["@c0403"]},{"chuong":"@c0403","tieuDe":"Bám theo Thuật Chú Sư lục diệp vào tầng bốn","text":"Hắn lặng lẽ bám đuôi một Thuật Chú Sư lục diệp hóa mặt người khổng lồ cùng đám tu sĩ vô thần, không bị phát hiện, tiến tới trung tâm tầng bốn.","importance":"normal","nguon":["@c0403"]},{"chuong":"@c0403","tieuDe":"Chứng kiến nghi thức Luân Hồi thụ chữa thương","text":"Vương Lâm chứng kiến mười một lục diệp Thuật Chú Sư niệm chú đẩy phù văn, Luân Hồi thụ dùng rễ quấn hơn trăm tu sĩ Kết Đan kỳ hút tinh huyết, linh lực truyền vào bát diệp Thuật Chú Sư trọng thương; nhận ra chỉ y mới có tư cách phát hiện ra hắn.","importance":"normal","nguon":["@c0403"]},{"chuong":"@c0404","tieuDe":"Một chưởng tiên lực giết bát diệp lão giả","text":"Vương Lâm hóa hư ảnh áp sát quầng sáng chữa thương trên Luân Hồi thụ, vỗ một chưởng chứa tiên lực kinh thiên động địa khắp tầng thứ tư; đám lục diệp Thuật Chú Sư bị thổi bay phun máu, nhận ra hắn là tu sĩ Anh Biến rồi bỏ chạy, lão giả bát diệp trọng thương lùi chạy.","importance":"normal","nguon":["@c0404"]},{"chuong":"@c0404","tieuDe":"Phá Luân Hồi thụ, cứu hơn trăm tu sĩ","text":"Vương Lâm vỗ tay khiến Luân Hồi thụ vỡ tan, hơn trăm tu sĩ bị giam rơi xuống tỉnh táo; hắn hô rời đi, một tu sĩ Kết Đan nhận ra và gọi hắn là Thủy tổ nhưng hắn thấy xa lạ.","importance":"normal","nguon":["@c0404"]},{"chuong":"@c0404","tieuDe":"Thả Văn thú truy diệt lục diệp","text":"Vương Lâm thả Văn thú đã mở linh trí; nó hóa tia chớp đen đâm miệng vào lục diệp Thuật Chú Sư hút khô thân thể thành bao da xương rồi tiếp tục đuổi giết kẻ khác.","importance":"bridge","nguon":["@c0404"]},{"chuong":"@c0404","tieuDe":"Tiên kiếm phá Tổ phù, chém đầu lão giả","text":"Vương Lâm rút tiên kiếm dung nhập tiên lực chém như khai thiên tích địa, đánh vỡ Tổ phù lão giả triệu hồi; sau đó đánh một ấn ký vào cơ thể lão rồi chém đầu mà không xưng danh.","importance":"bridge","nguon":["@c0404"]},{"chuong":"@c0404","tieuDe":"Đầu lâu không hồn phách & phù hào tổ phù","text":"Vương Lâm dùng bí thuật Luyện Hồn tông kiểm tra nhưng phát hiện lão giả không có hồn phách; dùng u hỏa luyện hóa mà đầu lâu không tan, trên đầu mang phù hào đen không trọn vẹn giống tổ phù, hắn thu đầu lâu vào túi trữ vật.","importance":"normal","nguon":["@c0404"]},{"chuong":"@c0404","tieuDe":"Tiến vào tầng thứ năm, bị sinh vật tảo biển vây","text":"Vương Lâm thu Văn thú, tiến vào tầng thứ năm rộng lớn phủ thực vật giống tảo biển từng gặp ở Sở quốc; thần thức phát hiện ba Luân Hồi thụ với bát diệp trọng thương, nhưng tảo biển mọc dày kết thành vô số sinh vật hình người quỷ dị bao vây hắn.","importance":"normal","nguon":["@c0404"]},{"text":"Khi xâm nhập sào huyệt Tiên Di tộc và bị sinh vật phòng ngự cảnh cáo, Vương Lâm xuất Thập Ức Tôn Hồn Phiên, hô Dung! dung hợp khoảng năm triệu hồn phách cùng hơn mười chủ hồn thành một hồn phách tu vi Vấn Đỉnh sơ kỳ, khiến cả tầng năm rung chuyển.","nguon":["@c0405"],"bridge":true,"khoang":"@c0405","importance":"bridge"},{"chuong":"@c0405","tieuDe":"Càn quét tầng năm, hủy Luân Hồi thụ","text":"Vương Lâm điều hồn phách Vấn Đỉnh lao vào Luân Hồi thụ làm cây tan nát, hóa thành ác ma quét ngang tầng năm giết sạch Thuật Chú Sư, cắt đầu luyện hóa huyết nhục và thu phù văn.","importance":"bridge","nguon":["@c0405"]},{"chuong":"@c0405","tieuDe":"Chẻ tre xuống tầng mười, giết 19 Thuật Chú Sư","text":"Hắn chẻ tre qua các tầng sáu, bảy, tám xuống tới tầng mười, tổng cộng giết mười chín bát diệp Thuật Chú Sư (đều đã bị thương).","importance":"bridge","nguon":["@c0405"]},{"chuong":"@c0405","tieuDe":"Hồn phách Vấn Đỉnh tan rã, thu hồi Hồn Phiên","text":"Tới tầng mười, hồn phách Vấn Đỉnh suy yếu tan rã bay vào Hồn Phiên không gọi lại được; Vương Lâm thu hồi Hồn Phiên, xác nhận hạn chế của thuật ngưng tụ vì thời gian dùng ngắn và tổn hại lớn.","importance":"bridge","nguon":["@c0405"]},{"chuong":"@c0405","tieuDe":"Thu hoạch linh thạch và 19 đầu lâu","text":"Vương Lâm cướp được lượng linh thạch khổng lồ sánh với một tông phái ngàn năm, cùng mười chín đầu lâu bát diệp Thuật Chú Sư mang khí tức thượng cổ — tinh hoa quý giá của Tiên Di tộc.","importance":"bridge","nguon":["@c0405"]},{"chuong":"@c0405","tieuDe":"Bày trận pháp ẩn rồi xuống tầng mười một","text":"Trước cửa tầng mười một, Vương Lâm bày trận pháp từng dùng chống thiên phú thần thông Cự Ma tộc, dùng ngọc giản Độn Thiên lập truyền tống trận nhỏ đặt tiên ngọc, rồi cầm tiên kiếm nhảy vào cửa động tối đen.","importance":"bridge","nguon":["@c0405"]},{"chuong":"@c0405","tieuDe":"Gặp nữ tử cửu diệp và bức tranh chín điểm sáng","text":"Tại tầng mười một, Vương Lâm thấy một nữ tử xích lõa lơ lửng có phù văn cửu diệp trên trán, dung mạo mỹ lệ khiến hắn thấy quen thuộc; phía trên là bức tranh chín điểm sáng giống y hệt bức tranh không điều khiển được trong túi trữ vật của hắn.","importance":"normal","nguon":["@c0405"]},{"chuong":"@c0405","tieuDe":"Hứa Quốc Lập nhận ra Tiên tử tiểu muội muội","text":"Khi nữ tử mở mắt, kiếm hồn Hứa Quốc Lập trong tiên kiếm của Vương Lâm biến ảo ra, lẩm bẩm gọi nàng là Tiên tử tiểu muội muội và cảm tạ nàng đã mang về tia ý cảnh mà tàn hồn năm xưa bị mất khi hóa thành tu sĩ.","importance":"normal","nguon":["@c0405"]},{"chuong":"@c0406","tieuDe":"Đối mặt tam tổ Mị Cơ","text":"Vương Lâm đối mặt nữ tử thần bí ở tầng mười một vùng đất Tiên Di; Hứa Lập Quốc trong tiên kiếm tách ra định gần gũi nàng nhưng bị áp chế phải chui lại. Nữ tử tự xưng là Mị Cơ, tam tổ Tiên Di Tộc.","importance":"bridge","nguon":["@c0406"]},{"chuong":"@c0406","tieuDe":"Bị Mị Cơ phong tỏa, đòi gần gũi","text":"Mị Cơ phong tỏa lối ra, nói ngửi thấy hắn chưa tận nữ sắc nên muốn cùng hắn gần gũi mới cho đi; Vương Lâm phán đoán nàng đang trọng thương chưa lành.","importance":"bridge","nguon":["@c0406"]},{"chuong":"@c0406","tieuDe":"Uy hiếp bằng pháp bảo","text":"Vương Lâm rung Thập Ức Tôn Hồn Phiên phát tiếng gầm xuyên hồn phách, dùng tiên kiếm một thành tiên lực chém khe sâu lộ tiên bảo, cảnh báo Mị Cơ và hứa rời đi để nàng dưỡng thương.","importance":"bridge","nguon":["@c0406"]},{"chuong":"@c0406","tieuDe":"Thoát thân qua Truyền Tống Trận","text":"Vương Lâm vờ bay tới cửa rồi bất ngờ kích hoạt Truyền Tống Trận tự bố trí ở tầng mười để dịch chuyển thoát thân; Mị Cơ quyết bắt sống, gọi hắn bằng tên Anh Biến Kỳ và phái cuộn tranh đuổi theo.","importance":"normal","nguon":["@c0406"]},{"chuong":"@c0406","tieuDe":"Bị Phù Thú Đồ Phổ truy sát","text":"Vương Lâm chạy từ tầng mười về tầng một, bị giao long nghìn trượng và hắc hổ trăm trượng từ cuộn tranh truy sát; hắn dùng cấm chế chứa tiên lực bịt miệng giao long rồi lùi vào tầng thứ nhất nhưng cấm chế bị phá.","importance":"bridge","nguon":["@c0406"]},{"chuong":"@c0406","tieuDe":"Dùng Phù Thú Đồ Phổ của mình khắc chế","text":"Vương Lâm lấy ra cuộn tranh lâu nay không khống chế được — chính là Phù Thú Đồ Phổ, bảo vật Tiên Di Tộc; thân ảnh nữ tổ tiên tự phong ấn hiện ra thu cả giao long lẫn mãnh hổ về, khiến Mị Cơ phun máu chịu phản phệ.","importance":"bridge","nguon":["@c0406"]},{"chuong":"@c0406","tieuDe":"Rời vùng đất Tiên Di, giữ ý cảnh tàn hồn","text":"Vương Lâm thu cuộn tranh, bay ra khỏi vùng đất Tiên Di trong đêm khuya; hắn không trả ý cảnh tàn hồn của tam tổ mà giữ lại làm thủ đoạn tối hậu sau này.","importance":"bridge","nguon":["@c0406"]},{"chuong":"@c0407","tieuDe":"Thất bại khôi phục Tôn Hồn Phiên","text":"Vương Lâm rời vùng Tiên Di, dùng Truyền Tống Trận Sở quốc ra vực ngoại chiến trường thu du hồn để khôi phục Thập Ức Tôn Hồn Phiên, nhưng du hồn vào phiên phát cuồng cắn nuốt rồi tan biến do trời sinh xung khắc; cách thôn hồn cũng thất bại, đành rời đi.","importance":"bridge","nguon":["@c0407"]},{"chuong":"@c0407","tieuDe":"Định lấy huyết dịch tổ tiên Cự Ma Tộc","text":"Vương Lâm nhắm tới thân thể khổng lồ tổ tiên Cự Ma Tộc dưới Thi Âm Tông Triệu quốc để lấy huyết dịch cho Bổn Tôn thi triển thần thông cổ thần, chuẩn bị rút mệnh hồn rời Chu Tước Tinh đi Thiên Vận Tinh bái sư.","importance":"bridge","nguon":["@c0407"]},{"chuong":"@c0407","tieuDe":"Đột nhập Thi Âm Tông","text":"Vương Lâm phá trận pháp Thi Âm Tông Triệu quốc dễ dàng, đạp xuống mắt trận hiện ra dưới lòng đất mê cung hang động, thần thức quét toàn tông.","importance":"bridge","nguon":["@c0407"]},{"chuong":"@c0407","tieuDe":"Chạm trán hư ảnh nguyên thần Di Lặc Tông","text":"Hư ảnh nguyên thần Hóa Thần Trung Kỳ sau lưng Lý Thanh Bình phát hiện và kinh hãi cầu xin Vương Lâm, khai là đệ tử Di Lặc Tông Thiên Vận Tinh mua thân từ Thi Âm Tông; Vương Lâm lạnh lùng tra hỏi vì sao người Thiên Vận Tinh lại tới Chu Tước Tinh.","importance":"major","nguon":["@c0407"]},{"chuong":"@c0408","tieuDe":"Tra hỏi, biết tên Tào Nhất Đấu","text":"Vương Lâm dùng thần thức tra hỏi hư ảnh trong thân Lý Thanh Bình, biết hắn tên Tào Nhất Đấu; dáng vẻ thành thực khiến Vương Lâm nhớ tới Hứa Lập Quốc năm xưa.","importance":"bridge","nguon":["@c0408"]},{"chuong":"@c0408","tieuDe":"Trấn áp Lý Thanh Bình","text":"Vương Lâm hiện ra từ hư không, một ánh mắt khiến Lý Thanh Bình toát mồ hôi lạnh, Nguyên Anh đông cứng; Lý Thanh Bình đoán hắn là Anh Biến lão quái, bị bảo câm miệng.","importance":"major","nguon":["@c0408"]},{"chuong":"@c0408","tieuDe":"Thu phục Tào Nhất Đấu làm nô bộc","text":"Vương Lâm cách không bắt lại nguyên thần Tào Nhất Đấu, ra điều kiện làm nô bộc trăm năm dẫn đường tới Thiên Vận Tinh, đổi lấy một thân thể Anh Biến Kỳ, hứa ta không chết thì ngươi cũng không chết; Tào Nhất Đấu bái chủ.","importance":"major","nguon":["@c0408"]},{"chuong":"@c0408","tieuDe":"Đánh hôn mê, thu vào hồn phiên","text":"Vương Lâm đánh Lý Thanh Bình hôn mê để giấu ý định đi Thiên Vận Tinh, rồi dùng cây hồn phiên (vốn chế để thu Lý Nguyên Phong) thu Tào Nhất Đấu vào trong.","importance":"bridge","nguon":["@c0408"]},{"chuong":"@c0408","tieuDe":"Trở lại nơi bế quan năm xưa","text":"Vương Lâm thông thạo mê cung Thi Âm Tông, không ai phát hiện, tới nơi bế quan năm xưa rồi hóa khói chui vào lỗ nhỏ — năm xưa Trúc Cơ Kỳ phải nhờ Thiên Nghịch Châu mới vào được, nay thân vào dễ dàng.","importance":"major","nguon":["@c0408"]},{"chuong":"@c0408","tieuDe":"Phá phòng ngự âm hàn tới quan tài người khổng lồ","text":"Vương Lâm dễ dàng phá các tầng hàn khí từng chặn hắn năm xưa, lao tới cỗ quan tài khổng lồ tỏa âm hàn vô biên, nghe lại tiếng Cứu ta xuyên vào linh hồn giống hệt năm xưa.","importance":"bridge","nguon":["@c0408"]},{"chuong":"@c0408","tieuDe":"Vào hang động sương trắng và dây leo tím","text":"Vương Lâm phá cánh cửa hàn khí cuối, tiến vào hang động khổng lồ với đám sương trắng âm hàn nồng đậm chiếm ba phần tư, trong đó thấp thoáng u quang và một dải dây leo màu tím quay cuồng.","importance":"bridge","nguon":["@c0408"]},{"chuong":"@c0409","tieuDe":"Phá sương trắng lộ thi thể tổ tiên Cự Ma Tộc","text":"Vương Lâm dùng pháp thuật Phong động ẩn tiên lực tạo cuồng phong cuốn tan đám sương trắng âm hàn, lộ ra thi thể người khổng lồ da xanh bị cây xanh tím ký sinh và pháp thuật giam cầm. Qua dấu ấn hình lưỡi búa giữa lông mày, hắn quả quyết đây là tổ tiên Cự Ma Tộc.","importance":"bridge","nguon":["@c0409"]},{"chuong":"@c0409","tieuDe":"Đối kháng cây ký sinh, phát hiện thân thể cứng rắn","text":"Vương Lâm dùng lửa tiên lực buộc cây ký sinh lui nhưng không hủy vì sợ phá giam cầm. Hắn rút tiên kiếm đâm thân người khổng lồ thì bị phản chấn đẩy lùi ba tấc do thân thể cực cứng, bèn dùng cành cây ký sinh làm vũ khí xâm nhập lấy máu.","importance":"normal","nguon":["@c0409"]},{"chuong":"@c0409","tieuDe":"Lấy máu tươi, cự tuyệt lời cầu cứu","text":"Vương Lâm dùng bình ngọc hứng máu tươi của tổ tiên Cự Ma Tộc, ngoảnh mặt làm ngơ trước lời kêu cứu và lời hứa trọng bảo vì biết thả ra sẽ bị truy sát. Cuối cùng hắn lấy cấm phiên ra để xử lý đám cây.","importance":"bridge","nguon":["@c0409"]},{"chuong":"@c0410","tieuDe":"Phong ấn cây xanh tím, lấy máu Lôi Cát","text":"Vương Lâm thúc cấm phiên hô Phong, hóa cấm chế hắc quang như lưới phong ấn cái cây xanh tím trên ngực người khổng lồ, đứng trên cổ dùng cành cây điểm tạo ấn chú lấy máu tươi cùng sức sống vào bình ngọc.","importance":"bridge","nguon":["@c0410"]},{"chuong":"@c0410","tieuDe":"Nhận ra Lôi Cát câu giờ, từ chối lời dụ","text":"Trước lời dụ làm vật cưỡi, dâng Khai Thiên Chi Thiết và dịch thể cốt tủy của Lôi Cát, Vương Lâm nhíu mày nhận ra hắn trả lời quá tỉ mỉ để kéo dài thời gian, liền thôi thúc tiên lực ép máu chảy nhanh hơn và cười lạnh từ chối cứu.","importance":"bridge","nguon":["@c0410"]},{"chuong":"@c0410","tieuDe":"Gỡ phong ấn rời đi, giữ làm nguồn máu","text":"Vương Lâm gỡ cấm chế thu về cấm phiên, từ chối lời mời khiến Cự Ma Tộc nhận chủ, tuyên bố giữ Lôi Cát nơi đây để bất cứ lúc nào tới lấy máu mới là tốt nhất, rồi hóa khói trở về theo đường cũ.","importance":"bridge","nguon":["@c0410"]},{"chuong":"@c0411","tieuDe":"Dò xét hang động qua hồn phách","text":"Vuong Lam xuất hiện ở Thi Âm Tông, điểm vào hồn phách âm khí mà hắn đã thả ra trước khi rời hang động người khổng lồ để dò xét — nơi có sức mạnh kỳ dị hạn chế thần thức nhưng ít ảnh hưởng tới âm khí. Nhận thông tin xong, hắn cười lạnh rồi rời đi.","importance":"bridge","nguon":["@c0411"]},{"chuong":"@c0411","tieuDe":"Từ chối Tư Đồ Nam","text":"Tại bình nguyên phía trên Thi Âm Tông, Vuong Lam gặp Tư Đồ Nam vừa đoạt xá thành công hiện thân đồng tử áo đỏ. Khi bị rủ tới Phong Loan Tinh hưởng lạc, hắn chau mày từ chối dứt khoát.","importance":"major","nguon":["@c0411"]},{"chuong":"@c0411","tieuDe":"Khẳng định bất đồng","text":"Vuong Lam tuyên bố Ta không giống như ngươi, tự nhận theo đuổi bản chất và đỉnh điểm của tu luyện, muốn đứng đầu thiên hạ và hiểu rõ thiên đạo chân tình thay vì hưởng lạc nhân gian. Vẻ kiêu ngạo của hắn khiến Tư Đồ Nam thấy xa lạ, gợi nhớ tới Diệp Vô Ưu.","importance":"bridge","nguon":["@c0411"]},{"chuong":"@c0412","tieuDe":"Chuẩn bị rút mệnh hồn, tạm biệt Tư Đồ Nam","text":"Vương Lâm chuẩn bị tự mình vào Chu Tước Tinh rút mệnh hồn khỏi Tu Tinh Chi Tinh (Tư Đồ Nam không thể trợ giúp vì chỉ Anh Biến tu sĩ mới vào được). Hắn bình thản nói lấy mệnh hồn xong sẽ rời đi, hẹn ngày gặp lại rồi hóa cầu vồng bay đi.","importance":"major","nguon":["@c0412"]},{"chuong":"@c0412","tieuDe":"Hỏi về cảnh giới trên Vấn Đỉnh","text":"Trên đường bay, Vương Lâm hỏi Tư Đồ Nam về cảnh giới sau Vấn Đỉnh và được giảng giải về Toái Niết Tam Cảnh (Khuy Niết, Tịnh Niết, Toái Niết), âm dương nhị ý, danh hiệu Chu Tước Tử cùng thần thông Chu Tước Ấn, Chu Tước Quyết. Hắn nhớ lại việc năm xưa từng giúp Lý Mộc Uyển đối phó luân hồi sứ giả.","importance":"bridge","nguon":["@c0412"]},{"chuong":"@c0412","tieuDe":"Đưa thanh tiên kiếm cho Tư Đồ Nam kiểm tra","text":"Vương Lâm lấy thanh tiên kiếm trong túi trữ vật ra hỏi có phải bảo vật cấp Toái Niết. Trong tay Tư Đồ Nam, kiếm phát kiếm quang ngập trời mạnh hơn khi ở tay Vương Lâm gấp vô số lần, ngầm xác nhận lai lịch phi thường của thanh kiếm.","importance":"bridge","nguon":["@c0412"]},{"chuong":"@c0414","tieuDe":"Cân nhắc điều kiện rời Chu Tước mộ","text":"Vương Lâm nhẩm tính: dùng ngọc giản Tư Đồ Nam đưa thì có thể rời Chu Tước mộ, nhưng nếu không giành được Tu Tinh Chi Tinh thì không rút được mệnh hồn; biện pháp khác lại khiến linh hồn tàn khuyết.","importance":"bridge","nguon":["@c0414"]},{"chuong":"@c0414","tieuDe":"Tiến vào Chu Tước Sơn, được nhường đường","text":"Vương Lâm tiến đến Chu Tước Sơn, đám tu sĩ biến sắc lui ra nhường đường; Man Hoang Nam Minh nhận ra thực lực hắn liền quát đệ tử, cung kính bái kiến tiền bối và tránh đường.","importance":"bridge","nguon":["@c0414"]},{"chuong":"@c0414","tieuDe":"Được công nhận tư cách, gia nhập nhóm mười sáu","text":"Vương Lâm tiến vào chu vi trăm trượng, được các tu sĩ Anh Biến công nhận tư cách ngang bằng, gia nhập nhóm mười sáu người được vào Chu Tước mộ nhanh nhất, rồi ngồi xuống một lối vào trầm mặc.","importance":"major","nguon":["@c0414"]},{"chuong":"@c0414","tieuDe":"Bị người trung niên bí ẩn gọi đích danh Tằng Ngưu","text":"Người đàn ông trung niên bí ẩn mang tiểu hầu gọi đích danh hắn là Tằng Ngưu, khen nghị lực dùng Luyện Tiên Phản Nguyên rửa phàm căn; Vương Lâm lạnh nhạt từ chối, đòi tĩnh tu.","importance":"bridge","nguon":["@c0414"]},{"chuong":"@c0414","tieuDe":"Cảm giác quen thuộc với người bí ẩn","text":"Vương Lâm chắc chắn từng gặp người trung niên này, nụ cười quỷ dị của hắn gợi cảm giác quen thuộc nhưng suy nghĩ mãi không nhớ ra là ai.","importance":"normal","nguon":["@c0414"]},{"chuong":"@c0414","tieuDe":"Theo đoàn phóng vào thông đạo","text":"Khi thông đạo mở thêm suất vào, đoàn tu sĩ tiến vào còn một tu sĩ Anh Biến sơ kỳ bị bắn ra ngoài; Vương Lâm cũng phóng vào theo.","importance":"major","nguon":["@c0414"]},{"chuong":"@c0416","tieuDe":"Chém vỡ con đường mệnh hồn","text":"Vương Lâm dùng tiên kiếm chứa tiên lực chém vỡ con đường mảnh đất khô cằn dài mấy vạn dặm, làm lộ ra lực lượng kỳ dị và tiếng cười của một linh thể đứa bé mà kiếm không diệt được.","importance":"bridge","nguon":["@c0416"]},{"chuong":"@c0416","tieuDe":"Phát hiện bí mật mệnh hồn","text":"Hắn dung thần thức vào tiên lực hóa thành tiên thức, phá cấm cố một viên đất và tách được mệnh hồn (lửa xanh hỏa thuộc tính) của phàm nhân, hiểu ra mỗi viên đất là một mệnh hồn còn đứa bé là linh thể dung nhập nhiều mệnh hồn.","importance":"normal","nguon":["@c0416"]},{"chuong":"@c0416","tieuDe":"Nghi vấn về mệnh hồn bản thân","text":"Đối chiếu lời Tư Đồ Nam rằng mệnh hồn nằm trong Tu Tinh Chi Tinh, Vương Lâm nghi mệnh hồn của chính mình cũng ẩn trong một loại sinh vật tương tự.","importance":"bridge","nguon":["@c0416"]},{"chuong":"@c0416","tieuDe":"Bay sâu vào Chu Tước mộ ba ngày","text":"Vương Lâm bay như lưu tinh vào sâu Chu Tước mộ suốt ba ngày, thần thức tản ra không tìm được giới hạn và không gặp tu sĩ nào.","importance":"normal","nguon":["@c0416"]},{"chuong":"@c0416","tieuDe":"Gặp Mộ Dung Vân, kết bạn đồng hành","text":"Vương Lâm che giấu tu vi, giả Hóa Thần sơ kỳ và dùng lại danh xưng cũ Thanh Mộc khi gặp Mộ Dung Vân cùng cô gái mặt rỗ; Mộ Dung Vân mời đồng hành và tiết lộ lối Kiền Phong vào bên trong qua tế đàn.","importance":"major","nguon":["@c0416"]},{"chuong":"@c0416","tieuDe":"Cảnh giác tin tế đàn chết người","text":"Nghe Mộ Dung Vân kể hai bát diệp Thuật Chú Sư Tiên Di Tộc và hai Anh Biến lão quái bỏ mạng ở tế đàn mà không thấy địch, Vương Lâm chú ý đồ án cùng vệt máu đen trên áo hắn rồi cười châm chọc về vận khí của hắn.","importance":"major","nguon":["@c0416"]},{"chuong":"@c0417","tieuDe":"Gặp Mặc Vân Hải bị tia chớp truy đuổi","text":"Vương Lâm cùng Mộ Dung Vân và nữ tử phi hành thì gặp lão già Mặc Vân Hải đang bị tia chớp giao long trắng truy kích; Vương Lâm khuyên lão mau lui vì vật đó quỷ dị, rồi chứng kiến Mộ Dung Vân chỉ bằng ánh mắt khiến tia chớp run rẩy bỏ chạy.","importance":"normal","nguon":["@c0417"]},{"chuong":"@c0417","tieuDe":"Bị ngộ nhận là Tằng Ngưu, đồng ý liên thủ","text":"Mặc Vân Hải tưởng Vương Lâm là Tằng đạo hữu và tạ ơn; Vương Lâm phủ nhận. Hắn đồng ý liên thủ với Mặc Vân Hải để bảo mệnh Mộ Dung Vân, đổi lấy việc được dẫn đường tới Tế Đàn.","importance":"bridge","nguon":["@c0417"]},{"chuong":"@c0417","tieuDe":"Âm thầm thả pháp bảo dò xét trong sương đen","text":"Trên đường bay ba ngày tới dãy núi sương đen, Vương Lâm dùng lực kỳ dị bao bọc nữ tử bay theo; trong màn sương hắn âm thầm phun một đạo hắc mang và thả một vật ra để dò xét mà nữ tử tu vi thấp không phát hiện.","importance":"normal","nguon":["@c0417"]},{"chuong":"@c0417","tieuDe":"Phát hiện Tế Đàn khác lời Tư Đồ Nam","text":"Tới đỉnh núi thấy Tế Đàn đen hình tháp cao trăm trượng trên thạch đài đầy vết máu, Vương Lâm cảnh giác nhận ra nơi này khác miêu tả của Tư Đồ Nam (Tế Đàn lẽ ra nằm trong thung lũng chứ không trên đỉnh núi).","importance":"normal","nguon":["@c0417"]},{"chuong":"@c0417","tieuDe":"Hộ pháp, chứng kiến Mộ Dung Vân bị sưu hồn giết","text":"Vương Lâm hộ pháp khi Mặc Vân Hải bất ngờ dùng Sưu hồn thuật moi hồn giết chết Mộ Dung Vân để xác nhận lời khai, rồi lão một mình lên đỉnh Tế Đàn dò đường, cúi nhìn chỗ lõm với sắc mặt cổ quái.","importance":"bridge","nguon":["@c0417"]},{"chuong":"@c0419","tieuDe":"Xông trận, trường thương vỡ thành cấm khí","text":"Vương Lâm hét Cút ngay, hoá hắc ảnh cầm trường thương đâm Liễu Mi nhưng bị hư ảnh Khổng Tước xoè đuôi phát tiên khí trắng đánh dừng thân; hắn vung thương đánh thêm khiến trường thương tím vàng tan thành cấm khí, Liễu Mi nhận xét pháp bảo của hắn kỳ lạ.","importance":"bridge","nguon":["@c0419"]},{"chuong":"@c0419","tieuDe":"Rút Thập Ức Tôn Hồn Phiên rồi thu lại","text":"Vương Lâm triệu Thập Ức Tôn Hồn Phiên định trực tiếp giết Liễu Mi để vào Chu Tước Mộ, nhưng nàng doạ phá huỷ Tế Đàn câu giờ mấy ngày nên hắn đành thu phiên lại.","importance":"bridge","nguon":["@c0419"]},{"chuong":"@c0419","tieuDe":"Triệu Hoạ trục sinh tử luân hồi đấu ý cảnh","text":"Trước yêu cầu lấy ý cảnh của Liễu Mi, Vương Lâm bấm quyết điểm mi tâm triệu Hoạ trục cực lớn, hiện tranh thuỷ mạc đen trắng tuôn bụi khí hoá Thanh Long ngoạm Khổng Tước, đấu ý cảnh sinh tử với đạo Thiên huyễn vô tình của nàng.","importance":"bridge","nguon":["@c0419"]},{"chuong":"@c0419","tieuDe":"Suy ngẫm vô tình - tuyệt tình, dung hợp ý cảnh","text":"Vương Lâm so sánh tuyệt tình của Hồng Điệp với vô tình bẩm sinh của Liễu Mi, nghĩ tới Lý Mộ Uyển khi than về sống và chết; Thanh Long tan thành bụi khí bao phủ Khổng Tước, ánh sáng bảy màu dung hợp với tranh thuỷ mạc.","importance":"bridge","nguon":["@c0419"]},{"chuong":"@c0421","tieuDe":"Chuẩn bị truyền tống ở Tế Đàn","text":"Vương Lâm vào Tế Đàn Chu Tước Mộ, cảm nhận lực lượng truyền tống dâng lên và đặt tay phải định rời đi thì biến cố nổ ra từ cơ thể Liễu Mi.","importance":"bridge","nguon":["@c0421"]},{"chuong":"@c0421","tieuDe":"Trúng bụi phấn dục ý","text":"Khi Mị Cơ tan nát, sương mù hồng dục ý lan tràn; Vương Lâm bay lui, vung cuồng phong tiên lực kháng cự nhưng bụi phấn (do ý cảnh hóa thành) vô hiệu, một ít theo lông tóc xâm nhập cơ thể, hắn vận tiên lực áp chế, sắc mặt âm trầm.","importance":"bridge","nguon":["@c0421"]},{"chuong":"@c0421","tieuDe":"Lần đầu thần trí mê muội, sa ảo mộng","text":"Sinh tử luân hồi ý cảnh Anh Biến sơ kỳ của Vương Lâm bị ý cảnh Liễu Mi vượt xa, hắn không kháng cự nổi, lần đầu thần trí rơi vào mê muội và sa vào ảo cảnh dục ý của Thiên huyễn tình dục đạo.","importance":"major","nguon":["@c0421"]},{"chuong":"@c0421","tieuDe":"Tỉnh mộng, truyền tống rời đi","text":"Vương Lâm tỉnh khỏi giấc mộng, xuất hiện trên cánh đồng hoang trong Chu Tước Mộ với ánh mắt phức tạp, nhớ nữ tử dưới thân khiến lòng chấn động, rồi gác việc Liễu Mi lại.","importance":"bridge","nguon":["@c0421"]},{"chuong":"@c0421","tieuDe":"Vào Thiên nghịch không gian thăm Nguyên Anh Lý Mộ Uyển","text":"Vương Lâm sờ mi tâm tiến vào Thiên nghịch không gian, nơi Nguyên Anh của Lý Mộ Uyển đang chậm rãi tẩm bổ khôi phục và sẽ có ngày thức tỉnh.","importance":"major","nguon":["@c0421"]},{"chuong":"@c0422","tieuDe":"Tiến sâu Chu Tước Mộ","text":"Vương Lâm rời đi tiến sâu vào Chu Tước Mộ, nhắm thẳng linh sơn trung tâm nơi lưu Chu Tước Ấn và thi thể một đời Chu Tước Tử. Hắn thần thức tản ra né vô số Linh vật mệnh hồn ngày càng cường đại, có lúc phải dùng Thập Ức Tôn Hồn Phiên mới ứng phó.","importance":"bridge","nguon":["@c0422"]},{"chuong":"@c0422","tieuDe":"Phá giải cạm bẫy thủy mệnh hồn","text":"Tới khe hai núi cao chọc trời, Vương Lâm thấy vách đá ẩm ướt bất thường liền khoét lỗ mười thước, phát hiện bên trong khô ráo nên biết là giả và lập tức lui khỏi đường nhỏ. Hơn mười vạn giọt nước (mỗi giọt một mệnh hồn) ngưng thành nữ tử thủy mệnh hồn Hóa Thần kỳ cảnh cáo cấm vào; hắn chậm rãi lui ra.","importance":"major","nguon":["@c0422"]},{"chuong":"@c0423","tieuDe":"Phát hiện mệnh hồn Lý Mộ Uyển","text":"Vương Lâm buông thần thức vào thung lũng, cảm giác tâm thần tương liên với một thuỷ mệnh hồn nữ tử; nhận ra đó là mệnh hồn Uyển nhi (Lý Mộ Uyển) trong Thiên Nghịch Châu nơi mi tâm hắn đang yếu ớt kêu gọi, liền không do dự xông vào sơn cốc.","importance":"normal","nguon":["@c0423"]},{"chuong":"@c0423","tieuDe":"Phân nguyên thần phong ấn thuỷ mệnh hồn","text":"Bị nữ tử thuỷ mệnh hồn cản đường, Vương Lâm ném kiếm tiên xuyên ngực nàng, nguyên thần phân từ một thành vô số chui vào mỗi giọt nước hô Phong! cấm chỉ phong ấn toàn bộ.","importance":"major","nguon":["@c0423"]},{"chuong":"@c0423","tieuDe":"Đối đầu Tiên Di Chi, xuất Thập Ức Tôn Hồn Phiên","text":"Vương Lâm gặp Tiên Di Chi (lão già lưng còng từng đuổi giết hắn), chém kiếm phá vòng phù văn rồi xuất Thập Ức Tôn Hồn Phiên cao ba trượng, thả Kỳ Lân tím vàng cùng hơn mười Chủ Hồn Anh Biến kỳ và trăm ngàn hồn phách khiến lão kinh hoảng bỏ chạy.","importance":"major","nguon":["@c0423"]},{"chuong":"@c0423","tieuDe":"Vây khốn và ép thuỷ mệnh hồn hoá nước","text":"Vương Lâm phá vòng phù văn cứu rồi gom Chủ Hồn vây nữ tử thuỷ mệnh hồn giống Lý Mộ Uyển; niệm Tôn Hồn Phiên dung! gom còn sáu Chủ Hồn vượt Anh Biến kỳ rồi hô Giết, ép nữ tử hoá thành hơi nước để lộ mệnh hồn.","importance":"major","nguon":["@c0423"]},{"chuong":"@c0423","tieuDe":"Đoạt giọt nước mệnh hồn Lý Mộ Uyển giữa kiếp sụp đổ","text":"Khi Chu Tước Mộ động đất sụp đổ và vô số khe thứ nguyên xuất hiện, Vương Lâm xuyên qua khe bắt lấy giọt nước trong suốt chứa mệnh hồn Lý Mộ Uyển, suýt mất mạng, bị cắn mất một mảng góc áo rồi thoát khỏi thung lũng.","importance":"major","nguon":["@c0423"]},{"chuong":"@c0423","tieuDe":"Cất mệnh hồn và chứng kiến Tiên Di Chi chết","text":"Vương Lâm đặt mệnh hồn Lý Mộ Uyển vào mi tâm dung nhập Thiên Nghịch không gian; trên đường bay thấy nguyên thần Tiên Di Chi (mất nửa thân) chạy trốn rồi bị khe thứ nguyên cắn nuốt tan biến, sau đó than nhẹ bay đi.","importance":"major","nguon":["@c0423"]},{"chuong":"@c0425","tieuDe":"Phát hiện kỳ bảo trung tâm hố trũng","text":"Vương Lâm thần thức quét vùng hố trũng trong Chu Tước Mộ, chấn động cảm nhận tại hố trũng trung tâm có cỗ kiếm khí bá đạo quen thuộc giống vật hắn từng thấy ở Tiên giới, kinh ngạc vì sao nơi này lại có bảo vật như thế.","importance":"normal","nguon":["@c0425"]},{"chuong":"@c0425","tieuDe":"Triệu hồi Hứa Lập Quốc mở đường","text":"Khi bị một thanh kiếm bạc xông tới quát đuổi, Vương Lâm triệu hồi kiếm hồn Hứa Lập Quốc; mọi bảo kiếm trong các hố trũng đều e ngại Hứa Lập Quốc mà tháo chạy về trung tâm, mở đường cho hắn tiến vào.","importance":"bridge","nguon":["@c0425"]},{"chuong":"@c0425","tieuDe":"Ép Hứa Lập Quốc xông vào, loan đao lộ diện","text":"Tới gần trung tâm, Vương Lâm ném Hứa Lập Quốc nhát gan ép xông vào đám bảo kiếm; tiếng kiếm minh tách ra một thông đạo, một thanh loan nguyệt đao bay ra từ sương thâm lam khiến hắn thoạt thất vọng vì tưởng là kỳ bảo Tiên giới.","importance":"bridge","nguon":["@c0425"]},{"chuong":"@c0425","tieuDe":"Nhận ra đao hồn là một mệnh hồn duy nhất","text":"Vương Lâm sửng sốt nhận ra đao hồn này chỉ do MỘT mệnh hồn tạo thành, khác hẳn mọi Linh vật trong Chu Tước Mộ vốn ngưng tụ từ nhiều mệnh hồn; loan đao khiến vô số kiếm hồn thần phục như thần tử bái thiên tử.","importance":"bridge","nguon":["@c0425"]},{"chuong":"@c0425","tieuDe":"Giao chiến đo sức loan đao rồi rút chạy","text":"Vương Lâm chém kiếm tiên va chạm loan đao, ước lượng lực công kích loan đao không kém một kích toàn lực Anh Biến hậu kỳ, nếu không dùng Thập Ức Tôn Hồn Phiên thì không địch nổi; hắn bung Tôn Hồn Phiên hoá khói đen, thuấn di đào thoát giữa vô số bảo kiếm truy kích.","importance":"major","nguon":["@c0425"]},{"chuong":"@c0425","tieuDe":"Gặp lại Chu Vũ Thái và nữ tử che khăn","text":"Trong lúc rượt đuổi, Vương Lâm gặp lại Chu Vũ Thái và một nữ tử che khăn đen mà hắn nhận ra thân phận; cả hai sợ hãi tháo chạy, ba người dàn thành thế Chu Vũ Thái trước - Vương Lâm giữa - kiếm quang sau.","importance":"normal","nguon":["@c0425"]},{"chuong":"@c0425","tieuDe":"Rượt đuổi sinh tử hướng Linh Sơn, bị thương","text":"Loan đao ra khỏi vùng hố trũng tốc độ tăng mấy chục lần lao thẳng tới; Vương Lâm liên tục thuấn di chạy về phía Linh Sơn ánh sáng bảy màu theo lời Tư Đồ Nam, bị thương cánh tay trái rồi chân phải phải tự trị thương, nhận định nếu bị trảm lần nữa có thể đầu rơi.","importance":"bridge","nguon":["@c0425"]},{"chuong":"@c0426","tieuDe":"Mất Hứa Lập Quốc vào thanh loan đao","text":"Vương Lâm giao tranh với thanh loan đao (mệnh hồn cường đại) ngày càng khó theo kịp, hiểu vì sao Chu Tước Tử e dè hồn phách thứ tư. Hắn xuất kiếm tiên đánh văng Hứa Lập Quốc ra, để loan đao cuốn đi, lấy Hứa Lập Quốc (tâm linh tương thông) làm căn cứ truy tìm thu phục mệnh hồn về sau.","importance":"major","nguon":["@c0426"]},{"chuong":"@c0426","tieuDe":"Gặp lại Hồng Điệp tiều tụy","text":"Vương Lâm nhắm tới Linh Sơn thì phát hiện Hồng Điệp cô độc trên núi, mắt trống rỗng do bị Kiền Phong khống chế. Hồi tưởng nàng từng là đại thiên kiêu Tuyết Vực quốc, đối thủ xứng đáng, hắn thầm thở dài.","importance":"normal","nguon":["@c0426"]},{"chuong":"@c0426","tieuDe":"Kiền Phong xúi chiến rồi bỏ đi","text":"Kiền Phong (gọi hắn là Tằng Ngưu) từ hư vô hẹn tái kiến trên Linh Sơn, xúi Hồng Điệp giết Vương Lâm rồi lao về Linh Sơn tìm mệnh hồn.","importance":"bridge","nguon":["@c0426"]},{"chuong":"@c0426","tieuDe":"Chặn trường kiếm đỏ, nghe lời cầu chết","text":"Hồng Điệp khai chiến phóng trường kiếm đỏ đâm mi tâm; Vương Lâm lui lại vỗ Cấm Phiên dựng cấm chỉ phòng hộ chặn được. Hắn nghe nàng thốt yếu ớt cầu Giết ta — một tia thần trí thà chết chứ không chịu tù túng.","importance":"bridge","nguon":["@c0426"]},{"chuong":"@c0426","tieuDe":"Ngưng tụ trường thương đâm Hồng Điệp","text":"Dù do dự, Vương Lâm vẫn dùng Cấm Phiên ngưng tụ trường thương ba trượng toả hắc khí, đâm một thương gào rít vang xa. Hồng Điệp mặc giáp băng đỏ hiện như chiến tiên, rút ra roi đen.","importance":"bridge","nguon":["@c0426"]},{"chuong":"@c0430","tieuDe":"Hoàn thành lời dặn Vân Tước Tử","text":"Vương Lâm báo với Vân Tước Tử rằng việc tiền bối dặn năm đó hắn đã hoàn thành toàn bộ, rồi tới một góc khoanh chân ngồi xuống. Hắn không hứng thú tìm hiểu cách Vân Tước Tử vào được nơi chứa đám tượng gỗ này.","importance":"bridge","nguon":["@c0430"]},{"chuong":"@c0430","tieuDe":"Từ bỏ Tu Tinh tinh","text":"Vương Lâm từ bỏ ý định đoạt Tu Tinh tinh, chỉ muốn thu hồi mệnh hồn của mình, không nỡ vì dục vọng cá nhân mà hy sinh toàn bộ sinh mệnh Chu Tước Tinh. Nhưng với kẻ thù thì tàn nhẫn — năm xưa hắn từng tiêu diệt toàn tộc Đằng gia.","importance":"bridge","nguon":["@c0430"]},{"chuong":"@c0430","tieuDe":"Đối chọi ánh mắt với Kiền Phong","text":"Vương Lâm đảo mắt đối chọi với Kiền Phong giữa không trung, khoé miệng lộ tia lạnh rồi thu về. Hắn nhìn thoáng người mang mặt nạ xa lạ nhưng không để tâm, rồi chăm chú nhìn một lão già có nụ cười quỷ dị khiến hắn cảm giác bị uy hiếp và quen thuộc.","importance":"bridge","nguon":["@c0430"]},{"chuong":"@c0430","tieuDe":"Liễu Mi khích đạo tâm, bị doạ giết","text":"Liễu Mi đáp xuống đỉnh Linh Sơn, tiến lại gần liền bị Vương Lâm lạnh lùng cảnh cáo đừng đến gần. Khi nàng nhắc tên Lý Mộ Uyển — vảy ngược của hắn — để thử phá đạo tâm, Vương Lâm nổi sát khí mắng nàng cút và doạ giết; nếu không phải lúc, hắn đã xuất Tôn Hồn Phiên giết nàng.","importance":"bridge","nguon":["@c0430"]},{"chuong":"@c0430","tieuDe":"Nhận ra lão già là Thác Lâm","text":"Nhờ cảm ứng huyền diệu của Anh Biến sơ kỳ tu sĩ, Vương Lâm xác định lão già âm trầm chính là Thác Lâm — ma niệm sinh từ Cổ Thần Đồ Ti, kẻ hắn từng trêu chọc khi mới Kết Đan tiến vào Cổ Thần chi địa.","importance":"major","nguon":["@c0430"]},{"chuong":"@c0430","tieuDe":"Thân phận tam tinh Cổ Thần qua ký ức truyền thừa","text":"Vương Lâm có ký ức truyền thừa Đồ Ti nên đạt tam tinh Cổ Thần, biết khẩu quyết hơn mười thần thông huỷ diệt tinh cầu nhưng chưa đủ thực lực (cần thất tinh) để vận dụng. Thác Lâm giữ lực lượng bát tinh nhưng chỉ phát huy được tới năm tinh, khao khát đoạt ký ức của hắn.","importance":"major","nguon":["@c0430"]},{"chuong":"@c0434","tieuDe":"Đòi ngọc giản đặt cọc","text":"Bị Vân Tước Tử dụ rút mệnh hồn từ tinh dẫn với lời hứa tế đàn viễn tổ, Vương Lâm bình tĩnh nắm Thập Ức Tôn Hồn Phiên, đòi và nhận ngọc giản phương pháp dùng mũ rơm làm vật đặt cọc rồi hóa cầu vồng bay lên tháp.","importance":"bridge","nguon":["@c0434"]},{"chuong":"@c0434","tieuDe":"Lật kèo, kích Hồn Phiên","text":"Tới trước Diệp Vô Ưu, Vương Lâm phát hiện mình đứng cạnh tử quang mà không có bóng nên quyết đánh cuộc; tuyên bố thất vọng với Vân Tước Tử rồi kích Thập Ức Tôn Hồn Phiên thả vô số hồn phách tấn công cái bóng sau Diệp Vô Ưu.","importance":"normal","nguon":["@c0434"]},{"chuong":"@c0434","tieuDe":"Bỏ tranh đoạt, rút lui","text":"Khi Tu Tinh Chi Tinh thật lộ diện, Vương Lâm ở xa cắn răng không tham gia tranh đoạt, dùng Hồn Phiên bao thân bay về thông đạo để chạy — quyết định đúng khi lão già âm trầm vừa ôm tinh thạch liền bị phản phệ hóa bụi.","importance":"normal","nguon":["@c0434"]},{"chuong":"@c0435","tieuDe":"Bị Tu Tinh Chi Tinh truy đuổi","text":"Tu Tinh Chi Tinh bỏ qua con khỉ nhỏ và Vân Tước Tử, nhằm thẳng Vương Lâm. Hắn xoay người chạy vào thông đạo, dùng Tôn Hồn phiên bao phủ toàn thân tăng tốc nhưng tinh thạch như có linh tính bám theo đuổi tận giết tuyệt.","importance":"bridge","nguon":["@c0435"]},{"chuong":"@c0435","tieuDe":"Trải nghiệm truyền thừa Chu Tước Ấn","text":"Một luồng lực kì dị từ tinh thạch chui vào cơ thể qua cánh tay phải, phù văn kỳ dị nổ vang trong đầu Vương Lâm, hóa thành ký ức Diệp Vô Ưu lĩnh Chu Tước Ấn tại Tiên Ấn Phủ. Hồng quang dưới chân khuếch tán làm tốc độ hắn tăng vọt phi thường, khí tức Chu Tước Ấn tỏa ra khiến Vân Tước Tử kinh hãi.","importance":"major","nguon":["@c0435"]},{"chuong":"@c0435","tieuDe":"Chịu đau kế thừa rồi từ chối làm Chu Tước phong hào","text":"Vương Lâm chịu đau như hồn phách bị khắc, gào thét, hồng quang bao phủ lao ra lòng biển. Khi thanh âm uy nghiêm hỏi có nguyện trở thành Chu Tước phong hào thủ hộ Chu Tước Tinh, hắn đáp Không muốn; hồng quang biến mất, truyền thừa ngưng tụ trở lại thành tinh thạch trên tay phải.","importance":"major","nguon":["@c0435"]},{"chuong":"@c0435","tieuDe":"Biết cách thu hồi mệnh hồn","text":"Qua một phù văn quỷ dị, Vương Lâm minh bạch muốn thu hồi mệnh hồn từ Tu Tinh Chi Tinh phải một mạng đổi một mạng, hoặc chờ mệnh hồn bị linh vật hấp thu rồi giết linh vật đoạt lại. Hắn xác định vật này không liên quan Cực Cảnh.","importance":"bridge","nguon":["@c0435"]},{"chuong":"@c0435","tieuDe":"Ném tinh thạch về phía Kiền Phong & Liễu Mi","text":"Vương Lâm ném tinh thạch ra hô đây là Tu Tinh Chi Tinh, nhằm vị trí Kiền Phong và Liễu Mi, khiến Vân Tước Tử lao đến giành và buộc Kiền Phong phải tế Đồng nhân.","importance":"bridge","nguon":["@c0435"]},{"chuong":"@c0435","tieuDe":"Xuất thủ quyết giết Kiền Phong & Liễu Mi","text":"Vương Lâm chộp lấy Thập Ức Tôn Hồn Phiên, dung hợp sáu chủ hồn (gồm tàn hồn đầu kỳ lân), rút chiến phủ bay lên chém xuống và ném phá tan Chu Tước Trùy của Kiền Phong, khiến Kiền Phong mở Chu Tước huyền trận ứng chiến.","importance":"bridge","nguon":["@c0435"]},{"chuong":"@c0438","tieuDe":"Bị Thác Sâm truy sát, Chiến Phủ bị phá","text":"Phân thức hư ảnh Thác Sâm (có máu Cổ Thần) đuổi theo định thôn phệ ký ức truyền thừa của Vương Lâm; Vương Lâm dùng Chiến Phủ bổ ra lưỡi phủ hơn mười trượng nhưng bị Thác Sâm điểm tan vỡ.","importance":"major","nguon":["@c0438"]},{"chuong":"@c0438","tieuDe":"Dung hợp linh hồn Vấn Đỉnh chạy trốn","text":"Vương Lâm rung Thập Ức Tôn Hồn Phiên, hô Dung để toàn bộ hồn phách hợp thành một linh hồn Vấn Đỉnh sơ kỳ hòng dùng tốc độ chạy trốn, nhưng bị Thác Sâm dùng vòng xoáy hấp lực kéo lại ngoài trăm trượng.","importance":"bridge","nguon":["@c0438"]},{"chuong":"@c0438","tieuDe":"Kích Pháp quyết toái diệt","text":"Trước cảm giác tử vong, Vương Lâm cho linh hồn Vấn Đỉnh kết ấn quyết và hô Vỡ, kích toàn bộ linh hồn trong Thập Ức Tôn Hồn Phiên tự bạo dồn vào Thác Sâm, uy lực hủy thiên diệt địa làm Thác Sâm bị thương; Thập Ức Hồn Phiên bị hủy, tu vi Vương Lâm chỉ còn Anh Biến sơ kỳ.","importance":"major","nguon":["@c0438"]},{"chuong":"@c0438","tieuDe":"Được Mặc Trí cứu, lộ thân phận cố nhân","text":"Sứ Giả Tu Chân Liên Minh đeo mặt nạ xuất hiện Phong ấn cắt đứt phân thức Thác Sâm, sau đó tháo mặt nạ gọi Vương Lâm là Đại Ngưu huynh — chính là Mặc Trí năm xưa bàn đạo sinh tử ở Cổ Miếu.","importance":"bridge","nguon":["@c0438"]},{"chuong":"@c0438","tieuDe":"Từ chối làm Chu Tước","text":"Mặc Trí hỏi vì sao Vương Lâm từ chối làm Chu Tước, Vương Lâm đáp chí hướng của hắn không dừng ở Chu Tước.","importance":"bridge","nguon":["@c0438"]},{"chuong":"@c0438","tieuDe":"Đối đầu Tử Tâm, dùng kế ép chùn","text":"Vương Lâm nhận ra Tử Tâm là Lô Đỉnh của Kiền Phong (kẻ hắn đã giết) và gợi ý chuyện quái dị có kẽ hở; khi Tử Tâm (Anh Biến trung kỳ) đe dọa giết, Vương Lâm ngụ ý nếu mình trở thành Chu Tước khiến Tử Tâm chùn lại vì Chu Tước Ấn có thể giết nàng.","importance":"major","nguon":["@c0438"]},{"chuong":"@c0439","tieuDe":"Nhường chức Chu Tước cho Chu Vũ Thái","text":"Dưới thân phận Đại Ngưu/Tằng Ngưu, Vương Lâm từ chối làm Chu Tước Tử, chỉ định Chu Vũ Thái tiếp nhận; Mặc Trí đồng ý, phong Chu Vũ Thái làm đệ thập ngũ Chu Tước.","importance":"bridge","nguon":["@c0439"]},{"chuong":"@c0439","tieuDe":"Nhận ấn ký đỏ của Mặc Trí","text":"Vương Lâm ôm quyền tạ ơn Mặc Trí, nói còn chút chuyện cần xử lý trong Chu Tước mộ; Mặc Trí để lại một đạo ấn ký màu đỏ để dùng tiên lực ngưng tụ đưa hắn ra ngoài.","importance":"bridge","nguon":["@c0439"]},{"chuong":"@c0439","tieuDe":"Toan tính nhường Chu Tước tinh","text":"Vương Lâm nghĩ mệnh hồn của mình và Lý Mộ Uyển đều đã có; để Chu Tước tinh cho Chu Vũ Thái vì hắn có ơn lớn, sẽ chăm sóc những người thân của Vương Lâm khi hắn rời đi.","importance":"bridge","nguon":["@c0439"]},{"chuong":"@c0439","tieuDe":"Thu ba chủ hồn, quyết giết Liễu Mi","text":"Vương Lâm gặp ba đạo hắc mang hóa ba Chủ Hồn (gồm Kỳ Lân tàn hồn), vung Hồn Phiên cuộn vào trong; quyết khi rời đi nhất định giết Liễu Mi vì nàng liên thủ Kiền Phong định dồn hắn vào chỗ chết.","importance":"normal","nguon":["@c0439"]},{"chuong":"@c0439","tieuDe":"Tổn thất Hồn Phiên, lập mục tiêu tìm loan đao","text":"Vương Lâm tổng kết Thập Ức Hồn Phiên chỉ còn ba chủ hồn, uy lực giảm nhiều; xác định Tu Tinh Chi Tinh liên quan lớn đến tiến hóa Cực Cảnh, lập mục tiêu tìm Hứa Lập Quốc lấy cây loan đao rồi hóa khói xanh rời Chu Tước tinh.","importance":"bridge","nguon":["@c0439"]},{"text":"Vương Lâm về Triệu Quốc bế quan đúng một năm, lành hẳn vết thương ở Chu Tước mộ, tu vi tinh tiến chút ít và củng cố vững thêm Anh Biến sơ kỳ.","nguon":["@c0440"],"bridge":true,"khoang":"@c0440","importance":"major"},{"chuong":"@c0440","tieuDe":"Từ chối nghi lễ phong hào","text":"Bảy ngày trước, Vương Lâm khéo léo từ chối thiệp mời dự nghi lễ phong hào của Chu Vũ Thái ở Chu Tước Quốc.","importance":"bridge","nguon":["@c0440"]},{"chuong":"@c0440","tieuDe":"Loan đao Lão Tứ và Hứa Lập Quốc","text":"Vương Lâm thả tiên kiếm cùng loan đao ra; Hứa Lập Quốc khoe đã thuần phục loan đao Lão Tứ tìm được ở Chu Tước mộ. Hắn vẫn chưa điều khiển được loan đao, tự nhận không phải đối thủ của nó.","importance":"normal","nguon":["@c0440"]},{"chuong":"@c0440","tieuDe":"Manh mối Tang Viên thôn","text":"Tư Đồ Nam báo cho Vương Lâm manh mối hắn nhờ kiểm tra: Tang Viên thôn ngoài Phượng Hoàng thành của Sở Quốc; hẹn khi rời đi sẽ cùng nhau đi.","importance":"bridge","nguon":["@c0440"]},{"chuong":"@c0440","tieuDe":"Chuẩn bị đi Thiên Vận tinh","text":"Vương Lâm dự định tế luyện lại các pháp bảo trong túi trữ vật trước khi rời Chu Tước tinh đi Thiên Vận tinh, con đường phía trước mờ mịt.","importance":"bridge","nguon":["@c0440"]},{"chuong":"@c0440","tieuDe":"Đưa Chu Như về nhà, dứt duyên phận","text":"Nhìn Chu Như đã trưởng thành mà nhớ tới Lý Mộ Uyển, Vương Lâm quyết đưa nàng về với cha mẹ, dặn dò đạo hiếu và nói duyên phận hai người đã hết; Chu Như đau buồn rơi lệ, Tiểu Bạch quyết đuổi theo.","importance":"bridge","nguon":["@c0440"]},{"chuong":"@c0442","tieuDe":"Viếng linh vị từ biệt cha mẹ","text":"Vương Lâm trở về tổ trạch Vương gia dưới chân Hằng Nhạc phái ở Triệu Quốc, đứng bất động ba ngày ba đêm trước linh vị cha mẹ, ký ức cuồn cuộn, rơi hai dòng lệ rồi quỳ dập đầu lẩm bẩm phải đi.","importance":"bridge","nguon":["@c0442"]},{"chuong":"@c0442","tieuDe":"Vương gia tiễn chân, rời Chu Tước tinh","text":"Vương Trác dẫn hơn trăm con cháu Vương gia quỳ tiễn; Vương Lâm dặn dò giao phó gia tộc, nhắc đã qua sáu trăm năm, rồi đạp một bước biến mất, kết thúc giai đoạn ở Chu Tước tinh.","importance":"bridge","nguon":["@c0442"]},{"chuong":"@c0442","tieuDe":"Tế luyện bốn vỏ kiếm","text":"Trên cánh đồng hoang phía đông Chu Tước tinh, Vương Lâm khoanh chân thổi khí Nguyên Thần bọc bốn vỏ kiếm; ba ngày sau thiết lập liên hệ ngày càng chặt với nội tâm rồi thu hồi.","importance":"major","nguon":["@c0442"]},{"chuong":"@c0442","tieuDe":"Khuất phục Côn Cực Tiên","text":"Vương Lâm dùng thần thức Vấn Đỉnh Chu Dật trong bảo tháp cùng Nguyên thần, suốt bảy ngày xóa được đạo thần thức cũ trên Côn Cực Tiên và lưu dấu ấn của mình, thu phục được tiên bảo.","importance":"major","nguon":["@c0442"]},{"chuong":"@c0442","tieuDe":"Phát hiện bí ẩn tiên lực Côn Cực Tiên","text":"Vương Lâm xác định Côn Cực Tiên là Tiên Bảo ngưng tụ tiên lực nhưng uy lực quỷ dị, không cần linh lực vẫn ẩn chứa lực lượng kỳ dị; trận pháp bên trong sinh cấm chế giúp nâng hiệu quả Cấm Phiên hướng tới mục tiêu 9999 cấm chế.","importance":"normal","nguon":["@c0442"]},{"chuong":"@c0443","tieuDe":"Thu hồi Côn Cực Tiên và bức tranh thần bí","text":"Vương Lâm cảm thấy cây roi Côn Cực Tiên (vốn của Sở Vân Phi) kỳ dị nên thu hồi, đồng thời lật ra một bức tranh pháp bảo thần bí ngang Nghịch Thiên châu; hắn nhận định cả hai đều cực thần bí.","importance":"bridge","nguon":["@c0443"]},{"chuong":"@c0443","tieuDe":"Vất vả thu phục Chiến Hồn vào Khu Thú Quyển","text":"Suốt nửa tháng Vương Lâm dốc toàn lực nhốt Chiến Hồn cuồng ngạo không khuất phục vào Khu Thú Quyển, khiến quyển xuất hiện vết nứt, bản thân cạn sạch tiên lực và suýt bỏ mạng.","importance":"bridge","nguon":["@c0443"]},{"chuong":"@c0443","tieuDe":"Tự đánh giá thực lực còn yếu","text":"Sau khi hấp thu tiên lực qua tiên ngọc phục hồi, Vương Lâm nhận định mình đủ đối phó Anh Biến trung/hậu kỳ nhưng thua tiên bảo và tu sĩ Vấn Đỉnh; hắn cảm thán còn quá yếu và biết Thiên Vận tinh mạnh hơn Chu Tước tinh nhiều.","importance":"major","nguon":["@c0443"]},{"chuong":"@c0443","tieuDe":"Đón Tư Đồ Nam rời Chu Tước tinh","text":"Vương Lâm cưỡi Văn Thú đến đô thành Chu Quốc đêm khuya gọi Tư Đồ Nam, rồi cùng bay qua Đoạn Cương Phong; Tư Đồ Nam xé toạc luồng gió mở đường, hai người rời khỏi Chu Tước tinh hướng Thiên Vận tinh.","importance":"normal","nguon":["@c0443"]},{"chuong":"@c0445","tieuDe":"Tư Đồ Nam rèn luyện một tháng","text":"Trong tình huống không dùng pháp bảo, Vương Lâm không địch lại Tư Đồ Nam nên bị lão (nâng tu vi lên Vấn Đỉnh sơ kỳ) bắt chuyên tránh né và chạy trốn suốt một tháng; nhờ cơ thể đạt tam tinh Cổ Thần sau khi dung hợp bản tôn nên không liên tục trọng thương, thu được nhiều tiến bộ.","importance":"bridge","nguon":["@c0445"]},{"chuong":"@c0445","tieuDe":"Đến Giao Dịch Tinh","text":"Vương Lâm theo Tinh La Bàn đến Giao Dịch Tinh; sau khi Tư Đồ Nam đuổi ba đạo cầu vồng rồi rời đi (hẹn ba ngày sau quay lại), hắn thu hồi Tinh La Bàn, hóa làn khói xanh bay xuống đất liền và dùng thần thức quét vạn trượng phát hiện Minh Hồng thành.","importance":"normal","nguon":["@c0445"]},{"chuong":"@c0445","tieuDe":"Vào Minh Hồng thành tìm Khôn Mộc Thạch","text":"Vương Lâm đưa linh thạch vào thành qua cửa Đông để mua hai loại vật liệu sửa Tinh La Bàn; phát hiện Lý Đan Nam đi theo, hắn thuê y dẫn đường với mười khối thượng phẩm linh thạch và hỏi mua Khôn Mộc Thạch, rồi yêu cầu dẫn vào phường thị tự do phía tây.","importance":"normal","nguon":["@c0445"]},{"chuong":"@c0446","tieuDe":"Mua Khôn Mộc Thạch, phá Khốn Phong Chú","text":"Được Lý Đan Nam dẫn vào phường thị tự do tây Minh Hồng thành, Vương Lâm tới cửa hàng Trương Hóa Lâm hỏi mua Khôn Mộc Thạch. Hắn vung tay phá vỡ Khốn Phong Chú trong nháy mắt, trả đủ năm khối cực phẩm linh thạch rồi rời đi.","importance":"normal","nguon":["@c0446"]},{"chuong":"@c0446","tieuDe":"Cảm nhận ba luồng ánh mắt theo dõi","text":"Sau khi đoạt được Khôn Mộc Thạch, Vương Lâm cảm thấy ba luồng ánh mắt như tia chớp nhắm vào mình; nghe Lý Đan Nam lý giải cơ chế nguy hiểm khi giao dịch và nhớ lại từng bị truy sát ở Tu Ma Hải.","importance":"normal","nguon":["@c0446"]},{"chuong":"@c0446","tieuDe":"Hỏi Mặc Tuyết Dịch, hướng tới Thương Thị","text":"Vương Lâm hỏi nơi bán Mặc Tuyết Dịch nhưng Lý Đan Nam chưa từng nghe, bèn dẫn hắn tới cửa hàng Thương Thị lớn nhất ở thành bắc Minh Tư thành.","importance":"normal","nguon":["@c0446"]},{"chuong":"@c0446","tieuDe":"Một quyền phế tiên cơ người hầu áo lam","text":"Bị thanh niên áo lam ngăn cản trước cửa hàng, Vương Lâm dùng tốc độ cực nhanh vọt qua trăm trượng, một quyền làm nứt không gian và phế tiên cơ tên người hầu, khiến tu vi hắn tụt từ rìa Anh Biến về Hóa Thần kỳ.","importance":"major","nguon":["@c0446"]},{"chuong":"@c0446","tieuDe":"Thi triển Tinh Chuyển hóa giải chén trà Bạch Vi","text":"Khi Bạch Vi ném chén trà chứa tiên lực khổng lồ, Vương Lâm bấm pháp quyết thi triển Tinh Chuyển tạo vòng tròn tiên lực làm chén trà chệch hướng. Hắn đối thoại nhã nhặn với Bạch Vi (Thiên Vận Tông), tự nhận là kẻ lưu lạc không môn phái.","importance":"bridge","nguon":["@c0446"]},{"chuong":"@c0446","tieuDe":"Vào cửa hàng Thương Thị hỏi Mặc Tuyết Dịch","text":"Vương Lâm xuyên qua hai người tiến vào cung điện linh khí nồng đậm, gặp nữ tử áo trắng đeo đầy pháp bảo và hỏi thẳng nơi đây có Mặc Tuyết Dịch không.","importance":"normal","nguon":["@c0446"]},{"chuong":"@c0447","tieuDe":"Mặc Tuyết Dịch quá đắt","text":"Vương Lâm trả Lý Đan Nam mười viên thượng phẩm linh thạch rồi rời cửa hàng nhà họ Thương ở Minh Mân Thành. Hắn phát hiện Mặc Tuyết Dịch (vật tẩm bổ nguyên thần thượng hạng) giá quá cao, toàn bộ linh thạch chỉ đổi được hai ba phần.","importance":"major","nguon":["@c0447"]},{"chuong":"@c0447","tieuDe":"Nhờ Tư Đồ Nam ra tay","text":"Vương Lâm tìm vách núi ngoài Minh Mân Thành tĩnh tọa, tản thần thức gọi Tư Đồ Nam, yêu cầu lấy Mặc Tuyết Dịch trong cửa hàng nhà họ Thương.","importance":"bridge","nguon":["@c0447"]},{"chuong":"@c0447","tieuDe":"Tẩu thoát vào tinh không","text":"Đêm ngày thứ ba, Vương Lâm đội mũ rơm chờ trên vách núi; Tư Đồ Nam lao tới chụp hắn mang bay xuyên khí quyển vào tinh không. Vương Lâm lấy ra Tinh La Bàn, hai người bay nhanh thoát khỏi truy binh.","importance":"bridge","nguon":["@c0447"]},{"chuong":"@c0447","tieuDe":"Nhận Mặc Tuyết Dịch","text":"Tư Đồ Nam đưa Vương Lâm một bình nhỏ chứa khá nhiều Mặc Tuyết Dịch. Vương Lâm thầm quyết định ngày sau cũng sẽ đi cướp đoạt một phen.","importance":"normal","nguon":["@c0447"]},{"chuong":"@c0447","tieuDe":"Chia tay & khấu đầu tiễn biệt","text":"Tại đám tinh vân hình con sứa, Vương Lâm chia tay Tư Đồ Nam (về Phượng Loan Tinh) để một mình hướng Thiên Vận Tinh. Coi Tư Đồ Nam như sư phụ, Vương Lâm quỳ trên Tinh La Bàn khấu đầu, tuyên bố cả đời chỉ bái cha mẹ và kính Tư Đồ Nam, rồi bay về hướng đông.","importance":"bridge","nguon":["@c0447"]},{"chuong":"@c0448","tieuDe":"Rời Chu Tước Tinh","text":"Theo Tinh Đồ của Thiên Vận Tử, Vương Lâm ngồi Tinh La Bàn bay vào tinh không hướng đến Thiên Vận Tinh; Tư Đồ Nam tiễn biệt rồi biến mất.","importance":"bridge","nguon":["@c0448"]},{"chuong":"@c0448","tieuDe":"Tế luyện Tinh La Bàn thành ngân long Thu Hác","text":"Trên đường đi, Vương Lâm dùng phương pháp luyện khí cổ thần cùng Khôn Mộc Thạch và Mặc Tuyết Dịch tế luyện lại Tinh La Bàn, hơn nửa năm biến nó thành con ngân long hình viễn cổ yêu thú Thu Hác có tốc độ gần ngang Vấn Đỉnh tu sĩ.","importance":"bridge","nguon":["@c0448"]},{"chuong":"@c0448","tieuDe":"Đánh bại biên duyên tu sĩ, gây uy danh","text":"Trong hành trình tinh không, Vương Lâm đánh trọng thương một biên duyên tu sĩ đui mù cảnh Anh Biến Sơ Kỳ, sau đó phát sát khí bổn tôn ngợp trời khiến các biên duyên tu sĩ khác đều tránh né. Da hắn dần ngăm đen do sức mạnh kỳ dị trong tinh không.","importance":"major","nguon":["@c0448"]},{"chuong":"@c0448","tieuDe":"Nhìn thấy Thiên Vận Tinh","text":"Sau khoảng hai năm tổng hành trình, Vương Lâm tới được tinh vực Thiên Vận Tinh — tinh cầu tím sẫm cực lớn linh lực vô biên; tâm thần chấn động, tự nhủ Thiên Vận Tinh, Vương Lâm ta đến đây.","importance":"bridge","nguon":["@c0448"]},{"chuong":"@c0448","tieuDe":"Tách bổn tôn để lại đề phòng","text":"Vương Lâm lùi về một ngôi sao nhỏ hoang dã, tách phân thân và bổn tôn; bổn tôn ở lại thổ nạp vì sợ cao thủ Thiên Vận Tinh nhận ra đó là thân thể cổ thần, còn phân thân quay về Thiên Vận Tinh.","importance":"bridge","nguon":["@c0448"]},{"chuong":"@c0448","tieuDe":"Dừng trước màn sương trận pháp","text":"Phân thân Vương Lâm dừng bên ngoài màn sương xanh bao quanh Thiên Vận Tinh, cảm nhận dao động có tính hủy diệt nên chưa dám xâm nhập, nhận định đây là trận pháp cấm chế hùng mạnh chưa rõ tinh cấp.","importance":"bridge","nguon":["@c0448"]},{"chuong":"@c0449","tieuDe":"Qua cửa người gác","text":"Vương Lâm gặp thanh niên áo choàng lụa đen gác màn sương lối vào Thiên Vận Tinh; hắn nói được Thiên Vận Tử tiền bối mời, nhận đến từ Chu Tước Tinh, rồi hóa giải xúc tu giao long sương thành trường kiếm xanh để bước qua, được cho vào.","importance":"normal","nguon":["@c0449"]},{"chuong":"@c0449","tieuDe":"Tới Thiên Vận Tông, chấp nhận Tam Quan Chi Lễ","text":"Vương Lâm theo trường kiếm xanh bay vào Thiên Vận Tinh, tới sơn môn Thiên Vận Tông ở Thập Vạn Đại Sơn; bị một thanh âm chặn lại, được giải thích muốn nhập môn phải qua ba cửa Nhân/Địa/Thiên Chi Quan, hắn chấp nhận và bước vào vòng sáng.","importance":"bridge","nguon":["@c0449"]},{"chuong":"@c0449","tieuDe":"Vấn đạo cửa khảo đạo tâm, trụ 83 ngày","text":"Trong Nhân Chi Quan khảo đạo tâm, Vương Lâm gặp ảo ảnh Lý Mộ Uyển; thay vì tránh né hay cưỡng chế giải trừ, hắn tiến lên ôm lấy nàng chọn cách vấn đạo, trụ được tám mươi ba ngày, vượt kỷ lục 67 ngày của Tôn Vân.","importance":"normal","nguon":["@c0449"]},{"chuong":"@c0449","tieuDe":"Bị đại sư huynh ngầm hại","text":"Đại sư huynh khâm phục nhưng nổi sát ý, bấm quyết phóng luồng ánh sáng bảy màu can thiệp phá vỡ Nhân Chi Quan của Vương Lâm; đồng tử ảo cảnh vung dao khắc xuất ngân quang nghênh đón, gây tiếng nổ long trời.","importance":"bridge","nguon":["@c0449"]},{"chuong":"@c0450","tieuDe":"Hoàn thành vấn đạo Nhân Chi Quan","text":"Vương Lâm tu đạo luân hồi trong Nhân Chi Quan, sau 84 lần luân hồi điêu khắc thành công tượng gỗ nữ tử và hoàn thành vấn đạo; từ đồng tử bước ra hóa thành thanh niên áo trắng, ngộ ra phải đủ trăm năm luân hồi mới có thể vấn đạo, cả người biến hóa kỳ dị nhưng ẩn giấu kỹ.","importance":"bridge","nguon":["@c0450"]},{"chuong":"@c0450","tieuDe":"Đuổi kẻ dòm ngó trong Nhân Chi Quan","text":"Vương Lâm dùng tượng gỗ hóa thành thôn xóm rồi đốt cháy khôi phục tiên cảnh, lạnh lùng đuổi đôi mắt bảy màu dòm ngó hắn cút đi.","importance":"bridge","nguon":["@c0450"]},{"chuong":"@c0450","tieuDe":"Đánh bại đệ thập hộ tiên Địa Chi Quan","text":"Vào Địa Chi Quan, Vương Lâm bấm quyết Thái Cực quy nguyên hô Phá, một chiêu đánh thân ảnh lửa đỏ đệ thập hộ tiên lui hơn mười trượng, hai tay rỉ máu, rồi bảo đối phương lui ra.","importance":"bridge","nguon":["@c0450"]},{"chuong":"@c0450","tieuDe":"Chủ động bỏ qua Địa Chi Quan","text":"Nhận ra có người ngoài đang dòm ngó ba cửa ải, Vương Lâm cười khó hiểu rồi tuyên bố bỏ qua Địa Chi Quan để không lộ bản lãnh và rời đi.","importance":"bridge","nguon":["@c0450"]},{"chuong":"@c0450","tieuDe":"Thân phận và âm mưu Tử Vân Các","text":"Được tiết lộ là ký danh đệ tử của Thiên Vận Tử ở Chu Tước Tinh, Vương Lâm được sắp xếp ở Tử Vân Các — nơi bị ví như đặt người lên lửa; Bạch Vi nghe xong ánh mắt lạnh như băng và vội rời đi.","importance":"bridge","nguon":["@c0450"]},{"chuong":"@c0451","tieuDe":"Ngộ chữ đạo, bỏ qua Thiên Chi Quan","text":"Sau năm mươi mốt ngày tĩnh tọa trong Thiên Chi Quan, Vương Lâm ngộ ra chữ \"đạo\" và hiểu ba cửa ải Nhân–Địa–Thiên là cơ duyên ngộ đạo chứ không phải khảo nghiệm, liền tuyên bố bỏ qua khiến cảnh giới ảo tan biến.","importance":"bridge","nguon":["@c0451"]},{"chuong":"@c0451","tieuDe":"Bái nhập Thiên Vận Tông, Tử hệ","text":"Vương Lâm trở lại Thập Vạn Đại Sơn, được Triệu Tinh Sát tự xưng đại sư huynh đón và dẫn đường vào sơn môn Tử Tông, chính thức nhập Tử hệ — hệ yếu nhất trong bảy hàng đệ tử của Thiên Vận Tử.","importance":"bridge","nguon":["@c0451"]},{"chuong":"@c0451","tieuDe":"Thầm nhận diện Triệu Tinh Sát","text":"Ngay lần đầu gặp, Vương Lâm nhận ra Triệu Tinh Sát chính là kẻ phát luồng sáng bảy màu hắn gặp ở Nhân Chi Quan, song giữ tâm cơ thâm trầm không lộ sơ hở.","importance":"normal","nguon":["@c0451"]},{"chuong":"@c0451","tieuDe":"Bị nữ tử cấm tiếp cận Tử Vân Các","text":"Tới Tử Vân Các, Vương Lâm bị một nữ tử áo tím Anh Biến Sơ Kỳ cấm vào trong vòng trăm dặm; hắn hiện sát khí nhưng nhẫn nhịn không gây chuyện mà thu ánh mắt rời đi.","importance":"major","nguon":["@c0451"]},{"chuong":"@c0451","tieuDe":"Lập động phủ điều tra","text":"Cách Tử Vân Các trăm dặm, Vương Lâm dùng phi kiếm khoét động phủ trong vách núi, bố trí cấm chế, ngồi tĩnh tọa suy tư về những điểm bất thường của Thiên Vận Tông và bí ẩn Tử Vân Các.","importance":"bridge","nguon":["@c0451"]},{"chuong":"@c0452","tieuDe":"Trinh sát Tử Vân Các","text":"Trong màn đêm, Vương Lâm hóa thành làn khói đen lẻn vào Tử Vân Các ba tầng để dò xét, lục soát từ trong ra ngoài nhưng không tìm thấy manh mối gì.","importance":"bridge","nguon":["@c0452"]},{"chuong":"@c0452","tieuDe":"Nửa tháng bị cô lập","text":"Vương Lâm bị cầm chân trong Tử Tông nửa tháng, không ai tìm tới, đệ tử tránh né như tránh ôn thần, Thiên Vận Tử không triệu kiến và Triệu Tinh Sát biến mất.","importance":"bridge","nguon":["@c0452"]},{"chuong":"@c0452","tieuDe":"Hai chấp pháp trưởng lão ép phá động phủ","text":"Ngày thứ mười bảy, hai chấp pháp trưởng lão Anh Biến Sơ Kỳ tới buộc Vương Lâm phá động phủ và theo về đại điện định tội; hắn vỗ tay phá sập động phủ nhưng vẫn bị ép đi.","importance":"major","nguon":["@c0452"]},{"chuong":"@c0452","tieuDe":"Diệt trưởng lão thứ nhất","text":"Chịu hết bị gạt bỏ, Vương Lâm rút Côn Cực Tiên đánh bật nguyên thần lão già ra ba thước, dùng Cấm Phiên giăng thiên la địa võng chặn đường rồi bắt nguyên thần ném vào chuông đè xuống luyện hóa.","importance":"major","nguon":["@c0452"]},{"chuong":"@c0452","tieuDe":"Phá chiêu Thất Tinh Toái","text":"Lão già còn lại dùng trường kiếm tím vỡ bảy mảnh chiêu Thất Tinh Toái; Vương Lâm tung tiên kiếm chứa Hứa Lập Quốc và loan đao đánh vỡ tan toàn bộ, khống chế lão cách mười trượng.","importance":"bridge","nguon":["@c0452"]},{"chuong":"@c0452","tieuDe":"Tuyên bố ương ngạnh và tra hỏi","text":"Vương Lâm tuyên bố sẽ làm người ương ngạnh nếu không được yên, rồi tra hỏi lão già còn lại: trước đây ai ở trong Tử Vân Các.","importance":"bridge","nguon":["@c0452"]},{"chuong":"@c0453","tieuDe":"Chế ngự hai chấp pháp, ép khai bí mật Tử hệ","text":"Vương Lâm trấn áp cả hai chấp pháp trưởng lão (anh biến sơ kỳ), ép lão già đầu hàng khai ra bí mật Tử hệ: Thiên Vận Thất tử, kỳ tài Tôn Vân bỏ trốn khiến Tử Vân Các bị phong ấn, và việc hắn được thủy tổ giao Tử Vân Các nên bị sáu sư huynh đệ bài xích vì xuất thân tinh cầu vứt đi.","importance":"major","nguon":["@c0453"]},{"chuong":"@c0453","tieuDe":"Thôn phệ nguyên thần hai chấp pháp","text":"Vương Lâm thu chuông, vuốt tan thanh quang nguyên thần một đồng bọn rồi nuốt vào tôn hồn phiên; sau đó ra lệnh Giết hắn, để loan đao và tiên kiếm truy sát lôi nguyên thần lão già về và nuốt giam luôn — công khai hành vi ma đạo.","importance":"major","nguon":["@c0453"]},{"chuong":"@c0453","tieuDe":"Trấn áp Tử y nữ tử bằng quang cầu trắng","text":"Vương Lâm thúc tiên kiếm và loan đao tấn công Tử y nữ tử rồi ngưng tụ một quang cầu trắng khổng lồ giáng xuống đất, chấn động như địa long, ép nàng bay ra với vẻ kinh hoàng.","importance":"bridge","nguon":["@c0453"]},{"chuong":"@c0453","tieuDe":"Đổi tên Tử Vân Các thành Tử Lâm Các, tuyên chiến Thiên Vận Tông","text":"Vương Lâm biến chữ Vân thành chữ Lâm trên biển các, đổi tên Tử Vân Các thành Tử Lâm Các, ngạo nghễ tuyên chiến với toàn Thiên Vận Tông; Tử y nữ tử khóc thề phải giết hắn rồi biến mất.","importance":"bridge","nguon":["@c0453"]},{"chuong":"@c0454","tieuDe":"Tịch Diệt Chỉ giam nguyên thần ngũ sư muội","text":"Vương Lâm né hỏa phượng của tử y nữ tử, triệu tiên kiếm phá dung nham rồi thi Tịch Diệt Chỉ khóa không gian, hấp thu một phân thân và chống phân thân tự bạo, điểm mi tâm giam nguyên thần nàng vào tôn Hồn Phiên.","importance":"major","nguon":["@c0454"]},{"chuong":"@c0454","tieuDe":"Đối mặt bốn người Tử tông, hỏi Tôn Vân","text":"Vương Lâm bình thản đối diện Triệu Tinh Sát, Bạch Vi, nhị sư huynh và nữ tử Anh Biến hậu kỳ; phân định tu vi từng người rồi hỏi ngược Tôn Vân là ai khiến cả bốn biến sắc.","importance":"major","nguon":["@c0454"]},{"chuong":"@c0454","tieuDe":"Phá Quy khư bằng Côn Cực Tiên","text":"Nhị sư huynh khiêu chiến cho ba pháp thuật; Vương Lâm dùng Tịch Diệt Chỉ ấn tới, khi đối thủ thi Quy khư thì hắn dùng Côn Cực Tiên quất hai roi đánh tan kim quang.","importance":"major","nguon":["@c0454"]},{"chuong":"@c0454","tieuDe":"Phá Thập phương bát la trận, chiến phủ bị Tiên Ma thể chặn","text":"Vương Lâm dùng tiên kiếm và loan đao phá kiếm trận Thập phương bát la của nhị sư huynh, nhưng chiến phủ chém vào lại bị cấm thuật Tiên Ma thể chặn, truyền chấn động tê tay.","importance":"bridge","nguon":["@c0454"]},{"chuong":"@c0454","tieuDe":"Thi Hóa Ma Chỉ thiêu hắc vụ","text":"Vương Lâm hóa Khu Thú Quyển thành Xạ Thần Xa rồi thi Hóa Ma Chỉ — thức thứ hai của Tư Đồ Nam, ma hỏa tím dung vào hắc vụ khiến đối thủ kêu thét lui chạy.","importance":"bridge","nguon":["@c0454"]},{"chuong":"@c0454","tieuDe":"Giải phong thú hồn chấn nhiếp toàn trường","text":"Triệu Tinh Sát can thiệp, Vương Lâm quát đuổi rồi hô Giải phong Xạ Thần Xa, tiếng gầm bất khuất chấn động mấy vạn dặm dọa lui cả bốn người và khiến đệ tử Tử tông loạn linh lực.","importance":"bridge","nguon":["@c0454"]},{"chuong":"@c0454","tieuDe":"Ra lệnh thú hồn truy sát và giết nhị sư huynh","text":"Vương Lâm ra lệnh đầu cự thú truy sát Triệu Tinh Sát, quất roi tan hắc vụ giết nhị sư huynh, đánh nguyên thần hắn bay ra rồi phất Tôn Hồn Phiên xua chủ hồn đuổi theo.","importance":"major","nguon":["@c0454"]},{"chuong":"@c0455","tieuDe":"Trấn áp toàn Tử tông","text":"Sau đại chiến, Vương Lâm thong dong trấn áp toàn trường khiến đệ tử và chấp pháp trưởng lão Tử tông cúi đầu kinh hãi; hắn hỏi Bạch Vi và nữ tử Anh Biến hậu kỳ có muốn ra tay, cả hai đều thoái lui, nữ tử gọi hắn là Lão thất và hẹn ngày sau luận bàn.","importance":"major","nguon":["@c0455"]},{"chuong":"@c0455","tieuDe":"Trọng thương nam tử trung niên","text":"Vương Lâm thu các chủ hồn truy kích vào Tôn Hồn Phiên; hồi lại trận chiến hắn dùng phi kiếm không bị Tiên Ma thể thôn phệ, ngọn lửa tím phá nát Tiên Ma thể khiến đối thủ phản phệ trọng thương, rồi Đoạt Hồn Tiên đánh bật nguyên thần nam tử trung niên rời khỏi thân thể.","importance":"major","nguon":["@c0455"]},{"chuong":"@c0455","tieuDe":"Bái Thiên Vận Tử làm sư tôn","text":"Thiên Vận Tử xuất hiện, nói đã sớm gặp Vương Lâm ở Chu Tước tinh năm xưa và khôi phục Tử Lâm Các cùng vạn vật; lão hỏi Vương Lâm có nguyện bái sư tu đại đạo thành đệ tử Tử hệ, Vương Lâm quỳ xuống bái sư.","importance":"major","nguon":["@c0455"]},{"chuong":"@c0455","tieuDe":"Thả ngũ sư tỷ áo tím","text":"Theo lời Thiên Vận Tử, Vương Lâm thả nguyên thần nữ tử áo tím khỏi Tôn Hồn Phiên; nàng xông tới phục thù, Vương Lâm lộ hàn quang, rồi Thiên Vận Tử một lời làm nguyên thần nàng tan vỡ khiến Vương Lâm chấn động trầm mặc.","importance":"major","nguon":["@c0455"]},{"chuong":"@c0455","tieuDe":"So sánh thực lực và luận tiên thuật","text":"Sau khi mọi người giải tán, Vương Lâm thầm thừa nhận Thiên Vận Tử mạnh hơn Tư Đồ Nam rất xa; hắn nhớ lại Tư Đồ Nam từng dạy mình, biết Tam sát chiêu vốn chỉ là một tiên thuật hạ phẩm không hoàn chỉnh lấy từ Tử Diệp Vô Ưu.","importance":"bridge","nguon":["@c0455"]},{"chuong":"@c0457","tieuDe":"Thất sư tổ Thiên Vận Tông","text":"Vương Lâm đi trên Tử Tông Sơn, được đệ tử Tử Tông cung kính xưng thất sư tổ; hắn hiểu ra Thiên Vận Tông phân vai vế theo thứ tự nhập môn trước sau và xác lập tâm thế người ương ngạnh, không che giấu khả năng để khỏi bị giẫm nát.","importance":"bridge","nguon":["@c0457"]},{"chuong":"@c0457","tieuDe":"Gặp Trương Hướng Phàm, mượn phi kiếm","text":"Tới Phẩm Linh Các lĩnh tiên ngọc, Vương Lâm gặp Trương Hướng Phàm (Hóa Thần đại viên mãn ẩn giấu) và xin mượn thanh phi kiếm xanh biếc để xem.","importance":"major","nguon":["@c0457"]},{"chuong":"@c0457","tieuDe":"Nhận ra kiếm ý cố nhân Chu Dật","text":"Vương Lâm cảm nhận trên phi kiếm có một tia kiếm ý chính là cảm ngộ của Chu Dật năm xưa hóa kiếm hồn tản mát, khiến hắn chấn động; nhờ giữ bảo tháp ý cảnh vấn đỉnh của Chu Dật nhiều năm nên vừa nhìn đã nhận ra.","importance":"bridge","nguon":["@c0457"]},{"chuong":"@c0457","tieuDe":"Lấy kiếm ý, đền ngọc giản cấm chế","text":"Vương Lâm tách tia kiếm ý thành điểm sáng xanh thu lấy, đền bù cho Trương Hướng Phàm một ngọc giản chứa mười tám đạo cấm chế công kích chồng tầng rồi trả lại phi kiếm.","importance":"bridge","nguon":["@c0457"]},{"chuong":"@c0457","tieuDe":"Lĩnh tiên ngọc Thất Tử","text":"Vương Lâm đưa lệnh bài để Trương Hướng Phàm mở truyền tống trận, lĩnh phần tiên ngọc mỗi tháng của Thiên Vận Thất Tử.","importance":"bridge","nguon":["@c0457"]}]},"nguon":["@c0391","@c0392","@c0393","@c0394","@c0395","@c0397","@c0399","@c0400","@c0401","@c0402","@c0403","@c0404","@c0405","@c0406","@c0407","@c0408","@c0409","@c0410","@c0411","@c0412","@c0414","@c0416","@c0417","@c0419","@c0421","@c0422","@c0423","@c0425","@c0426","@c0430","@c0434","@c0435","@c0438","@c0439","@c0440","@c0442","@c0443","@c0445","@c0446","@c0447","@c0448","@c0449","@c0450","@c0451","@c0452","@c0453","@c0454","@c0455","@c0457"]}]};